def normalize_iso_datetime(value: str) -> str:
    """Normalize .NET-style 7-digit fractional seconds for Python 3.10 ISO parsing."""
    return re.sub(r"(\.\d{6})\d+(Z|[+-]\d{2}:\d{2})$", r"\1\2", value)

