class ContractError(ValueError):
    """Raised when a contract file fails validation."""


def load_json(path: Path) -> dict[str, Any]:
    try:
        with path.open("r", encoding="utf-8") as handle:
            data = json.load(handle)
    except FileNotFoundError as exc:
        raise ContractError(f"{path}: file does not exist") from exc
    except json.JSONDecodeError as exc:
        raise ContractError(f"{path}: invalid JSON: {exc}") from exc

    if not isinstance(data, dict):
        raise ContractError(f"{path}: top-level JSON value must be an object")
    return data


def resolve_report_path(value: str, manifest_parent: Path) -> Path:
    candidate = Path(value)
    if candidate.is_absolute():
        return candidate
    repo_candidate = ROOT / candidate
    if repo_candidate.exists():
        return repo_candidate
    return manifest_parent / candidate


def file_sha256(path: Path) -> str:
    digest = hashlib.sha256()
    with path.open("rb") as handle:
        for chunk in iter(lambda: handle.read(1024 * 1024), b""):
            digest.update(chunk)
    return digest.hexdigest().upper()


def run_jsonschema(instance: dict[str, Any], schema_path: Path, instance_path: Path) -> bool:
    try:
        from jsonschema import Draft202012Validator, FormatChecker
    except ImportError:
        return False

    schema = load_json(schema_path)
    validator = Draft202012Validator(schema, format_checker=FormatChecker())
    errors = sorted(validator.iter_errors(instance), key=lambda error: list(error.path))
    if errors:
        first = errors[0]
        location = ".".join(str(part) for part in first.path) or "<root>"
        raise ContractError(f"{instance_path}: schema validation failed at {location}: {first.message}")
    return True


def require_object(value: Any, path: str) -> dict[str, Any]:
    if not isinstance(value, dict):
        raise ContractError(f"{path}: expected object")
    return value


def require_array(value: Any, path: str) -> list[Any]:
    if not isinstance(value, list):
        raise ContractError(f"{path}: expected array")
    return value


def require_keys(obj: dict[str, Any], keys: set[str], path: str) -> None:
    missing = sorted(keys.difference(obj))
    if missing:
        raise ContractError(f"{path}: missing required keys: {', '.join(missing)}")


def require_preserved_operator_execute_guard(
    *,
    report_step: dict[str, Any],
    readiness_step: dict[str, Any],
    report_step_path: str,
    readiness_step_path: str,
) -> None:
    if str(report_step.get("guard_set_command", "")) != str(readiness_step.get("guard_set_command", "")):
        raise ContractError(f"{report_step_path}.guard_set_command: must match {readiness_step_path}.guard_set_command")
    if str(report_step.get("guard_cleanup_command", "")) != str(readiness_step.get("guard_cleanup_command", "")):
        raise ContractError(f"{report_step_path}.guard_cleanup_command: must match {readiness_step_path}.guard_cleanup_command")
    report_required_env = require_object(report_step.get("required_env"), f"{report_step_path}.required_env")
    readiness_required_env = require_object(readiness_step.get("required_env"), f"{readiness_step_path}.required_env")
    if report_required_env != readiness_required_env:
        raise ContractError(f"{report_step_path}.required_env: must match {readiness_step_path}.required_env")


def validate_benchmark_resolution_command(
    *,
    plan: dict[str, Any],
    target: str | None,
    location: str,
) -> None:
    kind = str(plan["kind"])
    command_available = plan["command_available"] is True
    expected_kind = BENCHMARK_TARGET_RESOLUTION_KIND.get(str(target)) if target is not None else kind
    if expected_kind is not None and kind != expected_kind:
        raise ContractError(f"{location}.kind: expected {expected_kind}")

    if command_available:
        if kind not in BENCHMARK_RESOLUTION_COMMANDS:
            raise ContractError(f"{location}.kind: no guarded launcher mapping for command_available=true")
        expected_launcher, expected_guard, guarded_execute_required = BENCHMARK_RESOLUTION_COMMANDS[kind]
        validation_command = str(plan["validation_command"])
        if "-Execute" in validation_command:
            raise ContractError(f"{location}.validation_command: must be validation-only")
        if expected_launcher not in validation_command:
            raise ContractError(f"{location}.validation_command: must reference {expected_launcher}")
        if guarded_execute_required:
            execute_command = str(plan["execute_command"])
            execute_guard_env = str(plan["execute_guard_env"])
            if "-Execute" not in execute_command:
                raise ContractError(f"{location}.execute_command: guarded execute command must include -Execute")
            if expected_launcher not in execute_command:
                raise ContractError(f"{location}.execute_command: must reference {expected_launcher}")
            if execute_guard_env != expected_guard:
                raise ContractError(f"{location}.execute_guard_env: must require {expected_guard}")
            if kind == "wave1_governed_acquisition":
                operator_note = str(plan["operator_note"]).lower()
                required_terms = (
                    "tamandua_allow_vx_underground_download",
                    "unset",
                    "metadata-only",
                    "holdout_candidate",
                    "train/validation/test",
                )
                if any(term not in operator_note for term in required_terms):
                    raise ContractError(f"{location}.operator_note: must document VX metadata-only guard boundary")
        else:
            if plan["execute_command"] is not None:
                raise ContractError(f"{location}.execute_command: non-guarded resolution commands must not expose guarded execute")
            if plan["execute_guard_env"] is not None:
                raise ContractError(f"{location}.execute_guard_env: non-guarded resolution commands must not require a guard")
    else:
        if target is not None and expected_kind is not None:
            raise ContractError(f"{location}.command_available: mapped benchmark blockers must expose commands")
        for field in ["validation_command", "execute_command", "execute_guard_env"]:
            if plan[field] is not None:
                raise ContractError(f"{location}.{field}: unavailable command fields must be null")


def validate_quality_gate(obj: dict[str, Any], path: str) -> None:
    require_keys(obj, {"status", "checks"}, path)
    quality_status = obj["status"]
    if quality_status not in QUALITY_STATUSES:
        raise ContractError(f"{path}.status: invalid value {quality_status!r}")

    checks = require_array(obj["checks"], f"{path}.checks")
    if not checks:
        raise ContractError(f"{path}.checks: at least one quality check is required")
    check_statuses: list[str] = []
    for index, check_value in enumerate(checks):
        check = require_object(check_value, f"{path}.checks[{index}]")
        require_keys(check, {"name", "status"}, f"{path}.checks[{index}]")
        if not check["name"]:
            raise ContractError(f"{path}.checks[{index}].name: must not be empty")
        if check["status"] not in CHECK_STATUSES:
            raise ContractError(f"{path}.checks[{index}].status: invalid value {check['status']!r}")
        check_statuses.append(str(check["status"]))

    if quality_status == "pass" and any(status != "pass" for status in check_statuses):
        raise ContractError(f"{path}.status: pass requires all checks to pass")
    if quality_status == "fail" and "fail" not in check_statuses:
        raise ContractError(f"{path}.status: fail requires at least one failed check")
    if quality_status == "not_run":
        if "fail" in check_statuses:
            raise ContractError(f"{path}.status: not_run must not include failed checks")
        if "not_run" not in check_statuses:
            raise ContractError(f"{path}.status: not_run requires at least one not_run check")
    if quality_status == "partial":
        if "fail" in check_statuses:
            raise ContractError(f"{path}.status: partial must not include failed checks")
        if not {"warning", "not_run"}.intersection(check_statuses):
            raise ContractError(f"{path}.status: partial requires warning or not_run checks")


def validate_dataset_manifest(data: dict[str, Any], path: Path) -> None:
    require_keys(data, {"api_version", "kind", "metadata", "storage", "sources", "splits", "samples", "quality_gates"}, str(path))
    if data["api_version"] != DATASET_API_VERSION:
        raise ContractError(f"{path}: invalid api_version {data['api_version']!r}")
    if data["kind"] != "MLDatasetManifest":
        raise ContractError(f"{path}: invalid kind {data['kind']!r}")

    metadata = require_object(data["metadata"], f"{path}.metadata")
    require_keys(metadata, {"dataset_id", "version", "created_at", "created_by", "purpose", "claim_boundary"}, f"{path}.metadata")
    if len(str(metadata["claim_boundary"])) < 10:
        raise ContractError(f"{path}.metadata.claim_boundary: must describe the allowed claim")

    storage = require_object(data["storage"], f"{path}.storage")
    require_keys(storage, {"raw_samples_in_git", "raw_sample_storage", "manifest_path"}, f"{path}.storage")
    if storage["raw_samples_in_git"] is not False:
        raise ContractError(f"{path}.storage.raw_samples_in_git: must be false")
    production_purpose = metadata["purpose"] in {"training", "validation", "test", "holdout"}
    if production_purpose and str(storage["raw_sample_storage"]).startswith("synthetic://"):
        raise ContractError(f"{path}.storage.raw_sample_storage: production manifests must not use synthetic storage")
    raw_sample_storage = str(storage["raw_sample_storage"])
    if production_purpose and not raw_sample_storage.startswith("external://"):
        raise ContractError(f"{path}.storage.raw_sample_storage: production manifests must use external storage URI")

    sources = require_array(data["sources"], f"{path}.sources")
    if not sources:
        raise ContractError(f"{path}.sources: at least one source is required")
    source_ids: set[str] = set()
    source_types_by_id: dict[str, str] = {}
    for index, source_value in enumerate(sources):
        source = require_object(source_value, f"{path}.sources[{index}]")
        require_keys(source, {"source_id", "source_type", "role", "acquired_at"}, f"{path}.sources[{index}]")
        source_id = str(source["source_id"])
        if source_id in source_ids:
            raise ContractError(f"{path}.sources[{index}].source_id: duplicate {source_id!r}")
        source_ids.add(source_id)
        source_type = str(source["source_type"])
        source_types_by_id[source_id] = source_type
        if production_purpose and source_type == "synthetic":
            raise ContractError(f"{path}.sources[{index}].source_type: production manifests must not use synthetic sources")

    splits = require_object(data["splits"], f"{path}.splits")
    ratios = require_object(splits.get("ratios"), f"{path}.splits.ratios")
    require_keys(ratios, {"train", "validation", "test", "holdout"}, f"{path}.splits.ratios")
    for name, ratio in ratios.items():
        if not isinstance(ratio, (int, float)) or ratio < 0 or ratio > 1:
            raise ContractError(f"{path}.splits.ratios.{name}: ratio must be between 0 and 1")

    samples = require_array(data["samples"], f"{path}.samples")
    if not samples:
        raise ContractError(f"{path}.samples: at least one sample is required")
    sample_ids: set[str] = set()
    sample_sha256s: set[str] = set()
    split_counts: dict[str, int] = {split: 0 for split in DATASET_SPLITS}
    label_counts: dict[str, int] = {label: 0 for label in DATASET_LABELS}
    for index, sample_value in enumerate(samples):
        sample = require_object(sample_value, f"{path}.samples[{index}]")
        require_keys(sample, {"sample_id", "sha256", "label", "label_source", "source_id", "split", "storage_ref"}, f"{path}.samples[{index}]")
        sample_id = str(sample["sample_id"])
        if sample_id in sample_ids:
            raise ContractError(f"{path}.samples[{index}].sample_id: duplicate {sample_id!r}")
        sample_ids.add(sample_id)
        sha256 = str(sample["sha256"]).lower()
        if not SHA256_RE.match(sha256):
            raise ContractError(f"{path}.samples[{index}].sha256: must be a 64-char hex digest")
        if sha256 in sample_sha256s:
            raise ContractError(f"{path}.samples[{index}].sha256: duplicate sample hash {sha256}")
        sample_sha256s.add(sha256)
        if sample["label"] not in DATASET_LABELS:
            raise ContractError(f"{path}.samples[{index}].label: invalid value {sample['label']!r}")
        if sample["split"] not in DATASET_SPLITS:
            raise ContractError(f"{path}.samples[{index}].split: invalid value {sample['split']!r}")
        if sample["source_id"] not in source_ids:
            raise ContractError(f"{path}.samples[{index}].source_id: unknown source {sample['source_id']!r}")
        split = str(sample["split"])
        label = str(sample["label"])
        split_counts[split] += 1
        label_counts[label] += 1
        storage_ref = str(sample["storage_ref"])
        if production_purpose:
            if split in {"smoke", "parity"}:
                raise ContractError(f"{path}.samples[{index}].split: production manifests must not use smoke/parity splits")
            if storage_ref.startswith("synthetic://"):
                raise ContractError(f"{path}.samples[{index}].storage_ref: production manifests must not use synthetic storage refs")
            if not storage_ref.startswith("external://"):
                raise ContractError(f"{path}.samples[{index}].storage_ref: production manifests must use external storage refs")
            if source_types_by_id[str(sample["source_id"])] == "synthetic":
                raise ContractError(f"{path}.samples[{index}].source_id: production samples must not use synthetic sources")

    if production_purpose:
        if label_counts["malware"] < 1 or label_counts["goodware"] < 1:
            raise ContractError(f"{path}.samples: production manifests must include malware and goodware samples")
        if metadata["purpose"] == "training" and not all(split_counts[split] > 0 for split in ("train", "validation", "test")):
            raise ContractError(f"{path}.samples: training manifests must include train, validation, and test splits")

    validate_quality_gate(require_object(data["quality_gates"], f"{path}.quality_gates"), f"{path}.quality_gates")


def validate_benchmark_report(data: dict[str, Any], path: Path) -> None:
    require_keys(data, {"api_version", "kind", "metadata", "lane", "subject", "dataset", "environment", "metrics", "quality_gate", "claim_boundary"}, str(path))
    if data["api_version"] != BENCHMARK_API_VERSION:
        raise ContractError(f"{path}: invalid api_version {data['api_version']!r}")
    if data["kind"] != "MLBenchmarkReport":
        raise ContractError(f"{path}: invalid kind {data['kind']!r}")
    if data["lane"] not in LANES:
        raise ContractError(f"{path}.lane: invalid value {data['lane']!r}")
    if len(str(data["claim_boundary"])) < 10:
        raise ContractError(f"{path}.claim_boundary: must describe the allowed claim")

    metadata = require_object(data["metadata"], f"{path}.metadata")
    require_keys(metadata, {"report_id", "created_at", "created_by", "git_commit"}, f"{path}.metadata")

    subject = require_object(data["subject"], f"{path}.subject")
    require_keys(subject, {"type", "name", "version"}, f"{path}.subject")

    dataset = require_object(data["dataset"], f"{path}.dataset")
    require_keys(dataset, {"dataset_id", "manifest_ref", "sample_counts"}, f"{path}.dataset")
    counts = require_object(dataset["sample_counts"], f"{path}.dataset.sample_counts")
    require_keys(counts, {"total", "malware", "goodware", "unknown"}, f"{path}.dataset.sample_counts")
    for name, value in counts.items():
        if not isinstance(value, int) or value < 0:
            raise ContractError(f"{path}.dataset.sample_counts.{name}: must be a non-negative integer")
    if counts["total"] != counts["malware"] + counts["goodware"] + counts["unknown"]:
        raise ContractError(f"{path}.dataset.sample_counts.total: must equal malware, goodware, and unknown counts")

    environment = require_object(data["environment"], f"{path}.environment")
    require_keys(environment, {"os", "python_version"}, f"{path}.environment")

    metrics = require_object(data["metrics"], f"{path}.metrics")
    quality_gate = require_object(data["quality_gate"], f"{path}.quality_gate")
    validate_quality_gate(quality_gate, f"{path}.quality_gate")
    if quality_gate["status"] == "pass" and data["lane"] != "ML-0":
        if counts["total"] < 1:
            raise ContractError(f"{path}.dataset.sample_counts.total: pass benchmark reports must evaluate at least one sample")
        substantive_metrics = [
            "accuracy",
            "precision",
            "recall",
            "f1",
            "false_positive_rate",
            "false_negative_rate",
            "roc_auc",
            "verdict_agreement",
            "confidence_delta_p95",
            "latency_ms_p95",
            "throughput_per_second",
        ]
        if all(metrics.get(name) is None for name in substantive_metrics):
            raise ContractError(f"{path}.metrics: pass benchmark reports must record at least one substantive metric")

    artifacts = data.get("artifacts")
    if artifacts is not None:
        artifact_items = require_array(artifacts, f"{path}.artifacts")
        for index, artifact_value in enumerate(artifact_items):
            artifact = require_object(artifact_value, f"{path}.artifacts[{index}]")
            require_keys(artifact, {"name", "path"}, f"{path}.artifacts[{index}]")
            artifact_sha = artifact.get("sha256")
            if artifact_sha is None:
                continue
            if not SHA256_RE.match(str(artifact_sha)):
                raise ContractError(f"{path}.artifacts[{index}].sha256: must be a 64-char hex digest")
            artifact_ref = str(artifact["path"])
            if "://" in artifact_ref:
                raise ContractError(f"{path}.artifacts[{index}].path: sha256 artifacts must use a local filesystem path")
            artifact_path = resolve_report_path(artifact_ref, path.parent)
            if not artifact_path.exists() or not artifact_path.is_file():
                raise ContractError(f"{path}.artifacts[{index}].path: sha256 artifact file does not exist")
            actual_sha = file_sha256(artifact_path)
            if actual_sha.lower() != str(artifact_sha).lower():
                raise ContractError(f"{path}.artifacts[{index}].sha256: does not match artifact file")


def validate_model_contract(data: dict[str, Any], path: Path) -> None:
    require_keys(
        data,
        {
            "api_version",
            "kind",
            "metadata",
            "model",
            "artifact",
            "input",
            "output",
            "preprocessing",
            "decision",
            "runtime",
            "quality_gates",
        },
        str(path),
    )
    if data["api_version"] != MODEL_CONTRACT_API_VERSION:
        raise ContractError(f"{path}: invalid api_version {data['api_version']!r}")
    if data["kind"] != "MLModelContract":
        raise ContractError(f"{path}: invalid kind {data['kind']!r}")

    metadata = require_object(data["metadata"], f"{path}.metadata")
    require_keys(metadata, {"contract_id", "version", "created_at", "created_by", "claim_boundary"}, f"{path}.metadata")
    if len(str(metadata["claim_boundary"])) < 10:
        raise ContractError(f"{path}.metadata.claim_boundary: must describe the allowed claim")

    model = require_object(data["model"], f"{path}.model")
    require_keys(model, {"model_type", "num_classes", "labels", "opset_version"}, f"{path}.model")
    if model["model_type"] != "malware_smell_onnx":
        raise ContractError(f"{path}.model.model_type: invalid value {model['model_type']!r}")
    if model["num_classes"] != 8:
        raise ContractError(f"{path}.model.num_classes: expected 8")
    if model["opset_version"] != 17:
        raise ContractError(f"{path}.model.opset_version: expected 17")
    if require_array(model["labels"], f"{path}.model.labels") != CANONICAL_LABELS:
        raise ContractError(f"{path}.model.labels: must match canonical Malware-SMELL label order")

    artifact = require_object(data["artifact"], f"{path}.artifact")
    require_keys(artifact, {"file_name", "format", "metadata_file", "agent_paths"}, f"{path}.artifact")
    if artifact["format"] != "onnx" or not str(artifact["file_name"]).endswith(".onnx"):
        raise ContractError(f"{path}.artifact: expected ONNX artifact")
    if not str(artifact["metadata_file"]).endswith(".json"):
        raise ContractError(f"{path}.artifact.metadata_file: expected JSON metadata file")
    if artifact.get("metadata_sha256_required") is not None and artifact.get("metadata_sha256_required") is not True:
        raise ContractError(f"{path}.artifact.metadata_sha256_required: must be true when present")
    metadata_sha = artifact.get("metadata_sha256")
    if metadata_sha is not None and not SHA256_RE.match(str(metadata_sha)):
        raise ContractError(f"{path}.artifact.metadata_sha256: must be a lowercase 64-character SHA-256")
    metadata_size = artifact.get("metadata_size_bytes")
    if metadata_size is not None and int(metadata_size) <= 0:
        raise ContractError(f"{path}.artifact.metadata_size_bytes: must be positive when present")
    if artifact.get("sha256_required") is not True:
        raise ContractError(f"{path}.artifact.sha256_required: must be true for ONNX agent rollout")
    artifact_sha = artifact.get("sha256")
    if artifact_sha is not None and not SHA256_RE.match(str(artifact_sha)):
        raise ContractError(f"{path}.artifact.sha256: must be a lowercase 64-character SHA-256")
    artifact_size = artifact.get("size_bytes")
    if artifact_size is not None and int(artifact_size) <= 0:
        raise ContractError(f"{path}.artifact.size_bytes: must be positive when present")
    if artifact.get("signature_required") is not True:
        raise ContractError(f"{path}.artifact.signature_required: must be true for ONNX agent rollout")
    agent_paths = require_object(artifact["agent_paths"], f"{path}.artifact.agent_paths")
    require_keys(agent_paths, {"windows", "linux", "macos"}, f"{path}.artifact.agent_paths")
    for platform in ("windows", "linux", "macos"):
        agent_path = str(agent_paths[platform])
        if not agent_path or not agent_path.endswith(".onnx"):
            raise ContractError(f"{path}.artifact.agent_paths.{platform}: must reference an ONNX path")

    input_spec = require_object(data["input"], f"{path}.input")
    require_keys(input_spec, {"name", "format", "dtype", "layout", "sample_shape", "channels", "image_size"}, f"{path}.input")
    if input_spec["name"] != "input":
        raise ContractError(f"{path}.input.name: expected 'input'")
    if input_spec["format"] != "image_nchw" or input_spec["layout"] != "NCHW":
        raise ContractError(f"{path}.input.format: expected image_nchw/NCHW")
    if input_spec["dtype"] != "float32":
        raise ContractError(f"{path}.input.dtype: expected float32")
    if input_spec["sample_shape"] != [1, 3, 64, 64]:
        raise ContractError(f"{path}.input.sample_shape: expected [1, 3, 64, 64]")
    if input_spec["channels"] != 3 or input_spec["image_size"] != 64:
        raise ContractError(f"{path}.input: expected 3-channel 64x64 image input")

    output_spec = require_object(data["output"], f"{path}.output")
    require_keys(output_spec, {"name", "shape", "benign_index", "malicious_indices", "labels"}, f"{path}.output")
    if output_spec["name"] != "output" or output_spec["shape"] != [1, 8]:
        raise ContractError(f"{path}.output: expected output shape [1, 8] named 'output'")
    if output_spec["benign_index"] != 0 or output_spec["labels"] != CANONICAL_LABELS:
        raise ContractError(f"{path}.output: benign index and label order must match canonical labels")
    if output_spec["malicious_indices"] != [1, 2, 3, 4, 5, 6, 7]:
        raise ContractError(f"{path}.output.malicious_indices: expected [1, 2, 3, 4, 5, 6, 7]")

    preprocessing = require_object(data["preprocessing"], f"{path}.preprocessing")
    require_keys(preprocessing, {"version", "normalization", "channel_policy"}, f"{path}.preprocessing")
    if preprocessing["version"] != "binary_to_image_64_rgb_v1":
        raise ContractError(f"{path}.preprocessing.version: invalid value {preprocessing['version']!r}")
    if preprocessing["normalization"] != "byte_div_255":
        raise ContractError(f"{path}.preprocessing.normalization: expected byte_div_255")
    if preprocessing["channel_policy"] != "replicate_grayscale_to_rgb":
        raise ContractError(f"{path}.preprocessing.channel_policy: expected replicate_grayscale_to_rgb")

    decision = require_object(data["decision"], f"{path}.decision")
    require_keys(decision, {"malicious_threshold", "malicious_rule", "observe_before_block"}, f"{path}.decision")
    threshold = decision["malicious_threshold"]
    if not isinstance(threshold, (int, float)) or threshold < 0 or threshold > 1:
        raise ContractError(f"{path}.decision.malicious_threshold: must be between 0 and 1")
    if decision["observe_before_block"] is not True:
        raise ContractError(f"{path}.decision.observe_before_block: must be true")

    runtime = require_object(data["runtime"], f"{path}.runtime")
    require_keys(runtime, {"agent_features", "ort_version", "dynamic_runtime_loading", "canonical_agent_module"}, f"{path}.runtime")
    agent_features = require_array(runtime["agent_features"], f"{path}.runtime.agent_features")
    if "onnx" not in agent_features:
        raise ContractError(f"{path}.runtime.agent_features: must include 'onnx'")
    if "ml-local" not in agent_features:
        raise ContractError(f"{path}.runtime.agent_features: must include 'ml-local'")
    if runtime["dynamic_runtime_loading"] is not True:
        raise ContractError(f"{path}.runtime.dynamic_runtime_loading: must be true")
    if not str(runtime["ort_version"]).startswith("2.0.0-rc."):
        raise ContractError(f"{path}.runtime.ort_version: must pin the ORT 2.0.0 release candidate family")
    if "onnx" not in str(runtime["canonical_agent_module"]).lower():
        raise ContractError(f"{path}.runtime.canonical_agent_module: must reference the ONNX agent module")

    validate_quality_gate(require_object(data["quality_gates"], f"{path}.quality_gates"), f"{path}.quality_gates")
    contract_id = str(metadata["contract_id"])
    version = str(metadata["version"])
    if contract_id == "malware-smell-onnx-ml-prod-candidate-v1" or version == "ml-prod-candidate-v1":
        if artifact.get("metadata_sha256_required") is not True:
            raise ContractError(f"{path}.artifact.metadata_sha256_required: production candidate contract must require metadata SHA-256")
        if not SHA256_RE.match(str(artifact.get("metadata_sha256", ""))):
            raise ContractError(f"{path}.artifact.metadata_sha256: production candidate contract must record metadata SHA-256")
        if int(artifact.get("metadata_size_bytes") or 0) <= 0:
            raise ContractError(f"{path}.artifact.metadata_size_bytes: production candidate contract must record metadata size")


def validate_agent_parity_fixture(data: dict[str, Any], path: Path) -> None:
    require_keys(
        data,
        {
            "api_version",
            "kind",
            "metadata",
            "model_contract_ref",
            "onnx_model",
            "input",
            "output",
            "agent_tolerance",
            "samples",
        },
        str(path),
    )
    if data["api_version"] != AGENT_PARITY_FIXTURE_API_VERSION:
        raise ContractError(f"{path}: invalid api_version {data['api_version']!r}")
    if data["kind"] != "MLAgentParityFixture":
        raise ContractError(f"{path}: invalid kind {data['kind']!r}")
    model_contract_ref = str(data["model_contract_ref"])
    fixture_id = str(require_object(data["metadata"], f"{path}.metadata").get("fixture_id", ""))
    if (
        str(path).endswith("ml-prod-candidate-v1-ml3-agent-parity-fixture.json")
        or fixture_id == "ml_prod_candidate_v1_ml3_agent_parity_fixture"
    ) and model_contract_ref != "docs/benchmarks/runs/ml-prod-candidate-v1-model-contract.json":
        raise ContractError(f"{path}.model_contract_ref: production candidate ML-3 fixture must reference generated model contract")

    onnx_model = require_object(data["onnx_model"], f"{path}.onnx_model")
    require_keys(onnx_model, {"path", "sha256", "metadata_path", "metadata_sha256"}, f"{path}.onnx_model")
    if str(onnx_model["path"]).replace("\\", "/").endswith("ml-prod-candidate-v1-artifacts/malware_smell.onnx"):
        if str(onnx_model["metadata_path"]).replace("\\", "/") != "docs/benchmarks/runs/ml-prod-candidate-v1-artifacts/malware_smell.json":
            raise ContractError(f"{path}.onnx_model.metadata_path: production fixture must reference canonical ONNX metadata sidecar")
        if not SHA256_RE.match(str(onnx_model["metadata_sha256"])):
            raise ContractError(f"{path}.onnx_model.metadata_sha256: production fixture must record metadata sidecar SHA-256")

    input_spec = require_object(data["input"], f"{path}.input")
    if input_spec.get("name") != "input":
        raise ContractError(f"{path}.input.name: expected 'input'")
    if input_spec.get("image_size") != 64:
        raise ContractError(f"{path}.input.image_size: expected 64")
    if input_spec.get("preprocessing") != "binary_to_image_64_rgb_v1":
        raise ContractError(f"{path}.input.preprocessing: expected binary_to_image_64_rgb_v1")

    output_spec = require_object(data["output"], f"{path}.output")
    labels = require_array(output_spec.get("labels"), f"{path}.output.labels")
    if labels != CANONICAL_LABELS:
        raise ContractError(f"{path}.output.labels: must match canonical label order")

    samples = require_array(data["samples"], f"{path}.samples")
    if not samples:
        raise ContractError(f"{path}.samples: at least one sample is required")
    sample_ids: set[str] = set()
    for index, sample_value in enumerate(samples):
        sample = require_object(sample_value, f"{path}.samples[{index}]")
        require_keys(sample, {"sample_id", "raw_sha256", "raw_base64", "expected"}, f"{path}.samples[{index}]")
        sample_id = str(sample["sample_id"])
        if sample_id in sample_ids:
            raise ContractError(f"{path}.samples[{index}].sample_id: duplicate {sample_id!r}")
        sample_ids.add(sample_id)
        if not SHA256_RE.match(str(sample["raw_sha256"])):
            raise ContractError(f"{path}.samples[{index}].raw_sha256: must be a 64-char hex digest")
        expected = require_object(sample["expected"], f"{path}.samples[{index}].expected")
        probabilities = require_array(expected.get("probabilities"), f"{path}.samples[{index}].expected.probabilities")
        if len(probabilities) != len(CANONICAL_LABELS):
            raise ContractError(f"{path}.samples[{index}].expected.probabilities: expected 8 values")
        probability_sum = sum(float(value) for value in probabilities)
        if abs(probability_sum - 1.0) > 0.01:
            raise ContractError(f"{path}.samples[{index}].expected.probabilities: sum must be close to 1.0")


def validate_execution_plan_launcher_guards(path: Path) -> None:
    candidates = []
    if path.suffix:
        candidates.append(path.with_suffix(".handoff"))
        candidates.append(path.with_suffix(path.suffix + ".handoff"))
    else:
        candidates.append(Path(str(path) + ".handoff"))
    handoff_dirs = []
    seen: set[Path] = set()
    for candidate in candidates:
        if candidate in seen:
            continue
        seen.add(candidate)
        if candidate.exists():
            handoff_dirs.append(candidate)

    if not handoff_dirs:
        return

    for handoff_dir in handoff_dirs:
        if not handoff_dir.is_dir():
            raise ContractError(f"{path}: execution plan handoff path is not a directory: {handoff_dir}")

        for launcher_name, required_snippets in EXECUTION_PLAN_LAUNCHER_GUARDS.items():
            launcher_path = handoff_dir / launcher_name
            if not launcher_path.exists() or not launcher_path.is_file():
                raise ContractError(f"{path}: missing guarded launcher {launcher_path}")
            content = launcher_path.read_text(encoding="utf-8")
            for snippet in required_snippets:
                if snippet not in content:
                    raise ContractError(f"{launcher_path}: missing required launcher guard snippet {snippet!r}")


def validate_execution_plan(data: dict[str, Any], path: Path) -> None:
    require_keys(data, {"api_version", "kind", "metadata", "waves", "status_counts", "packages"}, str(path))
    if data["api_version"] != EXECUTION_PLAN_API_VERSION:
        raise ContractError(f"{path}: invalid api_version {data['api_version']!r}")
    if data["kind"] != "MLExecutionPlan":
        raise ContractError(f"{path}: invalid kind {data['kind']!r}")

    metadata = require_object(data["metadata"], f"{path}.metadata")
    require_keys(metadata, {"generated_at", "created_by", "claim_boundary"}, f"{path}.metadata")
    if len(str(metadata["claim_boundary"])) < 10:
        raise ContractError(f"{path}.metadata.claim_boundary: must describe the allowed claim")

    waves = require_array(data["waves"], f"{path}.waves")
    wave_ids: set[int] = set()
    for index, wave_value in enumerate(waves):
        wave = require_object(wave_value, f"{path}.waves[{index}]")
        require_keys(wave, {"wave", "purpose", "parallel"}, f"{path}.waves[{index}]")
        wave_id = wave["wave"]
        if not isinstance(wave_id, int) or wave_id < 0:
            raise ContractError(f"{path}.waves[{index}].wave: must be a non-negative integer")
        if wave_id in wave_ids:
            raise ContractError(f"{path}.waves[{index}].wave: duplicate {wave_id}")
        wave_ids.add(wave_id)

    packages = require_array(data["packages"], f"{path}.packages")
    package_ids: set[str] = set()
    status_counts: dict[str, int] = {status: 0 for status in EXECUTION_PLAN_STATUSES}
    for index, package_value in enumerate(packages):
        package = require_object(package_value, f"{path}.packages[{index}]")
        require_keys(
            package,
            {
                "package_id",
                "wave",
                "title",
                "owner_role",
                "parallel_group",
                "status",
                "dependencies",
                "required_env",
                "required_artifacts",
                "expected_artifacts",
                "safe_commands",
                "safe_command_fingerprints",
                "claim_boundary",
                "next_action",
            },
            f"{path}.packages[{index}]",
        )
        package_id = str(package["package_id"])
        if package_id in package_ids:
            raise ContractError(f"{path}.packages[{index}].package_id: duplicate {package_id!r}")
        package_ids.add(package_id)
        if package["wave"] not in wave_ids:
            raise ContractError(f"{path}.packages[{index}].wave: unknown wave {package['wave']!r}")
        status = package["status"]
        if status not in EXECUTION_PLAN_STATUSES:
            raise ContractError(f"{path}.packages[{index}].status: invalid value {status!r}")
        status_counts[status] += 1
        for dependency in require_array(package["dependencies"], f"{path}.packages[{index}].dependencies"):
            if not isinstance(dependency, str) or not dependency:
                raise ContractError(f"{path}.packages[{index}].dependencies: dependency ids must be non-empty strings")
        safe_commands = require_array(package["safe_commands"], f"{path}.packages[{index}].safe_commands")
        if package_id == "ml_data_governed_acquisition":
            title = str(package["title"])
            if "vx/InTheWild" not in title or "MalwareBazaar" not in title or "goodware" not in title:
                raise ContractError(
                    f"{path}.packages[{index}].title: governed acquisition title must mention MalwareBazaar, vx/InTheWild, and goodware"
                )
            required_env = [
                str(item) for item in require_array(package["required_env"], f"{path}.packages[{index}].required_env")
            ]
            for required_env_name in ["TAMANDUA_ML_DATA_ROOT", "TAMANDUA_MALWAREBAZAAR_AUTH_KEY"]:
                if required_env_name not in required_env:
                    raise ContractError(
                        f"{path}.packages[{index}].required_env: governed acquisition missing {required_env_name}"
                    )
            required_artifacts = [
                str(item) for item in require_array(package["required_artifacts"], f"{path}.packages[{index}].required_artifacts")
            ]
            for required_artifact in [
                "docs/benchmarks/runs/20260604T-ml-wave1-real-acquisition-transcript.template.json",
                "docs/benchmarks/runs/20260604T-ml-wave1-operator-handoff-index.json",
                "docs/benchmarks/runs/20260604T-ml-wave1-guarded-run-command-packet.json",
                "docs/benchmarks/runs/20260604T-ml-execution-plan.handoff/wave_1_real_acquisition_launcher.ps1",
                "docs/benchmarks/runs/20260604T-ml-execution-plan.handoff/wave_1_virusshare_fallback_readiness_launcher.ps1",
                "docs/benchmarks/runs/20260604T-ml-execution-plan.handoff/wave_1_post_acquisition_refresh_launcher.ps1",
                "docs/benchmarks/runs/20260604T-ml-execution-plan.handoff/wave_1_manifest_publish_launcher.ps1",
            ]:
                if required_artifact not in required_artifacts:
                    raise ContractError(
                        f"{path}.packages[{index}].required_artifacts: governed acquisition missing {required_artifact}"
                    )
            command_text = "\n".join(str(command) for command in safe_commands)
            for required_fragment in [
                "--dry-run-plan",
                "--skip-vt-validation",
                "--vx-inventory docs/benchmarks/runs/ml-vx-inthewild-inventory.json",
                "--resume",
                "wave_1_real_acquisition_launcher.ps1",
                "wave_1_virusshare_fallback_readiness_launcher.ps1",
            ]:
                if required_fragment not in command_text:
                    raise ContractError(
                        f"{path}.packages[{index}].safe_commands: governed acquisition command missing {required_fragment}"
                    )
            for safe_command in safe_commands:
                safe_command_text = str(safe_command)
                if "download_production_dataset.py" in safe_command_text and "--dry-run-plan" not in safe_command_text:
                    raise ContractError(
                        f"{path}.packages[{index}].safe_commands: governed acquisition direct command must be dry-run only; use launcher for guarded execution"
                    )
            if "vx/InTheWild" not in str(package["next_action"]):
                raise ContractError(f"{path}.packages[{index}].next_action: must mention vx/InTheWild inventory")
        if package_id == "ml1_train_candidate_and_model_card":
            expected_artifacts = [str(item) for item in require_array(package["expected_artifacts"], f"{path}.packages[{index}].expected_artifacts")]
            required_artifacts = [str(item) for item in require_array(package["required_artifacts"], f"{path}.packages[{index}].required_artifacts")]
            command_text = "\n".join(str(command) for command in safe_commands)
            if "model contract/card" not in str(package["title"]):
                raise ContractError(f"{path}.packages[{index}].title: ML-1 title must mention model contract/card")
            if "apps/tamandua_ml/scripts/generate_model_contract.py" not in required_artifacts:
                raise ContractError(f"{path}.packages[{index}].required_artifacts: missing generate_model_contract.py")
            if "docs/benchmarks/runs/ml-prod-candidate-v1-model-contract.json" not in expected_artifacts:
                raise ContractError(f"{path}.packages[{index}].expected_artifacts: missing production candidate model contract")
            if "docs/benchmarks/runs/ml-prod-candidate-v1-artifacts/malware_smell.json" not in expected_artifacts:
                raise ContractError(f"{path}.packages[{index}].expected_artifacts: missing production candidate ONNX metadata sidecar")
            for required_fragment in [
                "generate_model_contract.py",
                "--verify --contract-ref docs/benchmarks/runs/ml-prod-candidate-v1-model-contract.json",
                "--onnx-model docs/benchmarks/runs/ml-prod-candidate-v1-artifacts/malware_smell.onnx",
                "--output docs/benchmarks/runs/ml-prod-candidate-v1-model-contract.json",
                "--model-contract docs/benchmarks/runs/ml-prod-candidate-v1-model-contract.json",
            ]:
                if required_fragment not in command_text:
                    raise ContractError(
                        f"{path}.packages[{index}].safe_commands: ML-1 command missing {required_fragment}"
                    )
            if "--model-contract docs/apps/tamandua_ml/examples/ml_model_contract_malware_smell_onnx_v1.json" in command_text:
                raise ContractError(f"{path}.packages[{index}].safe_commands: model card must use the generated candidate contract")
            if "model contract" not in str(package["next_action"]):
                raise ContractError(f"{path}.packages[{index}].next_action: must mention model contract generation")
        if package_id == "ml2_ml3_onnx_agent_parity":
            expected_artifacts = [str(item) for item in require_array(package["expected_artifacts"], f"{path}.packages[{index}].expected_artifacts")]
            required_artifacts = [str(item) for item in require_array(package["required_artifacts"], f"{path}.packages[{index}].required_artifacts")]
            if "docs/benchmarks/runs/ml-prod-candidate-v1-model-contract.json" not in required_artifacts:
                raise ContractError(f"{path}.packages[{index}].required_artifacts: missing production candidate model contract")
            if "docs/benchmarks/runs/ml-prod-candidate-v1-artifacts/malware_smell.json" not in required_artifacts:
                raise ContractError(f"{path}.packages[{index}].required_artifacts: missing production candidate ONNX metadata sidecar")
            if "docs/benchmarks/runs/ml-prod-candidate-v1-ml3-agent-parity-fixture.json" not in expected_artifacts:
                raise ContractError(f"{path}.packages[{index}].expected_artifacts: missing production candidate ML-3 agent parity fixture")
        fingerprints = require_array(
            package["safe_command_fingerprints"],
            f"{path}.packages[{index}].safe_command_fingerprints",
        )
        if len(fingerprints) != len(safe_commands):
            raise ContractError(f"{path}.packages[{index}].safe_command_fingerprints: must match safe_commands length")
        for command_index, command in enumerate(safe_commands):
            if not isinstance(command, str) or not command.startswith(("python ", "cargo ", "powershell ")):
                raise ContractError(f"{path}.packages[{index}].safe_commands: unsupported command {command!r}")
            if command.startswith("powershell ") and " -Execute" in command:
                raise ContractError(f"{path}.packages[{index}].safe_commands: PowerShell safe command must not include -Execute")
            fingerprint = require_object(
                fingerprints[command_index],
                f"{path}.packages[{index}].safe_command_fingerprints[{command_index}]",
            )
            require_keys(
                fingerprint,
                {"index", "command_sha256"},
                f"{path}.packages[{index}].safe_command_fingerprints[{command_index}]",
            )
            if fingerprint["index"] != command_index:
                raise ContractError(
                    f"{path}.packages[{index}].safe_command_fingerprints[{command_index}].index: must match safe_commands index"
                )
            expected_sha = hashlib.sha256(command.encode("utf-8")).hexdigest()
            if str(fingerprint["command_sha256"]) != expected_sha:
                raise ContractError(
                    f"{path}.packages[{index}].safe_command_fingerprints[{command_index}].command_sha256: must match safe_commands"
                )
        if len(str(package["claim_boundary"])) < 10:
            raise ContractError(f"{path}.packages[{index}].claim_boundary: must describe the allowed claim")

    for index, package_value in enumerate(packages):
        package = require_object(package_value, f"{path}.packages[{index}]")
        for dependency in package["dependencies"]:
            if dependency not in package_ids:
                raise ContractError(f"{path}.packages[{index}].dependencies: unknown dependency {dependency!r}")

    declared_counts = require_object(data["status_counts"], f"{path}.status_counts")
    for status, actual_count in status_counts.items():
        declared_count = declared_counts.get(status, 0)
        if not isinstance(declared_count, int) or declared_count != actual_count:
            raise ContractError(f"{path}.status_counts.{status}: expected {actual_count}, got {declared_count!r}")
    validate_execution_plan_launcher_guards(path)


def validate_execution_status(data: dict[str, Any], path: Path) -> None:
    require_keys(data, {"api_version", "kind", "metadata", "source_plan", "required_env", "global_launchers", "next_actions", "waves", "packages"}, str(path))
    if data["api_version"] != EXECUTION_STATUS_API_VERSION:
        raise ContractError(f"{path}: invalid api_version {data['api_version']!r}")
    if data["kind"] != "MLExecutionStatus":
        raise ContractError(f"{path}: invalid kind {data['kind']!r}")

    metadata = require_object(data["metadata"], f"{path}.metadata")
    require_keys(metadata, {"report_id", "generated_at", "created_by", "claim_boundary"}, f"{path}.metadata")
    if len(str(metadata["claim_boundary"])) < 10:
        raise ContractError(f"{path}.metadata.claim_boundary: must describe the allowed claim")

    source_plan = require_object(data["source_plan"], f"{path}.source_plan")
    require_keys(source_plan, {"status_counts", "handoff_dir"}, f"{path}.source_plan")
    source_handoff_dir = str(source_plan["handoff_dir"]).replace("/", "\\").rstrip("\\")

    def require_under_source_handoff(value: Any, field_path: str) -> None:
        normalized = str(value).replace("/", "\\")
        if not normalized.startswith(source_handoff_dir + "\\"):
            raise ContractError(f"{field_path}: must be under source_plan.handoff_dir")

    required_env = require_array(data["required_env"], f"{path}.required_env")
    env_names: set[str] = set()
    for index, env_value in enumerate(required_env):
        env_item = require_object(env_value, f"{path}.required_env[{index}]")
        require_keys(env_item, {"name", "present", "placeholder", "value_redacted"}, f"{path}.required_env[{index}]")
        env_name = str(env_item["name"])
        if env_name in env_names:
            raise ContractError(f"{path}.required_env[{index}].name: duplicate {env_name!r}")
        env_names.add(env_name)
        if not isinstance(env_item["present"], bool) or not isinstance(env_item["placeholder"], bool):
            raise ContractError(f"{path}.required_env[{index}]: present and placeholder must be booleans")
        if env_item["value_redacted"] not in {"present", "missing_or_placeholder"}:
            raise ContractError(f"{path}.required_env[{index}].value_redacted: invalid value {env_item['value_redacted']!r}")
        if env_item["present"] and env_item["value_redacted"] != "present":
            raise ContractError(f"{path}.required_env[{index}].value_redacted: present env must be redacted as present")
        if env_item["placeholder"] and env_item["present"]:
            raise ContractError(f"{path}.required_env[{index}]: placeholder env cannot be present")

    global_launchers = require_array(data["global_launchers"], f"{path}.global_launchers")
    global_launcher_by_name: dict[str, dict[str, Any]] = {}
    for index, launcher_value in enumerate(global_launchers):
        launcher = require_object(launcher_value, f"{path}.global_launchers[{index}]")
        require_keys(launcher, {"name", "path", "exists", "claim_boundary"}, f"{path}.global_launchers[{index}]")
        name = str(launcher["name"])
        if name in global_launcher_by_name:
            raise ContractError(f"{path}.global_launchers[{index}].name: duplicate {name!r}")
        global_launcher_by_name[name] = launcher
        if not isinstance(launcher["exists"], bool):
            raise ContractError(f"{path}.global_launchers[{index}].exists: must be boolean")
        if launcher["exists"] is not True:
            raise ContractError(f"{path}.global_launchers[{index}].exists: required global launcher must exist")
        require_under_source_handoff(launcher["path"], f"{path}.global_launchers[{index}].path")
        boundary = str(launcher["claim_boundary"])
        if "No-execution" not in boundary or "train models" not in boundary:
            raise ContractError(f"{path}.global_launchers[{index}].claim_boundary: must describe no-execution refresh boundary")
    refresh_launcher = global_launcher_by_name.get("ml_readiness_refresh_launcher.ps1")
    if refresh_launcher is None:
        raise ContractError(f"{path}.global_launchers: must include ml_readiness_refresh_launcher.ps1")
    if not str(refresh_launcher["path"]).endswith("ml_readiness_refresh_launcher.ps1"):
        raise ContractError(f"{path}.global_launchers.ml_readiness_refresh_launcher.path: must reference refresh launcher")
    benchmark_launcher = global_launcher_by_name.get("ml_benchmark_refresh_launcher.ps1")
    if benchmark_launcher is None:
        raise ContractError(f"{path}.global_launchers: must include ml_benchmark_refresh_launcher.ps1")
    if not str(benchmark_launcher["path"]).endswith("ml_benchmark_refresh_launcher.ps1"):
        raise ContractError(f"{path}.global_launchers.ml_benchmark_refresh_launcher.path: must reference benchmark refresh launcher")
    prelab_launcher = global_launcher_by_name.get("ml_prelab_validation_launcher.ps1")
    if prelab_launcher is None:
        raise ContractError(f"{path}.global_launchers: must include ml_prelab_validation_launcher.ps1")
    if not str(prelab_launcher["path"]).endswith("ml_prelab_validation_launcher.ps1"):
        raise ContractError(f"{path}.global_launchers.ml_prelab_validation_launcher.path: must reference pre-lab validation launcher")

    waves = require_array(data["waves"], f"{path}.waves")
    wave_ids: set[int] = set()
    for index, wave_value in enumerate(waves):
        wave = require_object(wave_value, f"{path}.waves[{index}]")
        require_keys(wave, {"wave", "purpose", "parallel", "launch_ready", "blockers", "handoff"}, f"{path}.waves[{index}]")
        wave_id = wave["wave"]
        if not isinstance(wave_id, int) or wave_id < 0:
            raise ContractError(f"{path}.waves[{index}].wave: must be a non-negative integer")
        if wave_id in wave_ids:
            raise ContractError(f"{path}.waves[{index}].wave: duplicate {wave_id}")
        wave_ids.add(wave_id)
        require_array(wave["blockers"], f"{path}.waves[{index}].blockers")
        handoff = require_object(wave["handoff"], f"{path}.waves[{index}].handoff")
        require_keys(
            handoff,
            {"wave", "handoff_path", "handoff_exists", "preflight_path", "preflight_exists", "required_launchers"},
            f"{path}.waves[{index}].handoff",
        )
        if handoff["wave"] != wave_id:
            raise ContractError(f"{path}.waves[{index}].handoff.wave: must match wave")
        require_under_source_handoff(handoff["handoff_path"], f"{path}.waves[{index}].handoff.handoff_path")
        require_under_source_handoff(handoff["preflight_path"], f"{path}.waves[{index}].handoff.preflight_path")
        blockers = [str(blocker) for blocker in require_array(wave["blockers"], f"{path}.waves[{index}].blockers")]
        if handoff["handoff_exists"] is False and f"missing_handoff:wave_{wave_id}_handoff.md" not in blockers:
            raise ContractError(f"{path}.waves[{index}].blockers: missing handoff must be reported")
        if handoff["preflight_exists"] is False and f"missing_preflight:wave_{wave_id}_preflight.ps1" not in blockers:
            raise ContractError(f"{path}.waves[{index}].blockers: missing preflight must be reported")
        for launcher_index, launcher_value in enumerate(require_array(handoff["required_launchers"], f"{path}.waves[{index}].handoff.required_launchers")):
            launcher = require_object(launcher_value, f"{path}.waves[{index}].handoff.required_launchers[{launcher_index}]")
            require_keys(launcher, {"name", "path", "exists"}, f"{path}.waves[{index}].handoff.required_launchers[{launcher_index}]")
            require_under_source_handoff(launcher["path"], f"{path}.waves[{index}].handoff.required_launchers[{launcher_index}].path")
            if launcher["exists"] is False and f"missing_launcher:{launcher['name']}" not in blockers:
                raise ContractError(f"{path}.waves[{index}].blockers: missing launcher {launcher['name']} must be reported")
        if wave["launch_ready"] is True and blockers:
            raise ContractError(f"{path}.waves[{index}].launch_ready: cannot be true with blockers")

    packages = require_array(data["packages"], f"{path}.packages")
    package_ids: set[str] = set()
    package_by_id: dict[str, dict[str, Any]] = {}
    status_counts: dict[str, int] = {status: 0 for status in EXECUTION_PLAN_STATUSES}
    for index, package_value in enumerate(packages):
        package = require_object(package_value, f"{path}.packages[{index}]")
        require_keys(
            package,
            {"package_id", "wave", "status", "evidence_state", "launch_ready", "blockers", "claim_boundary", "next_action"},
            f"{path}.packages[{index}]",
        )
        package_id = str(package["package_id"])
        if package_id in package_ids:
            raise ContractError(f"{path}.packages[{index}].package_id: duplicate {package_id!r}")
        package_ids.add(package_id)
        package_by_id[package_id] = package
        if package["wave"] not in wave_ids:
            raise ContractError(f"{path}.packages[{index}].wave: unknown wave {package['wave']!r}")
        status = package["status"]
        if status not in EXECUTION_PLAN_STATUSES:
            raise ContractError(f"{path}.packages[{index}].status: invalid value {status!r}")
        evidence_state = package["evidence_state"]
        if evidence_state not in EXECUTION_STATUS_EVIDENCE_STATES:
            raise ContractError(f"{path}.packages[{index}].evidence_state: invalid value {evidence_state!r}")
        expected_evidence_state = "ready_validation_only" if status == "ready" else status
        if evidence_state != expected_evidence_state:
            raise ContractError(f"{path}.packages[{index}].evidence_state: expected {expected_evidence_state!r}")
        status_counts[status] += 1
        blockers = require_array(package["blockers"], f"{path}.packages[{index}].blockers")
        if package["launch_ready"] and (status not in {"ready", "evidence_exists"} or blockers):
            raise ContractError(f"{path}.packages[{index}].launch_ready: ready packages must have ready/evidence status and no blockers")
        if len(str(package["claim_boundary"])) < 10:
            raise ContractError(f"{path}.packages[{index}].claim_boundary: must describe the allowed claim")

    declared_counts = require_object(source_plan["status_counts"], f"{path}.source_plan.status_counts")
    for status, actual_count in status_counts.items():
        declared_count = declared_counts.get(status, 0)
        if not isinstance(declared_count, int) or declared_count != actual_count:
            raise ContractError(f"{path}.source_plan.status_counts.{status}: expected {actual_count}, got {declared_count!r}")

    actions = require_array(data["next_actions"], f"{path}.next_actions")
    priorities: list[int] = []
    for index, action_value in enumerate(actions):
        action = require_object(action_value, f"{path}.next_actions[{index}]")
        require_keys(action, {"action_type", "package_id", "wave", "priority", "description"}, f"{path}.next_actions[{index}]")
        action_type = action["action_type"]
        if action_type not in EXECUTION_STATUS_ACTION_TYPES:
            raise ContractError(f"{path}.next_actions[{index}].action_type: invalid value {action_type!r}")
        package_id = str(action["package_id"])
        package_lookup_id = {
            "ml_data_virusshare_fallback": "ml_data_governed_acquisition",
        }.get(package_id, package_id)
        if package_lookup_id not in package_by_id:
            raise ContractError(f"{path}.next_actions[{index}].package_id: unknown package {package_id!r}")
        if action["wave"] != package_by_id[package_lookup_id]["wave"]:
            raise ContractError(f"{path}.next_actions[{index}].wave: must match package wave")
        priority = action["priority"]
        if not isinstance(priority, int) or priority < 1:
            raise ContractError(f"{path}.next_actions[{index}].priority: must be a positive integer")
        priorities.append(priority)

        if action_type == "launch_package":
            require_keys(
                action,
                {"validation_command", "execute_command", "execute_guard_env", "claim_boundary"},
                f"{path}.next_actions[{index}]",
            )
            if not package_by_id[package_lookup_id]["launch_ready"] or package_by_id[package_lookup_id]["status"] != "ready":
                raise ContractError(f"{path}.next_actions[{index}]: launch_package must target a ready launchable package")
            if " -Execute" not in str(action["execute_command"]):
                raise ContractError(f"{path}.next_actions[{index}].execute_command: must include -Execute")
            if not str(action["execute_guard_env"]).startswith("TAMANDUA_ALLOW_"):
                raise ContractError(f"{path}.next_actions[{index}].execute_guard_env: must be a TAMANDUA_ALLOW_* guard")
        elif action_type == "publish_dataset_manifest":
            require_keys(
                action,
                {"artifact", "source_artifact", "validation_command", "execute_command", "execute_guard_env", "claim_boundary"},
                f"{path}.next_actions[{index}]",
            )
            if action["artifact"] != "docs/benchmarks/runs/ml-prod-candidate-v1-dataset-manifest.json":
                raise ContractError(f"{path}.next_actions[{index}].artifact: unexpected dataset manifest artifact")
            if not str(action["execute_command"]).endswith("wave_1_manifest_publish_launcher.ps1' -Execute"):
                raise ContractError(f"{path}.next_actions[{index}].execute_command: must execute guarded manifest publish launcher")
            if "publish_dataset_manifest.py" in str(action["execute_command"]):
                raise ContractError(f"{path}.next_actions[{index}].execute_command: must not bypass guarded manifest publish launcher")
            if not str(action["execute_guard_env"]).startswith("TAMANDUA_ALLOW_"):
                raise ContractError(f"{path}.next_actions[{index}].execute_guard_env: must be a TAMANDUA_ALLOW_* guard")
            validation_command = str(action["validation_command"])
            if "Sanitized dataset manifest was not published" not in validation_command:
                raise ContractError(f"{path}.next_actions[{index}].validation_command: must preserve no-publication evidence")
            if (
                "TAMANDUA_ALLOW_ML_MANIFEST_PUBLISH=1" not in validation_command
                and "$env:TAMANDUA_ALLOW_ML_MANIFEST_PUBLISH = '1'" not in validation_command
                and "$env:TAMANDUA_ALLOW_ML_MANIFEST_PUBLISH = ''1''" not in validation_command
            ):
                raise ContractError(f"{path}.next_actions[{index}].validation_command: must print guarded manifest publish command evidence")
        elif action_type == "refresh_post_acquisition_receipts":
            require_keys(
                action,
                {"source_artifact", "validation_command", "execute_guard_env", "claim_boundary"},
                f"{path}.next_actions[{index}]",
            )
            validation_command = str(action["validation_command"]).replace("/", "\\").rstrip("'\"")
            if not validation_command.endswith("wave_1_post_acquisition_refresh_launcher.ps1"):
                raise ContractError(f"{path}.next_actions[{index}].validation_command: must run post-acquisition refresh launcher")
            if action["execute_guard_env"] is not None:
                raise ContractError(f"{path}.next_actions[{index}].execute_guard_env: refresh action must not require an execute guard")
            if "No-execution" not in str(action["claim_boundary"]):
                raise ContractError(f"{path}.next_actions[{index}].claim_boundary: must describe no-execution refresh boundary")
        elif action_type in {"set_required_env", "fix_required_env"}:
            require_keys(action, {"env"}, f"{path}.next_actions[{index}]")
            if action_type == "set_required_env":
                require_keys(action, {"placeholder"}, f"{path}.next_actions[{index}]")
        elif action_type == "produce_required_artifact":
            require_keys(action, {"artifact"}, f"{path}.next_actions[{index}]")
        elif action_type == "wait_for_dependency_evidence":
            require_keys(action, {"dependency_id", "dependency_status", "dependency_evidence_state"}, f"{path}.next_actions[{index}]")
            if action["dependency_id"] not in package_by_id:
                raise ContractError(f"{path}.next_actions[{index}].dependency_id: unknown dependency {action['dependency_id']!r}")
            dependency = package_by_id[str(action["dependency_id"])]
            if action["dependency_status"] != dependency["status"]:
                raise ContractError(f"{path}.next_actions[{index}].dependency_status: must match dependency package status")
            if action["dependency_evidence_state"] != dependency["evidence_state"]:
                raise ContractError(f"{path}.next_actions[{index}].dependency_evidence_state: must match dependency package evidence_state")

    expected_priorities = list(range(1, len(actions) + 1))
    if sorted(priorities) != expected_priorities:
        raise ContractError(f"{path}.next_actions.priority: expected consecutive priorities {expected_priorities}, got {sorted(priorities)}")


def validate_ml_execution_master_handoff(data: dict[str, Any], path: Path) -> None:
    require_keys(
        data,
        {
            "api_version",
            "kind",
            "metadata",
            "source",
            "ready_for_lab_operator",
            "blockers",
            "next_gate",
            "vx_policy",
            "parallel_batches",
            "critical_path_head",
            "critical_path",
            "execution_sequence",
            "goal_completion_audit",
            "summary",
        },
        str(path),
    )
    if data["api_version"] != ML_EXECUTION_MASTER_HANDOFF_API_VERSION:
        raise ContractError(f"{path}: invalid api_version {data['api_version']!r}")
    if data["kind"] != "MLExecutionMasterHandoff":
        raise ContractError(f"{path}: invalid kind {data['kind']!r}")

    metadata = require_object(data["metadata"], f"{path}.metadata")
    require_keys(metadata, {"report_id", "generated_at", "created_by", "claim_boundary"}, f"{path}.metadata")
    boundary = str(metadata["claim_boundary"])
    if "No-execution" not in boundary or "master handoff" not in boundary:
        raise ContractError(f"{path}.metadata.claim_boundary: must describe no-execution master handoff boundary")

    source = require_object(data["source"], f"{path}.source")
    require_keys(
        source,
        {
            "execution_status",
            "execution_status_validation",
            "parallel_work_packages",
            "parallel_work_packages_validation",
            "platform_readiness_audit",
            "platform_readiness_audit_validation",
            "wave1_operator_handoff_index",
            "wave1_operator_handoff_index_validation",
            "wave1_guarded_run_command_packet",
            "wave1_guarded_run_command_packet_validation",
            "benchmark_critical_path",
            "benchmark_critical_path_validation",
            "benchmark_actionability_audit",
            "benchmark_actionability_audit_validation",
            "unblock_validation_status",
            "unblock_validation_status_validation",
            "prelab_contract_coverage",
            "prelab_contract_coverage_validation",
            "next_action_validation_run",
            "next_action_validation_run_validation",
            "source_status_summary",
        },
        f"{path}.source",
    )
    expected_refs = {
        "execution_status": ("20260604T-ml-execution-status.json",),
        "parallel_work_packages": ("20260604T-ml-parallel-work-packages.json",),
        "platform_readiness_audit": (
            "20260604T-ml-platform-readiness-audit.json",
            "20260620T2155Z-ml-platform-readiness-ml6-packets.json",
            "20260621T0020Z-ml-platform-readiness-command-packet-blockers.json",
            "20260621T-ml-platform-readiness-post-readiness-refresh.json",
        ),
        "wave1_operator_handoff_index": ("20260604T-ml-wave1-operator-handoff-index.json",),
        "wave1_guarded_run_command_packet": ("20260604T-ml-wave1-guarded-run-command-packet.json",),
        "benchmark_critical_path": (
            "20260604T-ml-benchmark-critical-path.json",
            "20260620T2005Z-ml-benchmark-critical-path-contract-packets.json",
        ),
        "benchmark_actionability_audit": (
            "20260604T-ml-benchmark-actionability-audit.json",
            "20260620T2035Z-ml-benchmark-actionability-audit-contract-packets.json",
        ),
        "unblock_validation_status": ("20260604T-ml-unblock-validation-status.json",),
        "prelab_contract_coverage": ("20260604T-ml-prelab-contract-coverage.json",),
        "next_action_validation_run": (
            "20260604T-ml-prelab-next-action-validation.run.json",
            "20260621T0110Z-ml-next-action-platform-aligned-lab-root.run.json",
            "20260621T0300Z-ml-next-action-governed-lab-root.run.json",
            "20260621T-ml-next-action-post-readiness-refresh-governed.run.json",
        ),
    }
    for field, suffixes in expected_refs.items():
        if not str(source[field]).endswith(suffixes):
            raise ContractError(f"{path}.source.{field}: must reference canonical {' or '.join(suffixes)}")
    platform_path = resolve_report_path(str(source["platform_readiness_audit"]), path.parent)
    platform_payload = load_json(platform_path)
    validate_ml_platform_readiness_audit(platform_payload, platform_path)
    wave1_handoff_path = resolve_report_path(str(source["wave1_operator_handoff_index"]), path.parent)
    wave1_handoff = load_json(wave1_handoff_path)
    validate_wave1_operator_handoff_index(wave1_handoff, wave1_handoff_path)
    actionability_path = resolve_report_path(str(source["benchmark_actionability_audit"]), path.parent)
    actionability_payload = load_json(actionability_path)
    validate_ml_benchmark_actionability_audit(actionability_payload, actionability_path)
    guarded_packet_path = resolve_report_path(str(source["wave1_guarded_run_command_packet"]), path.parent)
    guarded_packet = load_json(guarded_packet_path)
    run_jsonschema(guarded_packet, WAVE1_GUARDED_RUN_COMMAND_PACKET_SCHEMA, guarded_packet_path)
    unblock_validation_path = resolve_report_path(str(source["unblock_validation_status"]), path.parent)
    unblock_validation_payload = load_json(unblock_validation_path)
    validate_ml_unblock_validation_status(unblock_validation_payload, unblock_validation_path)
    validation_fields = {
        "execution_status_validated": "execution_status_validation",
        "parallel_work_packages_validated": "parallel_work_packages_validation",
        "platform_readiness_validated": "platform_readiness_audit_validation",
        "wave1_operator_handoff_validated": "wave1_operator_handoff_index_validation",
        "benchmark_critical_path_validated": "benchmark_critical_path_validation",
        "benchmark_actionability_audit_validated": "benchmark_actionability_audit_validation",
        "unblock_validation_status_validated": "unblock_validation_status_validation",
        "prelab_contract_coverage_validated": "prelab_contract_coverage_validation",
        "next_action_validation_run_validated": "next_action_validation_run_validation",
    }
    for source_field in validation_fields.values():
        if source[source_field] not in {"jsonschema+built-in", "built-in"}:
            raise ContractError(f"{path}.source.{source_field}: invalid validation mode")
    if str(source["wave1_guarded_run_command_packet_validation"]) != "jsonschema":
        raise ContractError(f"{path}.source.wave1_guarded_run_command_packet_validation: must be jsonschema")

    source_summary = require_object(source["source_status_summary"], f"{path}.source.source_status_summary")
    require_keys(
        source_summary,
        {
            "execution_status_validated",
            "parallel_work_packages_validated",
            "platform_readiness_validated",
            "wave1_operator_handoff_validated",
            "benchmark_critical_path_validated",
            "benchmark_actionability_audit_validated",
            "benchmark_actionability_ready",
            "benchmark_actionability_gap_count",
            "benchmark_actionability_queue_items",
            "benchmark_actionability_queue_items_with_resolution_command",
            "benchmark_actionability_critical_path_steps",
            "benchmark_actionability_critical_path_steps_with_resolution_command",
            "benchmark_actionability_handoff_files",
            "benchmark_actionability_handoff_files_with_resolution_command",
            "benchmark_actionability_validation_only",
            "benchmark_actionability_evidence_usable_for_goal",
            "benchmark_standalone_detection_surface_covered",
            "benchmark_agent_onnx_detection_surface_covered",
            "benchmark_tamandua_detection_surface_covered",
            "benchmark_detection_surface_contract_ready",
            "unblock_validation_status_validated",
            "unblock_actionability_ready",
            "unblock_total_items",
            "unblock_pending_items",
            "unblock_items_with_resolution_command_exposure",
            "unblock_items_without_resolution_command_exposure",
            "unblock_handoff_items_with_resolution_command_exposure",
            "unblock_handoff_items_without_resolution_command_exposure",
            "prelab_contract_coverage_validated",
            "next_action_validation_run_validated",
            "next_action_validation_run_ready",
            "next_action_validation_run_returncode",
            "next_action_validation_run_safety_assertions_passed",
            "next_action_validation_run_guard_absent",
            "next_action_validation_run_matches_next_gate",
            "next_action_validation_run_no_real_operation_evidence",
            "next_action_validation_run_data_root_outside_repo",
            "prelab_contract_coverage_complete",
            "wave1_safe_for_operator",
            "wave1_blocker_count",
            "wave1_goal_snapshot_anchor_check_passed",
            "wave1_lab_standby_readiness_validated",
            "wave1_local_training_readiness_validated",
            "wave1_lab_standby_readiness_ready",
            "wave1_local_training_readiness_ready",
            "wave1_packet_consistency_lab_standby_guard_proof_mismatch_count",
            "wave1_packet_consistency_ml_lab_standby_guards_unset",
            "wave1_pre_execution_transcript_contract_validation_before_run",
            "wave1_pre_execution_transcript_contract_valid_before_run",
            "wave1_pre_execution_transcript_contract_missing_before_run",
            "wave1_acceptance_intake_transcript_contract_validation",
            "wave1_acceptance_intake_transcript_contract_valid",
            "wave1_transcript_contract_valid_for_manifest_publish",
            "wave1_acquisition_transcript_guarded_run_command_packet_sha256",
            "wave1_acquisition_transcript_stdout_sha256",
            "wave1_acquisition_transcript_stderr_sha256",
            "wave1_manifest_transcript_guarded_run_command_packet_sha256",
            "wave1_manifest_transcript_stdout_sha256",
            "wave1_manifest_transcript_stderr_sha256",
            "wave1_transcript_hashes_match_between_receipts",
            "wave1_operator_path_steps",
            "wave1_operator_path_step_count",
            "wave1_operator_publish_guard_env",
            "wave1_guarded_run_command_packet_schema_validated",
            "wave1_guarded_packet_vx_archive_download_guard_env",
            "wave1_guarded_packet_vx_archive_download_guard_present",
            "wave1_guarded_packet_vx_download_authorized",
            "wave1_guarded_packet_vx_inventory_metadata_only",
            "wave1_guarded_packet_vx_samples_allowed_in_training_splits",
            "wave1_guarded_packet_vx_guard_must_remain_unset",
            "next_action_package_id",
            "next_action_type",
            "next_action_wave",
            "next_action_priority",
            "next_action_execute_guard_env",
            "platform_production_candidate_ready",
            "platform_blocker_count",
            "parallel_total_claims",
            "ready_validation_only",
            "blocked",
            "evidence_exists",
            "ready_validation_only_claim_ids",
            "blocked_claim_ids",
            "critical_path_steps",
            "critical_path_pending_items",
            "critical_path_evidence_item_count",
            "critical_path_evidence_usable_for_goal",
            "critical_path_first_phase",
            "critical_path_last_phase",
            "first_critical_target",
            "last_critical_target",
        },
        f"{path}.source.source_status_summary",
    )
    for summary_field, source_field in validation_fields.items():
        if bool(source_summary[summary_field]) != (source[source_field] in {"jsonschema+built-in", "built-in"}):
            raise ContractError(f"{path}.source.source_status_summary.{summary_field}: must match validation mode")

