def validate_ml_lab_standby_readiness(data: dict[str, Any], path: Path) -> None:
    require_keys(data, {"api_version", "kind", "metadata", "configuration", "source_status_summary", "passed", "checks"}, str(path))
    if data["api_version"] != ML_LAB_STANDBY_READINESS_API_VERSION:
        raise ContractError(f"{path}: invalid api_version {data['api_version']!r}")
    if data["kind"] != "MLLabStandbyReadiness":
        raise ContractError(f"{path}: invalid kind {data['kind']!r}")
    if not isinstance(data["passed"], bool):
        raise ContractError(f"{path}.passed: must be boolean")

    metadata = require_object(data["metadata"], f"{path}.metadata")
    require_keys(metadata, {"report_id", "generated_at", "created_by", "claim_boundary"}, f"{path}.metadata")
    boundary = str(metadata["claim_boundary"])
    if "No-execution" not in boundary or "does not run terraform" not in boundary:
        raise ContractError(f"{path}.metadata.claim_boundary: must describe no-execution Terraform boundary")

    configuration = require_object(data["configuration"], f"{path}.configuration")
    require_keys(
        configuration,
        {
            "module_dir",
            "readme",
            "adr",
            "roadmap",
            "required_tf_files",
            "forbidden_active_paths",
            "forbidden_state_patterns",
            "required_unset_guard_env",
        },
        f"{path}.configuration",
    )
    expected_refs = {
        "module_dir": "infra/azure/ml-lab",
        "readme": "infra/azure/ml-lab/README.md",
        "adr": "docs/architecture/adr/ADR-0001-local-first-ml-development.md",
        "roadmap": "ROADMAP.md",
    }
    for field, expected in expected_refs.items():
        if str(configuration[field]).replace("\\", "/") != expected:
            raise ContractError(f"{path}.configuration.{field}: must be {expected}")
    required_tf_files = {str(item) for item in require_array(configuration["required_tf_files"], f"{path}.configuration.required_tf_files")}
    for filename in {"versions.tf", "variables.tf", "main.tf", "network.tf", "storage.tf", "bastion.tf"}:
        if filename not in required_tf_files:
            raise ContractError(f"{path}.configuration.required_tf_files: missing {filename}")
    forbidden_active = {
        str(item) for item in require_array(configuration["forbidden_active_paths"], f"{path}.configuration.forbidden_active_paths")
    }
    for forbidden in {"vm_acquisition.tf", "vm_training.tf", "cloud-init"}:
        if forbidden not in forbidden_active:
            raise ContractError(f"{path}.configuration.forbidden_active_paths: missing {forbidden}")
    forbidden_state = {
        str(item) for item in require_array(configuration["forbidden_state_patterns"], f"{path}.configuration.forbidden_state_patterns")
    }
    for forbidden in {"*.tfstate", ".terraform"}:
        if forbidden not in forbidden_state:
            raise ContractError(f"{path}.configuration.forbidden_state_patterns: missing {forbidden}")
    required_unset_guard_env = {
        str(item)
        for item in require_array(
            configuration["required_unset_guard_env"],
            f"{path}.configuration.required_unset_guard_env",
        )
    }
    for guard in {
        "TAMANDUA_ALLOW_ML_REAL_ACQUISITION",
        "TAMANDUA_ALLOW_ML_MANIFEST_PUBLISH",
        "TAMANDUA_ALLOW_ML_TRAINING",
        "TAMANDUA_ALLOW_ML_PARITY",
        "TAMANDUA_ALLOW_ML_SERVICE_BENCH",
        "TAMANDUA_ALLOW_ML_PIPELINE_REPLAY",
        "TAMANDUA_ALLOW_ML_HOLDOUT",
        "TAMANDUA_ALLOW_VX_UNDERGROUND_DOWNLOAD",
    }:
        if guard not in required_unset_guard_env:
            raise ContractError(f"{path}.configuration.required_unset_guard_env: missing {guard}")

    required_checks = {
        "module_dir_exists",
        "required_terraform_files_present",
        "readme_exists",
        "readme_declares_dormant_standby",
        "readme_references_adr_and_roadmap",
        "adr_local_first_accepted",
        "roadmap_local_first_section_present",
        "terraform_state_absent",
        "active_vm_definitions_absent",
        "storage_public_network_disabled",
        "key_vault_default_deny",
        "compute_nsg_denies_inbound_internet",
        "raw_malware_guard_documented",
        "no_execution_claim_boundary_documented",
        "ml_execution_guards_unset",
    }
    checks = require_array(data["checks"], f"{path}.checks")
    check_by_name: dict[str, dict[str, Any]] = {}
    for index, check_value in enumerate(checks):
        check = require_object(check_value, f"{path}.checks[{index}]")
        require_keys(check, {"name", "passed", "detail"}, f"{path}.checks[{index}]")
        name = str(check["name"])
        if name in check_by_name:
            raise ContractError(f"{path}.checks[{index}].name: duplicate {name!r}")
        if not isinstance(check["passed"], bool):
            raise ContractError(f"{path}.checks[{index}].passed: must be boolean")
        check_by_name[name] = check
    missing = sorted(required_checks.difference(check_by_name))
    if missing:
        raise ContractError(f"{path}.checks: missing required checks: {', '.join(missing)}")

    actual_passed = all(check["passed"] for check in checks)
    if data["passed"] != actual_passed:
        raise ContractError(f"{path}.passed: expected {actual_passed}, got {data['passed']!r}")

    source_summary = require_object(data["source_status_summary"], f"{path}.source_status_summary")
    require_keys(
        source_summary,
        required_checks.union({"check_count", "passed_checks", "failed_checks", "passed"}),
        f"{path}.source_status_summary",
    )
    for name in required_checks:
        if bool(source_summary[name]) != bool(check_by_name[name]["passed"]):
            raise ContractError(f"{path}.source_status_summary.{name}: must match {name}")
    expected_counts = {
        "check_count": len(checks),
        "passed_checks": sum(1 for check in checks if check["passed"] is True),
        "failed_checks": sum(1 for check in checks if check["passed"] is not True),
    }
    for field, expected in expected_counts.items():
        if int(source_summary[field]) != expected:
            raise ContractError(f"{path}.source_status_summary.{field}: must match checks")
    if bool(source_summary["passed"]) != bool(data["passed"]):
        raise ContractError(f"{path}.source_status_summary.passed: must match report")
    if data["passed"]:
        for name in required_checks:
            if check_by_name[name]["passed"] is not True:
                raise ContractError(f"{path}.checks.{name}: required lab standby check must pass")
        state_check = check_by_name["terraform_state_absent"]
        if state_check.get("state_paths"):
            raise ContractError(f"{path}.checks.terraform_state_absent.state_paths: must be empty when passed")
        vm_check = check_by_name["active_vm_definitions_absent"]
        if vm_check.get("active_paths") or vm_check.get("vm_resource_markers"):
            raise ContractError(f"{path}.checks.active_vm_definitions_absent: active VM evidence must be empty when passed")
        guard_check = check_by_name["ml_execution_guards_unset"]
        if guard_check.get("enabled_guards"):
            raise ContractError(f"{path}.checks.ml_execution_guards_unset.enabled_guards: must be empty when passed")


def validate_ml_local_training_readiness(data: dict[str, Any], path: Path) -> None:
    require_keys(data, {"api_version", "kind", "metadata", "configuration", "source_status_summary", "passed", "checks"}, str(path))
    if data["api_version"] != ML_LOCAL_TRAINING_READINESS_API_VERSION:
        raise ContractError(f"{path}: invalid api_version {data['api_version']!r}")
    if data["kind"] != "MLLocalTrainingReadiness":
        raise ContractError(f"{path}: invalid kind {data['kind']!r}")
    if not isinstance(data["passed"], bool):
        raise ContractError(f"{path}.passed: must be boolean")

    metadata = require_object(data["metadata"], f"{path}.metadata")
    require_keys(metadata, {"report_id", "generated_at", "created_by", "claim_boundary"}, f"{path}.metadata")
    boundary = str(metadata["claim_boundary"])
    if "No-execution" not in boundary or "does not build Docker images" not in boundary:
        raise ContractError(f"{path}.metadata.claim_boundary: must describe no-execution local training boundary")

    configuration = require_object(data["configuration"], f"{path}.configuration")
    require_keys(
        configuration,
        {
            "dockerfile",
            "compose",
            "gitattributes",
            "gitignore",
            "verifier",
            "model_lifecycle",
            "adr",
            "ci_workflow",
            "required_lfs_patterns",
            "required_artifact_ignore_patterns",
        },
        f"{path}.configuration",
    )
    expected_refs = {
        "dockerfile": "docker/training-lab/Dockerfile",
        "compose": "docker/training-lab/docker-compose.yml",
        "gitattributes": ".gitattributes",
        "gitignore": ".gitignore",
        "verifier": "scripts/local-training/verify_environment.py",
        "model_lifecycle": "docs/MODEL_LIFECYCLE.md",
        "adr": "docs/architecture/adr/ADR-0001-local-first-ml-development.md",
        "ci_workflow": ".github/workflows/ml-training-lab-smoke.yml",
    }
    for field, expected in expected_refs.items():
        if str(configuration[field]).replace("\\", "/") != expected:
            raise ContractError(f"{path}.configuration.{field}: must be {expected}")
    required_lfs = {str(item) for item in require_array(configuration["required_lfs_patterns"], f"{path}.configuration.required_lfs_patterns")}
    for pattern in {"*.onnx", "*.pt", "*.safetensors"}:
        if pattern not in required_lfs:
            raise ContractError(f"{path}.configuration.required_lfs_patterns: missing {pattern}")
    required_artifact_ignores = {
        str(item)
        for item in require_array(
            configuration["required_artifact_ignore_patterns"],
            f"{path}.configuration.required_artifact_ignore_patterns",
        )
    }
    for pattern in {
        "docs/benchmarks/runs/*-artifacts/*.pt",
        "docs/benchmarks/runs/*-artifacts/*.pth",
        "docs/benchmarks/runs/*-artifacts/*.pkl",
        "docs/benchmarks/runs/*-artifacts/*.npz",
        "docs/benchmarks/runs/*-artifacts/*.onnx",
    }:
        if pattern not in required_artifact_ignores:
            raise ContractError(f"{path}.configuration.required_artifact_ignore_patterns: missing {pattern}")

    required_checks = {
        "dockerfile_exists",
        "compose_exists",
        "gitattributes_exists",
        "gitignore_exists",
        "verifier_exists",
        "model_lifecycle_exists",
        "adr_local_first_accepted",
        "ci_workflow_exists",
        "dockerfile_cuda_pytorch_onnx_uv",
        "dockerfile_non_root_trainer",
        "compose_trainer_network_disabled",
        "compose_gpu_passthrough_declared",
        "compose_dataset_read_only",
        "compose_source_read_only",
        "gitattributes_lfs_patterns_present",
        "gitignore_artifact_binaries_ignored",
        "git_index_artifact_binaries_untracked",
        "verifier_checks_gpu_docker_lfs",
        "model_lifecycle_documents_training_and_lfs",
        "model_lifecycle_references_wave1_dataset_manifest",
        "ci_workflow_builds_training_dockerfile",
        "ci_workflow_does_not_train",
        "no_execution_claim_boundary_documented",
    }
    checks = require_array(data["checks"], f"{path}.checks")
    check_by_name: dict[str, dict[str, Any]] = {}
    for index, check_value in enumerate(checks):
        check = require_object(check_value, f"{path}.checks[{index}]")
        require_keys(check, {"name", "passed", "detail"}, f"{path}.checks[{index}]")
        name = str(check["name"])
        if name in check_by_name:
            raise ContractError(f"{path}.checks[{index}].name: duplicate {name!r}")
        if not isinstance(check["passed"], bool):
            raise ContractError(f"{path}.checks[{index}].passed: must be boolean")
        check_by_name[name] = check
    missing = sorted(required_checks.difference(check_by_name))
    if missing:
        raise ContractError(f"{path}.checks: missing required checks: {', '.join(missing)}")

    actual_passed = all(check["passed"] for check in checks)
    if data["passed"] != actual_passed:
        raise ContractError(f"{path}.passed: expected {actual_passed}, got {data['passed']!r}")

    source_summary = require_object(data["source_status_summary"], f"{path}.source_status_summary")
    require_keys(source_summary, required_checks.union({"check_count", "passed_checks", "failed_checks", "passed"}), f"{path}.source_status_summary")
    for name in required_checks:
        if bool(source_summary[name]) != bool(check_by_name[name]["passed"]):
            raise ContractError(f"{path}.source_status_summary.{name}: must match {name}")
    expected_counts = {
        "check_count": len(checks),
        "passed_checks": sum(1 for check in checks if check["passed"] is True),
        "failed_checks": sum(1 for check in checks if check["passed"] is not True),
    }
    for field, expected in expected_counts.items():
        if int(source_summary[field]) != expected:
            raise ContractError(f"{path}.source_status_summary.{field}: must match checks")
    if bool(source_summary["passed"]) != bool(data["passed"]):
        raise ContractError(f"{path}.source_status_summary.passed: must match report")
    if data["passed"]:
        for name in required_checks:
            if check_by_name[name]["passed"] is not True:
                raise ContractError(f"{path}.checks.{name}: required local training check must pass")
        lfs_check = check_by_name["gitattributes_lfs_patterns_present"]
        if lfs_check.get("missing_lfs"):
            raise ContractError(f"{path}.checks.gitattributes_lfs_patterns_present.missing_lfs: must be empty when passed")
        gitignore_check = check_by_name["gitignore_artifact_binaries_ignored"]
        if gitignore_check.get("missing_artifact_ignores"):
            raise ContractError(
                f"{path}.checks.gitignore_artifact_binaries_ignored.missing_artifact_ignores: must be empty when passed"
            )
        tracked_check = check_by_name["git_index_artifact_binaries_untracked"]
        if tracked_check.get("git_index_available") is not True:
            raise ContractError(
                f"{path}.checks.git_index_artifact_binaries_untracked.git_index_available: must be true when passed"
            )
        if tracked_check.get("tracked_artifact_binaries"):
            raise ContractError(
                f"{path}.checks.git_index_artifact_binaries_untracked.tracked_artifact_binaries: must be empty when passed"
            )


def validate_next_action_run(data: dict[str, Any], path: Path) -> None:
    require_keys(
        data,
        {
            "api_version",
            "kind",
            "status_ref",
            "mode",
            "action",
            "command",
            "returncode",
            "stdout",
            "stderr",
            "env_snapshot",
            "safety_assertions",
            "validation_scope",
            "claim_boundary",
        },
        str(path),
    )
    if data["api_version"] != NEXT_ACTION_RUN_API_VERSION:
        raise ContractError(f"{path}: invalid api_version {data['api_version']!r}")
    if data["kind"] != "MLNextActionRun":
        raise ContractError(f"{path}: invalid kind {data['kind']!r}")
    claim_boundary = str(data["claim_boundary"])
    if len(claim_boundary) < 10:
        raise ContractError(f"{path}.claim_boundary: must describe the allowed claim")
    if mode := data["mode"]:
        if mode == "validation_only":
            required_boundary_terms = (
                "Validation-only mode",
                "does not download malware",
                "train models",
                "run inference",
                "contact live services",
            )
            missing_terms = [term for term in required_boundary_terms if term not in claim_boundary]
            if missing_terms:
                raise ContractError(
                    f"{path}.claim_boundary: validation_only boundary missing required terms: {', '.join(missing_terms)}"
                )

    if mode not in {"validation_only", "execute"}:
        raise ContractError(f"{path}.mode: invalid value {mode!r}")

    action = require_object(data["action"], f"{path}.action")
    require_keys(action, {"priority", "action_type", "package_id", "wave", "execute_guard_env"}, f"{path}.action")
    required_env = action.get("required_env", [])
    if required_env is not None:
        required_env_values = require_array(required_env, f"{path}.action.required_env")
        for index, value in enumerate(required_env_values):
            env_name = str(value)
            if not (env_name.startswith("TAMANDUA_") or env_name == "VIRUSSHARE_API_KEY"):
                raise ContractError(f"{path}.action.required_env[{index}]: unsupported env name")
    if action.get("source_decision_status") is not None and not str(action["source_decision_status"]).strip():
        raise ContractError(f"{path}.action.source_decision_status: must not be empty")
    if action.get("source_decision_ref") is not None and not str(action["source_decision_ref"]).strip():
        raise ContractError(f"{path}.action.source_decision_ref: must not be empty")
    executable_action_types = {"launch_package", "refresh_post_acquisition_receipts", "publish_dataset_manifest"}
    non_executable_action_types = {"set_required_env", "fix_required_env"}
    if action["action_type"] not in executable_action_types.union(non_executable_action_types):
        raise ContractError(f"{path}.action.action_type: expected supported ML action")
    if not isinstance(action["priority"], int) or action["priority"] < 1:
        raise ContractError(f"{path}.action.priority: must be a positive integer")
    if not isinstance(action["wave"], int) or action["wave"] < 0:
        raise ContractError(f"{path}.action.wave: must be a non-negative integer")

    guard = action.get("execute_guard_env")
    if guard is not None and not str(guard).startswith("TAMANDUA_ALLOW_"):
        raise ContractError(f"{path}.action.execute_guard_env: must be a TAMANDUA_ALLOW_* guard")

    snapshot = require_object(data["env_snapshot"], f"{path}.env_snapshot")
    require_keys(snapshot, {"status_required_env", "execute_guard_env"}, f"{path}.env_snapshot")
    status_required_env = require_array(snapshot["status_required_env"], f"{path}.env_snapshot.status_required_env")
    env_by_name: dict[str, dict[str, Any]] = {}
    for index, env_value in enumerate(status_required_env):
        env = require_object(env_value, f"{path}.env_snapshot.status_required_env[{index}]")
        require_keys(env, {"name", "present", "placeholder", "value_redacted"}, f"{path}.env_snapshot.status_required_env[{index}]")
        name = str(env["name"])
        if name in env_by_name:
            raise ContractError(f"{path}.env_snapshot.status_required_env[{index}].name: duplicate {name}")
        env_by_name[name] = env
        if not isinstance(env["present"], bool) or not isinstance(env["placeholder"], bool):
            raise ContractError(f"{path}.env_snapshot.status_required_env[{index}]: present/placeholder must be booleans")
        if env["value_redacted"] not in {"present", "missing_or_placeholder"}:
            raise ContractError(f"{path}.env_snapshot.status_required_env[{index}].value_redacted: invalid value")
        if env["present"] and env["value_redacted"] != "present":
            raise ContractError(f"{path}.env_snapshot.status_required_env[{index}].value_redacted: present env must be redacted as present")
        if not env["present"] and env["value_redacted"] != "missing_or_placeholder":
            raise ContractError(f"{path}.env_snapshot.status_required_env[{index}].value_redacted: missing env must be redacted as missing_or_placeholder")

    guard_snapshot = snapshot.get("execute_guard_env")
    if guard is not None:
        guard_env = require_object(guard_snapshot, f"{path}.env_snapshot.execute_guard_env")
        require_keys(guard_env, {"name", "present", "value_redacted"}, f"{path}.env_snapshot.execute_guard_env")
        if guard_env["name"] != guard:
            raise ContractError(f"{path}.env_snapshot.execute_guard_env.name: must match action execute_guard_env")
        if not isinstance(guard_env["present"], bool):
            raise ContractError(f"{path}.env_snapshot.execute_guard_env.present: must be boolean")
    elif guard_snapshot is not None:
        raise ContractError(f"{path}.env_snapshot.execute_guard_env: must be null when action has no guard")

    validation_scope = require_object(data["validation_scope"], f"{path}.validation_scope")
    require_keys(
        validation_scope,
        {"scope_type", "selected_package_id", "selected_wave", "full_platform_sweep"},
        f"{path}.validation_scope",
    )
    if validation_scope["scope_type"] != "selected_action_only":
        raise ContractError(f"{path}.validation_scope.scope_type: must be selected_action_only")
    if validation_scope["selected_package_id"] != action["package_id"]:
        raise ContractError(f"{path}.validation_scope.selected_package_id: must match action package_id")
    if validation_scope["selected_wave"] != action["wave"]:
        raise ContractError(f"{path}.validation_scope.selected_wave: must match action wave")
    if validation_scope["full_platform_sweep"] is not False:
        raise ContractError(f"{path}.validation_scope.full_platform_sweep: next-action evidence is not a full sweep")

    if "platform_alignment" in data:
        platform_alignment = require_object(data["platform_alignment"], f"{path}.platform_alignment")
        require_keys(
            platform_alignment,
            {"checked", "aligned", "next_requirement_id", "expected_package_id", "selected_package_id"},
            f"{path}.platform_alignment",
        )
        if bool(platform_alignment["checked"]):
            if platform_alignment["aligned"] is not True:
                raise ContractError(f"{path}.platform_alignment.aligned: checked platform alignment must be true")
            selected_package = str(platform_alignment["selected_package_id"])
            selected_base = str(platform_alignment.get("selected_base_package_id") or selected_package)
            if selected_package != str(action["package_id"]):
                raise ContractError(f"{path}.platform_alignment.selected_package_id: must match action package_id")
            if selected_package == "ml_data_virusshare_fallback":
                selected_base = "ml_data_governed_acquisition"
            if selected_base != str(platform_alignment["expected_package_id"]):
                raise ContractError(f"{path}.platform_alignment.expected_package_id: must match selected base package")
            if str(platform_alignment["next_requirement_id"]) == "wave1_governed_acquisition":
                if str(platform_alignment["expected_package_id"]) != "ml_data_governed_acquisition":
                    raise ContractError(f"{path}.platform_alignment.expected_package_id: Wave 1 must map to governed acquisition")
                if platform_alignment.get("next_unblock_action_order") != 1:
                    raise ContractError(f"{path}.platform_alignment.next_unblock_action_order: Wave 1 must be first action")
            readiness_ref = str(platform_alignment.get("readiness_ref", ""))
            if readiness_ref:
                readiness_path = resolve_report_path(readiness_ref, path.parent)
                readiness = load_json(readiness_path)
                validate_ml_platform_readiness_audit(readiness, readiness_path)

    command = str(data["command"])
    if not command.strip():
        raise ContractError(f"{path}.command: must not be empty")
    if action["action_type"] in non_executable_action_types and not command.startswith(f"blocked:{action['action_type']}:"):
        raise ContractError(f"{path}.command: non-executable env action must be recorded as blocked")
    stdout = str(data.get("stdout", ""))
    stderr = str(data.get("stderr", ""))
    returncode = data["returncode"]
    safety = require_object(data["safety_assertions"], f"{path}.safety_assertions")
    require_keys(
        safety,
        {
            "command_validation_only",
            "execute_guard_absent",
            "selected_action_only",
            "no_success_stderr",
            "no_real_operation_evidence",
            "guarded_command_printed",
            "no_real_acquisition_evidence",
            "guarded_would_run_command_printed",
            "data_root_outside_repo",
        },
        f"{path}.safety_assertions",
    )
    data_root_outside_repo = (
        "TAMANDUA_ML_DATA_ROOT" in env_by_name
        and env_by_name["TAMANDUA_ML_DATA_ROOT"].get("outside_repo") is True
    )
    no_real_operation_markers = {
        "set_required_env": ("No execution: required env remediation only.",),
        "fix_required_env": ("No execution: required env remediation only.",),
        "launch_package": (
            "Real acquisition was not executed",
            "VirusShare fallback readiness refreshed without acquisition",
            "ML-1 candidate training/export/benchmark was not executed",
            "ML-2 ONNX parity and ML-3 agent fixture checks were not executed",
            "ML-4 live service benchmark was not executed",
            "ML-5 full pipeline replay was not executed",
            "ML-6 holdout robustness benchmark was not executed",
        ),
        "publish_dataset_manifest": ("Sanitized dataset manifest was not published",),
        "refresh_post_acquisition_receipts": (
            "Wave 1 lab run intake is not ready",
            "Wave 1 receipts are complete",
            "Acquisition receipt is ready",
        ),
    }
    guarded_command_printed = bool(
        guard
        and (
            f"{guard}=1" in stdout
            or f"$env:{guard} = '1'" in stdout
        )
        and (
            "Command that would run after -Execute" in stdout
            or "Commands that would run after -Execute" in stdout
            or "Operator commands from packet:" in stdout
        )
    )
    if (
        mode == "validation_only"
        and data["returncode"] == 0
        and action["package_id"] == "ml_data_governed_acquisition"
        and "download_production_dataset.py" in stdout
    ):
        would_run_markers = (
            "Command that would run after -Execute with the guard set:",
            "Command that would run after -Execute and TAMANDUA_ALLOW_ML_REAL_ACQUISITION=1:",
        )
        if not any(marker in stdout for marker in would_run_markers):
            raise ContractError(f"{path}.stdout: direct acquisition command may appear only as guarded would-run evidence")
    derived_safety = {
        "command_validation_only": " -Execute" not in command and not command.rstrip().endswith("-Execute"),
        "execute_guard_absent": guard_snapshot is None
        or (isinstance(guard_snapshot, dict) and guard_snapshot.get("present") is False),
        "selected_action_only": validation_scope["scope_type"] == "selected_action_only"
        and validation_scope["full_platform_sweep"] is False
        and validation_scope["selected_package_id"] == action["package_id"]
        and validation_scope["selected_wave"] == action["wave"],
        "no_success_stderr": returncode != 0 or not stderr.strip(),
        "no_real_operation_evidence": any(
            marker in stdout for marker in no_real_operation_markers.get(str(action["action_type"]), ())
        ),
        "guarded_command_printed": guarded_command_printed,
        "no_real_acquisition_evidence": "Real acquisition was not executed" in stdout
        or "VirusShare fallback readiness refreshed without acquisition" in stdout,
        "guarded_would_run_command_printed": (
            "Command that would run after -Execute with the guard set:" in stdout
            and "$env:TAMANDUA_ALLOW_ML_REAL_ACQUISITION = '1'" in stdout
            and "download_production_dataset.py" in stdout
        )
        or (
            "Command that would run after -Execute and TAMANDUA_ALLOW_ML_REAL_ACQUISITION=1:" in stdout
            and "download_production_dataset.py" in stdout
        )
        or (
            "Operator commands from packet:" in stdout
            and "$env:TAMANDUA_ALLOW_ML_REAL_ACQUISITION = '1'" in stdout
            and "download_production_dataset.py" in stdout
        ),
        "data_root_outside_repo": data_root_outside_repo,
    }
    for field, expected in derived_safety.items():
        if safety[field] is not expected:
            raise ContractError(f"{path}.safety_assertions.{field}: must match derived receipt evidence")
    if mode == "validation_only":
        if " -Execute" in command or command.rstrip().endswith("-Execute"):
            raise ContractError(f"{path}.command: validation_only reports must not run -Execute commands")
        for field in ("command_validation_only", "execute_guard_absent", "selected_action_only", "no_success_stderr"):
            if safety[field] is not True:
                raise ContractError(f"{path}.safety_assertions.{field}: validation_only requires true")
        if guard is not None:
            guard_snapshot_object = require_object(guard_snapshot, f"{path}.env_snapshot.execute_guard_env")
            if guard_snapshot_object.get("present") is not False:
                raise ContractError(f"{path}.env_snapshot.execute_guard_env.present: validation_only must record absent guard")
            if guard_snapshot_object.get("value_redacted") != "missing_or_placeholder":
                raise ContractError(
                    f"{path}.env_snapshot.execute_guard_env.value_redacted: validation_only guard must be missing_or_placeholder"
                )
        if action["action_type"] == "launch_package":
            if data["returncode"] == 0 and not safety["no_real_operation_evidence"]:
                raise ContractError(f"{path}.safety_assertions.no_real_operation_evidence: successful validation_only launch must preserve no-real-operation evidence")
            if data["returncode"] == 0 and guard is not None and not safety["guarded_command_printed"]:
                raise ContractError(f"{path}.safety_assertions.guarded_command_printed: successful validation_only launch must print guarded would-run command evidence")
            if (
                data["returncode"] == 0
                and action["package_id"] == "ml_data_governed_acquisition"
                and "Real acquisition was not executed" not in stdout
            ):
                raise ContractError(f"{path}.stdout: successful validation_only run must preserve no-acquisition evidence")
            if data["returncode"] == 0 and action["package_id"] == "ml_data_governed_acquisition":
                if "download_production_dataset.py" in command:
                    raise ContractError(f"{path}.command: Wave 1 validation-only receipt must not select direct acquisition")
            if (
                data["returncode"] == 0
                and action["package_id"] == "ml_data_governed_acquisition"
                and not (
                    (
                        "Command that would run after -Execute with the guard set:" in stdout
                        and "$env:TAMANDUA_ALLOW_ML_REAL_ACQUISITION = '1'" in stdout
                        and "download_production_dataset.py" in stdout
                    )
                    or (
                        "Command that would run after -Execute and TAMANDUA_ALLOW_ML_REAL_ACQUISITION=1:" in stdout
                        and "download_production_dataset.py" in stdout
                    )
                )
            ):
                raise ContractError(
                    f"{path}.stdout: successful Wave 1 validation must print the guarded acquisition command as would-run evidence"
                )
            if data["returncode"] == 0 and action["package_id"] == "ml_data_governed_acquisition":
                for field in (
                    "no_real_acquisition_evidence",
                    "guarded_would_run_command_printed",
                    "data_root_outside_repo",
                ):
                    if safety[field] is not True:
                        raise ContractError(f"{path}.safety_assertions.{field}: successful Wave 1 validation requires true")
            if (
                data["returncode"] == 0
                and action["package_id"] == "ml_data_governed_acquisition"
                and (
                    "TAMANDUA_ML_DATA_ROOT" not in env_by_name
                    or env_by_name["TAMANDUA_ML_DATA_ROOT"].get("present") is not True
                    or env_by_name["TAMANDUA_ML_DATA_ROOT"].get("outside_repo") is not True
                )
            ):
                raise ContractError(f"{path}.env_snapshot.status_required_env: successful Wave 1 validation must record external TAMANDUA_ML_DATA_ROOT")
        elif action["action_type"] == "publish_dataset_manifest":
            if data["returncode"] == 0 and "Sanitized dataset manifest was not published" not in stdout:
                raise ContractError(f"{path}.stdout: successful validation_only publish run must preserve no-publication evidence")
            if data["returncode"] == 0 and not safety["no_real_operation_evidence"]:
                raise ContractError(f"{path}.safety_assertions.no_real_operation_evidence: successful publish validation must preserve no-publication evidence")
            if data["returncode"] == 0 and guard is not None and not safety["guarded_command_printed"]:
                raise ContractError(f"{path}.safety_assertions.guarded_command_printed: successful publish validation must print guarded would-run command evidence")
        elif action["action_type"] == "refresh_post_acquisition_receipts":
            if data["returncode"] == 0 and "Wave 1 lab run intake is not ready" not in stdout and "Wave 1 receipts are complete" not in stdout and "Acquisition receipt is ready" not in stdout:
                raise ContractError(f"{path}.stdout: successful validation_only refresh run must preserve post-acquisition refresh evidence")
    else:
        if guard is None:
            raise ContractError(f"{path}.action.execute_guard_env: execute mode requires guard env")
        if action["action_type"] == "launch_package" and " -Execute" not in command and not command.rstrip().endswith("-Execute"):
            raise ContractError(f"{path}.command: execute mode must use -Execute")
        if action["action_type"] == "publish_dataset_manifest":
            if not command.endswith("wave_1_manifest_publish_launcher.ps1' -Execute"):
                raise ContractError(f"{path}.command: execute mode must use guarded manifest publish launcher")
            if "publish_dataset_manifest.py" in command:
                raise ContractError(f"{path}.command: execute mode must not bypass guarded manifest publish launcher")

    if returncode is not None and not isinstance(returncode, int):
        raise ContractError(f"{path}.returncode: must be integer or null")
    if returncode == 0 and stderr.strip():
        raise ContractError(f"{path}.stderr: successful run must not have stderr output")

    if not str(path).startswith("memory:"):
        validate_next_action_run_status_freshness(data, path, action, command, mode)


def validate_next_action_run_status_freshness(
    data: dict[str, Any],
    path: Path,
    action: dict[str, Any],
    command: str,
    mode: str,
) -> None:
    if action.get("package_id") == "ml_data_virusshare_fallback":
        if mode != "validation_only":
            raise ContractError(f"{path}.mode: VirusShare fallback next-action evidence must be validation_only")
        if "wave_1_virusshare_fallback_readiness_launcher.ps1" not in command:
            raise ContractError(f"{path}.command: VirusShare fallback validation must select readiness launcher")
        if action.get("execute_guard_env") != "TAMANDUA_ALLOW_ML_REAL_ACQUISITION":
            raise ContractError(f"{path}.action.execute_guard_env: VirusShare fallback must require real acquisition guard")
        required_env = set(str(value) for value in action.get("required_env", []))
        if not {"TAMANDUA_ML_DATA_ROOT", "VIRUSSHARE_API_KEY"}.issubset(required_env):
            raise ContractError(f"{path}.action.required_env: VirusShare fallback must require data root and API key")
        source_decision_ref = str(action.get("source_decision_ref", ""))
        if not source_decision_ref:
            raise ContractError(f"{path}.action.source_decision_ref: VirusShare fallback must reference source decision evidence")
        source_decision_path = resolve_report_path(source_decision_ref, path.parent)
        source_decision = load_json(source_decision_path)
        source_summary = require_object(source_decision.get("source_status_summary"), f"{source_decision_path}.source_status_summary")
        if "selected_route" in source_summary:
            if source_summary.get("selected_route") != "virusshare_fallback":
                raise ContractError(f"{path}.action.source_decision_ref: selected_route must be virusshare_fallback")
            if source_summary.get("decision_status") != action.get("source_decision_status"):
                raise ContractError(f"{path}.action.source_decision_status: must match source decision")
        else:
            if "ready_for_guarded_virusshare_fallback" not in source_summary:
                raise ContractError(f"{path}.action.source_decision_ref: must reference source decision or VirusShare readiness evidence")
            if action.get("source_decision_status") != "waiting_for_usable_virusshare_secret":
                raise ContractError(f"{path}.action.source_decision_status: must record VirusShare secret wait state")
        return

    status_path = resolve_report_path(str(data["status_ref"]), path.parent)
    status = load_json(status_path)
    validate_execution_status(status, status_path)

    status_actions = require_array(status.get("next_actions"), f"{status_path}.next_actions")
    matching_actions = [
        require_object(action_value, f"{status_path}.next_actions[{index}]")
        for index, action_value in enumerate(status_actions)
        if isinstance(action_value, dict) and action_value.get("priority") == action["priority"]
    ]
    if not matching_actions:
        raise ContractError(f"{path}.action.priority: not present in status_ref next_actions")

    status_action = matching_actions[0]
    for field in ("action_type", "package_id", "wave", "execute_guard_env"):
        if status_action.get(field) != action.get(field):
            raise ContractError(f"{path}.action.{field}: must match status_ref next_actions priority {action['priority']}")

    if action["action_type"] in {"set_required_env", "fix_required_env"}:
        expected_env = str(status_action.get("env", ""))
        if command != f"blocked:{action['action_type']}:{expected_env}":
            raise ContractError(f"{path}.command: must identify blocked env action from status_ref")
        return

    expected_command_field = "execute_command" if mode == "execute" else "validation_command"
    expected_command = status_action.get(expected_command_field)
    if not expected_command:
        raise ContractError(f"{status_path}.next_actions.priority[{action['priority']}].{expected_command_field}: missing")
    if command != str(expected_command):
        raise ContractError(f"{path}.command: must match status_ref {expected_command_field}")
    if (
        mode == "validation_only"
        and action["package_id"] == "ml_data_governed_acquisition"
        and "wave_1_real_acquisition_launcher.ps1" not in command
    ):
        raise ContractError(f"{path}.command: Wave 1 validation-only receipt must select the guarded launcher")

    if mode == "execute":
        guard_snapshot = require_object(data["env_snapshot"]["execute_guard_env"], f"{path}.env_snapshot.execute_guard_env")
        if guard_snapshot.get("present") is not True or guard_snapshot.get("value_redacted") != "present":
            raise ContractError(f"{path}.env_snapshot.execute_guard_env: execute mode must record present guard")


def validate_acquisition_readiness(data: dict[str, Any], path: Path) -> None:
    require_keys(data, {"api_version", "kind", "metadata", "source_status_summary", "vx_policy", "configuration", "passed", "checks"}, str(path))
    if data["api_version"] != ACQUISITION_READINESS_API_VERSION:
        raise ContractError(f"{path}: invalid api_version {data['api_version']!r}")
    if data["kind"] != "MLAcquisitionReadinessProbe":
        raise ContractError(f"{path}: invalid kind {data['kind']!r}")
    if not isinstance(data["passed"], bool):
        raise ContractError(f"{path}.passed: must be boolean")

    metadata = require_object(data["metadata"], f"{path}.metadata")
    require_keys(metadata, {"report_id", "generated_at", "created_by", "claim_boundary"}, f"{path}.metadata")
    claim_boundary = str(metadata["claim_boundary"])
    if len(claim_boundary) < 10 or "Does not download malware" not in claim_boundary:
        raise ContractError(f"{path}.metadata.claim_boundary: must describe the no-execution boundary")

    configuration = require_object(data["configuration"], f"{path}.configuration")
    require_keys(
        configuration,
        {
            "data_root",
            "production_dir",
            "raw_dir",
            "dry_run_ref",
            "vx_inventory_ref",
            "execution_status_ref",
            "real_acquisition_guard_env",
            "manifest_publish_guard_env",
            "malware_bazaar_auth_key_env",
            "real_acquisition_transcript",
            "canonical_dataset_manifest",
            "min_free_gib",
        },
        f"{path}.configuration",
    )
    if not str(configuration["data_root"]).strip():
        raise ContractError(f"{path}.configuration.data_root: must not be empty")
    if not isinstance(configuration["min_free_gib"], int) or configuration["min_free_gib"] < 0:
        raise ContractError(f"{path}.configuration.min_free_gib: must be a non-negative integer")
    if configuration["real_acquisition_guard_env"] != "TAMANDUA_ALLOW_ML_REAL_ACQUISITION":
        raise ContractError(f"{path}.configuration.real_acquisition_guard_env: invalid guard")
    if configuration["manifest_publish_guard_env"] != "TAMANDUA_ALLOW_ML_MANIFEST_PUBLISH":
        raise ContractError(f"{path}.configuration.manifest_publish_guard_env: invalid guard")
    if configuration["malware_bazaar_auth_key_env"] != "TAMANDUA_MALWAREBAZAAR_AUTH_KEY":
        raise ContractError(f"{path}.configuration.malware_bazaar_auth_key_env: invalid Auth-Key env")
    if not str(configuration["real_acquisition_transcript"]).endswith("20260604T-ml-wave1-real-acquisition-transcript.json"):
        raise ContractError(f"{path}.configuration.real_acquisition_transcript: must reference canonical Wave 1 transcript")
    if not str(configuration["canonical_dataset_manifest"]).endswith("ml-prod-candidate-v1-dataset-manifest.json"):
        raise ContractError(f"{path}.configuration.canonical_dataset_manifest: must reference canonical dataset manifest")

    checks = require_array(data["checks"], f"{path}.checks")
    required_checks = {
        "data_root_set",
        "data_root_outside_repo",
        "production_dir_writeable",
        "raw_dir_writeable",
        "free_space_gib",
        "acquisition_dry_run_exists",
        "dry_run_contract_shape_valid",
        "dry_run_output_matches_data_root",
        "dry_run_safety_no_downloads",
        "dry_run_vx_policy_metadata_only_boundary",
        "vx_inventory_metadata_present",
        "vx_inventory_contract_shape_valid",
        "status_next_action_is_acquisition",
        "production_manifest_absent_before_real_run",
        "acquisition_guard_absent_before_real_run",
        "manifest_publish_guard_absent_before_real_run",
        "malware_bazaar_auth_key_present",
        "real_acquisition_transcript_absent_before_real_run",
        "canonical_dataset_manifest_absent_before_real_run",
    }
    check_by_name: dict[str, dict[str, Any]] = {}
    for index, check_value in enumerate(checks):
        check = require_object(check_value, f"{path}.checks[{index}]")
        require_keys(check, {"name", "passed", "detail"}, f"{path}.checks[{index}]")
        name = str(check["name"])
        if name in check_by_name:
            raise ContractError(f"{path}.checks[{index}].name: duplicate {name!r}")
        if not isinstance(check["passed"], bool):
            raise ContractError(f"{path}.checks[{index}].passed: must be boolean")
        check_by_name[name] = check

    missing_checks = sorted(required_checks.difference(check_by_name))
    if missing_checks:
        raise ContractError(f"{path}.checks: missing required checks: {', '.join(missing_checks)}")

    actual_passed = all(check["passed"] for check in checks)
    if data["passed"] != actual_passed:
        raise ContractError(f"{path}.passed: expected {actual_passed}, got {data['passed']!r}")

    source_summary = require_object(data["source_status_summary"], f"{path}.source_status_summary")
    require_keys(
        source_summary,
        {
            "data_root_set",
            "data_root_outside_repo",
            "production_dir_writeable",
            "raw_dir_writeable",
            "free_space_gib",
            "min_free_gib",
            "free_space_meets_minimum",
            "acquisition_dry_run_exists",
            "dry_run_contract_shape_valid",
            "dry_run_output_matches_data_root",
            "dry_run_safety_no_downloads",
            "dry_run_vx_policy_metadata_only_boundary",
            "vx_inventory_ref",
            "vx_inventory_metadata_only",
            "vx_samples_in_training_splits",
            "vx_archive_download_guard_env",
            "vx_archive_download_guard_must_be_unset",
            "vx_inventory_metadata_present",
            "vx_inventory_contract_shape_valid",
            "status_next_action_is_acquisition",
            "production_manifest_absent_before_real_run",
            "acquisition_guard_absent_before_real_run",
            "manifest_publish_guard_absent_before_real_run",
            "malware_bazaar_auth_key_env",
            "malware_bazaar_auth_key_present",
            "real_acquisition_transcript_absent_before_real_run",
            "canonical_dataset_manifest_absent_before_real_run",
            "check_count",
            "passed_checks",
            "failed_checks",
            "passed",
        },
        f"{path}.source_status_summary",
    )
    check_flag_fields = {
        "data_root_set": "data_root_set",
        "data_root_outside_repo": "data_root_outside_repo",
        "production_dir_writeable": "production_dir_writeable",
        "raw_dir_writeable": "raw_dir_writeable",
        "free_space_meets_minimum": "free_space_gib",
        "acquisition_dry_run_exists": "acquisition_dry_run_exists",
        "dry_run_contract_shape_valid": "dry_run_contract_shape_valid",
        "dry_run_output_matches_data_root": "dry_run_output_matches_data_root",
        "dry_run_safety_no_downloads": "dry_run_safety_no_downloads",
        "dry_run_vx_policy_metadata_only_boundary": "dry_run_vx_policy_metadata_only_boundary",
        "vx_inventory_metadata_present": "vx_inventory_metadata_present",
        "vx_inventory_contract_shape_valid": "vx_inventory_contract_shape_valid",
        "status_next_action_is_acquisition": "status_next_action_is_acquisition",
        "production_manifest_absent_before_real_run": "production_manifest_absent_before_real_run",
        "acquisition_guard_absent_before_real_run": "acquisition_guard_absent_before_real_run",
        "manifest_publish_guard_absent_before_real_run": "manifest_publish_guard_absent_before_real_run",
        "malware_bazaar_auth_key_present": "malware_bazaar_auth_key_present",
        "real_acquisition_transcript_absent_before_real_run": "real_acquisition_transcript_absent_before_real_run",
        "canonical_dataset_manifest_absent_before_real_run": "canonical_dataset_manifest_absent_before_real_run",
    }
    for source_field, check_name in check_flag_fields.items():
        if bool(source_summary[source_field]) != bool(check_by_name[check_name]["passed"]):
            raise ContractError(f"{path}.source_status_summary.{source_field}: must match {check_name}")
    if source_summary["malware_bazaar_auth_key_env"] != "TAMANDUA_MALWAREBAZAAR_AUTH_KEY":
        raise ContractError(f"{path}.source_status_summary.malware_bazaar_auth_key_env: invalid Auth-Key env")
    free_space = check_by_name["free_space_gib"]
    free_gib = free_space.get("free_gib")
    min_free_gib = free_space.get("min_free_gib", configuration["min_free_gib"])
    if not isinstance(free_gib, (int, float)):
        raise ContractError(f"{path}.checks.free_space_gib.free_gib: must be numeric")
    if float(source_summary["free_space_gib"]) != float(free_gib):
        raise ContractError(f"{path}.source_status_summary.free_space_gib: must match free_space_gib check")
    if int(source_summary["min_free_gib"]) != int(min_free_gib):
        raise ContractError(f"{path}.source_status_summary.min_free_gib: must match free_space_gib check")
    expected_counts = {
        "check_count": len(checks),
        "passed_checks": sum(1 for check in checks if check["passed"] is True),
        "failed_checks": sum(1 for check in checks if check["passed"] is not True),
    }
    for field, expected in expected_counts.items():
        if int(source_summary[field]) != expected:
            raise ContractError(f"{path}.source_status_summary.{field}: must match checks")
    if bool(source_summary["passed"]) != bool(data["passed"]):
        raise ContractError(f"{path}.source_status_summary.passed: must match report")

    vx_policy = require_object(data["vx_policy"], f"{path}.vx_policy")
    vx_required = {
        "vx_inventory_ref",
        "vx_inventory_metadata_only",
        "vx_samples_in_training_splits",
        "vx_archive_download_guard_env",
        "vx_archive_download_guard_must_be_unset",
        "operator_note",
    }
    require_keys(vx_policy, vx_required, f"{path}.vx_policy")
    if vx_policy["vx_archive_download_guard_env"] != "TAMANDUA_ALLOW_VX_UNDERGROUND_DOWNLOAD":
        raise ContractError(f"{path}.vx_policy.vx_archive_download_guard_env: invalid VX archive guard")
    if vx_policy["vx_archive_download_guard_must_be_unset"] is not True:
        raise ContractError(f"{path}.vx_policy.vx_archive_download_guard_must_be_unset: must be true")
    if vx_policy["vx_inventory_metadata_only"] is not True:
        raise ContractError(f"{path}.vx_policy.vx_inventory_metadata_only: must be true")
    if vx_policy["vx_samples_in_training_splits"] is not False:
        raise ContractError(f"{path}.vx_policy.vx_samples_in_training_splits: must be false")
    note = str(vx_policy["operator_note"]).lower()
    for term in ("metadata", "vx", "download"):
        if term not in note:
            raise ContractError(f"{path}.vx_policy.operator_note: must document VX metadata-only download boundary")
    for field in (
        "vx_inventory_ref",
        "vx_inventory_metadata_only",
        "vx_samples_in_training_splits",
        "vx_archive_download_guard_env",
        "vx_archive_download_guard_must_be_unset",
    ):
        if source_summary[field] != vx_policy[field]:
            raise ContractError(f"{path}.source_status_summary.{field}: must match vx_policy")
    if check_by_name["dry_run_vx_policy_metadata_only_boundary"]["passed"] is not True:
        raise ContractError(f"{path}.checks.dry_run_vx_policy_metadata_only_boundary: must pass")

    if data["passed"]:
        for name in required_checks:
            if check_by_name[name]["passed"] is not True:
                raise ContractError(f"{path}.checks.{name}: required readiness check must pass")
        if free_gib < min_free_gib:
            raise ContractError(f"{path}.checks.free_space_gib: free_gib must meet min_free_gib")

        if not str(path).startswith("memory:"):
            dry_run_ref = resolve_report_path(str(configuration["dry_run_ref"]), path.parent)
            if dry_run_ref.exists():
                validate_acquisition_dry_run(load_json(dry_run_ref), dry_run_ref)
            else:
                raise ContractError(f"{path}.configuration.dry_run_ref: referenced dry-run file does not exist")

            vx_inventory_ref = resolve_report_path(str(configuration["vx_inventory_ref"]), path.parent)
            if vx_inventory_ref.exists():
                validate_vx_underground_inventory(load_json(vx_inventory_ref), vx_inventory_ref)
            else:
                raise ContractError(f"{path}.configuration.vx_inventory_ref: referenced VX inventory file does not exist")


def validate_manifest_publish_transition(data: dict[str, Any], path: Path) -> None:
    require_keys(data, {"api_version", "kind", "metadata", "source_status_summary", "configuration", "passed", "checks", "selected_action"}, str(path))
    if data["api_version"] != MANIFEST_PUBLISH_TRANSITION_API_VERSION:
        raise ContractError(f"{path}: invalid api_version {data['api_version']!r}")
    if data["kind"] != "MLManifestPublishTransitionProbe":
        raise ContractError(f"{path}: invalid kind {data['kind']!r}")
    if not isinstance(data["passed"], bool):
        raise ContractError(f"{path}.passed: must be boolean")

    metadata = require_object(data["metadata"], f"{path}.metadata")
    require_keys(metadata, {"report_id", "generated_at", "created_by", "claim_boundary"}, f"{path}.metadata")
    claim_boundary = str(metadata["claim_boundary"])
    if len(claim_boundary) < 10 or "does not download malware" not in claim_boundary.lower() or "does not" not in claim_boundary.lower():
        raise ContractError(f"{path}.metadata.claim_boundary: must describe the no-execution boundary")

    configuration = require_object(data["configuration"], f"{path}.configuration")
    require_keys(configuration, {"simulation_root", "source_manifest", "status_ref", "next_action_run_ref"}, f"{path}.configuration")
    for field in ("simulation_root", "source_manifest", "status_ref", "next_action_run_ref"):
        if not str(configuration[field]).strip():
            raise ContractError(f"{path}.configuration.{field}: must not be empty")

    checks = require_array(data["checks"], f"{path}.checks")
    required_checks = {
        "simulation_root_outside_repo",
        "synthetic_external_manifest_exists",
        "next_action_is_post_acquisition_refresh",
        "refresh_has_no_execute_guard",
        "validation_only_refreshed_without_publish",
    }
    check_by_name: dict[str, dict[str, Any]] = {}
    for index, check_value in enumerate(checks):
        check = require_object(check_value, f"{path}.checks[{index}]")
        require_keys(check, {"name", "passed", "detail"}, f"{path}.checks[{index}]")
        name = str(check["name"])
        if name in check_by_name:
            raise ContractError(f"{path}.checks[{index}].name: duplicate {name!r}")
        if not isinstance(check["passed"], bool):
            raise ContractError(f"{path}.checks[{index}].passed: must be boolean")
        check_by_name[name] = check

    missing_checks = sorted(required_checks.difference(check_by_name))
    if missing_checks:
        raise ContractError(f"{path}.checks: missing required checks: {', '.join(missing_checks)}")

    actual_passed = all(check["passed"] for check in checks)
    if data["passed"] != actual_passed:
        raise ContractError(f"{path}.passed: expected {actual_passed}, got {data['passed']!r}")

    action = require_object(data["selected_action"], f"{path}.selected_action")
    require_keys(
        action,
        {
            "action_type",
            "package_id",
            "wave",
            "priority",
            "description",
            "source_artifact",
            "validation_command",
            "execute_guard_env",
            "claim_boundary",
        },
        f"{path}.selected_action",
    )
    if action["action_type"] != "refresh_post_acquisition_receipts":
        raise ContractError(f"{path}.selected_action.action_type: expected refresh_post_acquisition_receipts")
    if action["package_id"] != "ml_data_governed_acquisition" or action["wave"] != 1 or action["priority"] != 1:
        raise ContractError(f"{path}.selected_action: must be the Wave 1 post-acquisition refresh action")
    if action["source_artifact"] != configuration["source_manifest"]:
        raise ContractError(f"{path}.selected_action.source_artifact: must match configuration.source_manifest")
    if action["execute_guard_env"] is not None:
        raise ContractError(f"{path}.selected_action.execute_guard_env: expected null for no-execution refresh")
    validation_command = str(action["validation_command"]).replace("/", "\\").rstrip("'\"")
    if not validation_command.endswith("wave_1_post_acquisition_refresh_launcher.ps1"):
        raise ContractError(f"{path}.selected_action.validation_command: must invoke post-acquisition refresh launcher")

    source_summary = require_object(data["source_status_summary"], f"{path}.source_status_summary")
    require_keys(
        source_summary,
        {
            "simulation_root_outside_repo",
            "synthetic_external_manifest_exists",
            "next_action_is_post_acquisition_refresh",
            "refresh_has_no_execute_guard",
            "validation_only_refreshed_without_publish",
            "selected_action_type",
            "selected_package_id",
            "selected_wave",
            "selected_priority",
            "selected_execute_guard_env",
            "check_count",
            "passed_checks",
            "failed_checks",
            "passed",
        },
        f"{path}.source_status_summary",
    )
    check_flag_fields = {
        "simulation_root_outside_repo": "simulation_root_outside_repo",
        "synthetic_external_manifest_exists": "synthetic_external_manifest_exists",
        "next_action_is_post_acquisition_refresh": "next_action_is_post_acquisition_refresh",
        "refresh_has_no_execute_guard": "refresh_has_no_execute_guard",
        "validation_only_refreshed_without_publish": "validation_only_refreshed_without_publish",
    }
    for source_field, check_name in check_flag_fields.items():
        if bool(source_summary[source_field]) != bool(check_by_name[check_name]["passed"]):
            raise ContractError(f"{path}.source_status_summary.{source_field}: must match {check_name}")
    if source_summary["selected_action_type"] != action["action_type"]:
        raise ContractError(f"{path}.source_status_summary.selected_action_type: must match selected_action")
    if source_summary["selected_package_id"] != action["package_id"]:
        raise ContractError(f"{path}.source_status_summary.selected_package_id: must match selected_action")
    if int(source_summary["selected_wave"]) != int(action["wave"]):
        raise ContractError(f"{path}.source_status_summary.selected_wave: must match selected_action")
    if int(source_summary["selected_priority"]) != int(action["priority"]):
        raise ContractError(f"{path}.source_status_summary.selected_priority: must match selected_action")
    if source_summary["selected_execute_guard_env"] != action["execute_guard_env"]:
        raise ContractError(f"{path}.source_status_summary.selected_execute_guard_env: must match selected_action")
    expected_counts = {
        "check_count": len(checks),
        "passed_checks": sum(1 for check in checks if check["passed"] is True),
        "failed_checks": sum(1 for check in checks if check["passed"] is not True),
    }
    for field, expected in expected_counts.items():
        if int(source_summary[field]) != expected:
            raise ContractError(f"{path}.source_status_summary.{field}: must match checks")
    if bool(source_summary["passed"]) != bool(data["passed"]):
        raise ContractError(f"{path}.source_status_summary.passed: must match report")

    if data["passed"]:
        for name in required_checks:
            if check_by_name[name]["passed"] is not True:
                raise ContractError(f"{path}.checks.{name}: required transition check must pass")


def validate_dataset_manifest_publish_probe(data: dict[str, Any], path: Path) -> None:
    require_keys(data, {"api_version", "kind", "metadata", "source_status_summary", "configuration", "passed", "checks", "sample_count"}, str(path))
    if data["api_version"] != DATASET_MANIFEST_PUBLISH_PROBE_API_VERSION:
        raise ContractError(f"{path}: invalid api_version {data['api_version']!r}")
    if data["kind"] != "MLDatasetManifestPublishProbe":
        raise ContractError(f"{path}: invalid kind {data['kind']!r}")
    if not isinstance(data["passed"], bool):
        raise ContractError(f"{path}.passed: must be boolean")
    if not isinstance(data["sample_count"], int) or data["sample_count"] <= 0:
        raise ContractError(f"{path}.sample_count: must be positive integer")

    metadata = require_object(data["metadata"], f"{path}.metadata")
    require_keys(metadata, {"report_id", "generated_at", "created_by", "claim_boundary"}, f"{path}.metadata")
    claim_boundary = str(metadata["claim_boundary"])
    if (
        len(claim_boundary) < 10
        or "does not download malware" not in claim_boundary.lower()
        or "canonical" not in claim_boundary.lower()
    ):
        raise ContractError(f"{path}.metadata.claim_boundary: must describe synthetic non-canonical boundary")

    configuration = require_object(data["configuration"], f"{path}.configuration")
    require_keys(configuration, {"source_manifest", "output_manifest", "canonical_manifest_ref", "dataset_id"}, f"{path}.configuration")
    if configuration["dataset_id"] != "ml-publish-probe-v1":
        raise ContractError(f"{path}.configuration.dataset_id: expected ml-publish-probe-v1")
    for field in ("source_manifest", "output_manifest", "canonical_manifest_ref"):
        if not str(configuration[field]).strip():
            raise ContractError(f"{path}.configuration.{field}: must not be empty")
    if str(configuration["output_manifest"]) == str(configuration["canonical_manifest_ref"]):
        raise ContractError(f"{path}.configuration.output_manifest: must not equal canonical_manifest_ref")
    if "ml-prod-candidate-v1-dataset-manifest.json" not in str(configuration["canonical_manifest_ref"]):
        raise ContractError(f"{path}.configuration.canonical_manifest_ref: must reference production candidate manifest")

    checks = require_array(data["checks"], f"{path}.checks")
    required_checks = {
        "source_manifest_outside_repo",
        "output_is_not_canonical_manifest",
        "raw_samples_not_in_git",
        "malware_and_goodware_present",
        "train_validation_test_splits_present",
        "manifest_contract_validated",
    }
    check_by_name: dict[str, dict[str, Any]] = {}
    for index, check_value in enumerate(checks):
        check = require_object(check_value, f"{path}.checks[{index}]")
        require_keys(check, {"name", "passed", "detail"}, f"{path}.checks[{index}]")
        name = str(check["name"])
        if name in check_by_name:
            raise ContractError(f"{path}.checks[{index}].name: duplicate {name!r}")
        if not isinstance(check["passed"], bool):
            raise ContractError(f"{path}.checks[{index}].passed: must be boolean")
        check_by_name[name] = check

    missing_checks = sorted(required_checks.difference(check_by_name))
    if missing_checks:
        raise ContractError(f"{path}.checks: missing required checks: {', '.join(missing_checks)}")

    actual_passed = all(check["passed"] for check in checks)
    if data["passed"] != actual_passed:
        raise ContractError(f"{path}.passed: expected {actual_passed}, got {data['passed']!r}")

    source_summary = require_object(data["source_status_summary"], f"{path}.source_status_summary")
    require_keys(
        source_summary,
        {
            "source_manifest_outside_repo",
            "output_is_not_canonical_manifest",
            "raw_samples_not_in_git",
            "malware_and_goodware_present",
            "train_validation_test_splits_present",
            "manifest_contract_validated",
            "dataset_id",
            "sample_count",
            "label_count",
            "split_count",
            "check_count",
            "passed_checks",
            "failed_checks",
            "passed",
        },
        f"{path}.source_status_summary",
    )
    check_flag_fields = {
        "source_manifest_outside_repo": "source_manifest_outside_repo",
        "output_is_not_canonical_manifest": "output_is_not_canonical_manifest",
        "raw_samples_not_in_git": "raw_samples_not_in_git",
        "malware_and_goodware_present": "malware_and_goodware_present",
        "train_validation_test_splits_present": "train_validation_test_splits_present",
        "manifest_contract_validated": "manifest_contract_validated",
    }
    for source_field, check_name in check_flag_fields.items():
        if bool(source_summary[source_field]) != bool(check_by_name[check_name]["passed"]):
            raise ContractError(f"{path}.source_status_summary.{source_field}: must match {check_name}")
    if source_summary["dataset_id"] != configuration["dataset_id"]:
        raise ContractError(f"{path}.source_status_summary.dataset_id: must match configuration.dataset_id")
    if int(source_summary["sample_count"]) != int(data["sample_count"]):
        raise ContractError(f"{path}.source_status_summary.sample_count: must match sample_count")
    expected_counts = {
        "check_count": len(checks),
        "passed_checks": sum(1 for check in checks if check["passed"] is True),
        "failed_checks": sum(1 for check in checks if check["passed"] is not True),
    }
    for field, expected in expected_counts.items():
        if int(source_summary[field]) != expected:
            raise ContractError(f"{path}.source_status_summary.{field}: must match checks")
    if bool(source_summary["passed"]) != bool(data["passed"]):
        raise ContractError(f"{path}.source_status_summary.passed: must match report")
    if int(source_summary["label_count"]) < 2:
        raise ContractError(f"{path}.source_status_summary.label_count: must cover malware and goodware")
    if int(source_summary["split_count"]) < 3:
        raise ContractError(f"{path}.source_status_summary.split_count: must cover train/validation/test")

    if data["passed"]:
        for name in required_checks:
            if check_by_name[name]["passed"] is not True:
                raise ContractError(f"{path}.checks.{name}: required publish probe check must pass")
        if str(check_by_name["output_is_not_canonical_manifest"]["detail"]) == str(configuration["canonical_manifest_ref"]):
            raise ContractError(f"{path}.checks.output_is_not_canonical_manifest: detail must not equal canonical manifest")
        if "validate_dataset_manifest passed" not in str(check_by_name["manifest_contract_validated"]["detail"]):
            raise ContractError(f"{path}.checks.manifest_contract_validated: must record dataset contract validation")


