    sequence = [require_object(item, f"{path}.operator_sequence.item") for item in require_array(data["operator_sequence"], f"{path}.operator_sequence")]
    if len(sequence) != 2:
        raise ContractError(f"{path}.operator_sequence: must contain validation and guarded execute steps")
    if int(summary["operator_sequence_steps"]) != len(sequence):
        raise ContractError(f"{path}.source_status_summary.operator_sequence_steps: must match operator sequence")
    validation_step = sequence[0]
    execute_step = sequence[1]
    require_keys(validation_step, {"step", "mode", "command", "required_env", "claim_boundary"}, f"{path}.operator_sequence[0]")
    require_keys(
        execute_step,
        {"step", "mode", "guard_set_command", "command", "required_env", "guard_cleanup_command", "claim_boundary"},
        f"{path}.operator_sequence[1]",
    )
    if int(validation_step["step"]) != 1 or validation_step["mode"] != "validation_only":
        raise ContractError(f"{path}.operator_sequence[0]: first step must be validation_only")
    if "-Execute" in str(validation_step["command"]):
        raise ContractError(f"{path}.operator_sequence[0].command: validation step must not execute")
    if authorization["action_type"] == "launch_package" and str(validation_step["command"]) != str(authorization["validation_command"]):
        raise ContractError(f"{path}.operator_sequence[0].command: must match authorization validation command")
    if require_object(validation_step["required_env"], f"{path}.operator_sequence[0].required_env"):
        raise ContractError(f"{path}.operator_sequence[0].required_env: validation step must not require guards")
    if int(execute_step["step"]) != 2 or execute_step["mode"] != "guarded_execute":
        raise ContractError(f"{path}.operator_sequence[1]: second step must be guarded_execute")
    if authorization["action_type"] == "launch_package" and str(execute_step["command"]) != str(authorization["execute_command"]):
        raise ContractError(f"{path}.operator_sequence[1].command: must match authorization execute command")
    if "TAMANDUA_ALLOW_ML_REAL_ACQUISITION=1" in str(execute_step["command"]):
        raise ContractError(f"{path}.operator_sequence[1].command: execute command must not inline guard assignment")
    if str(execute_step["guard_set_command"]) != "$env:TAMANDUA_ALLOW_ML_REAL_ACQUISITION = '1'":
        raise ContractError(f"{path}.operator_sequence[1].guard_set_command: must set real acquisition guard separately")
    if not source_aware_virusshare_fallback and str(execute_step["guard_set_command"]) != str(brief_execute_step.get("guard_set_command", "")):
        raise ContractError(f"{path}.operator_sequence[1].guard_set_command: must match operator launch brief execute guard")
    execute_required_env = require_object(execute_step["required_env"], f"{path}.operator_sequence[1].required_env")
    brief_execute_required_env = require_object(brief_execute_step.get("required_env"), f"{brief_path}.operator_sequence.execute.required_env")
    if execute_required_env.get("TAMANDUA_ALLOW_ML_REAL_ACQUISITION") != "1":
        raise ContractError(f"{path}.operator_sequence[1].required_env: must require real acquisition guard")
    expected_execute_data_root = str(brief_config_paths["data_root"])
