def validate_wave1_validation_only_guard_drift_probe(data: dict[str, Any], path: Path) -> None:
    require_keys(data, {"api_version", "kind", "metadata", "probe", "source_status_summary", "passed", "checks"}, str(path))
    if data["api_version"] != WAVE1_VALIDATION_ONLY_GUARD_DRIFT_PROBE_API_VERSION:
        raise ContractError(f"{path}: invalid api_version {data['api_version']!r}")
    if data["kind"] != "MLWave1ValidationOnlyGuardDriftProbe":
        raise ContractError(f"{path}: invalid kind {data['kind']!r}")
    metadata = require_object(data["metadata"], f"{path}.metadata")
    require_keys(metadata, {"report_id", "generated_at", "created_by", "claim_boundary"}, f"{path}.metadata")
    boundary = str(metadata["claim_boundary"])
    if "No-execution" not in boundary or "without -Execute" not in boundary:
        raise ContractError(f"{path}.metadata.claim_boundary: must preserve no-execution guard drift boundary")

    probe = require_object(data["probe"], f"{path}.probe")
    require_keys(
        probe,
        {
            "launcher",
            "command",
            "forced_guard_env",
            "returncode",
            "stdout_sha256",
            "stderr_sha256",
            "stdout_preview",
            "stderr_preview",
        },
        f"{path}.probe",
    )
    if not str(probe["launcher"]).endswith("wave_1_real_acquisition_launcher.ps1"):
        raise ContractError(f"{path}.probe.launcher: must reference Wave 1 real acquisition launcher")
    command = [str(item) for item in require_array(probe["command"], f"{path}.probe.command")]
    if "-Execute" in command or any("-Execute" in item for item in command):
        raise ContractError(f"{path}.probe.command: must invoke launcher without -Execute")
    forced_guard_env = require_object(probe["forced_guard_env"], f"{path}.probe.forced_guard_env")
    if forced_guard_env.get("TAMANDUA_ALLOW_ML_REAL_ACQUISITION") != "1":
        raise ContractError(f"{path}.probe.forced_guard_env: must force real acquisition guard drift")
    if int(probe["returncode"]) == 0:
        raise ContractError(f"{path}.probe.returncode: launcher must reject validation-only guard drift")
    for field in ["stdout_sha256", "stderr_sha256"]:
        if not SHA256_RE.match(str(probe[field])):
            raise ContractError(f"{path}.probe.{field}: must be sha256")
    combined_preview = f"{probe['stdout_preview']}\n{probe['stderr_preview']}"
    if "Starting real governed ML acquisition" in combined_preview:
        raise ContractError(f"{path}.probe: must not start real acquisition")
    if "Command that would run after -Execute" in combined_preview:
        raise ContractError(f"{path}.probe: must not print would-run command after guard drift")

    summary = require_object(data["source_status_summary"], f"{path}.source_status_summary")
    require_keys(
        summary,
        {
            "passed",
            "check_count",
            "passed_checks",
            "failed_checks",
            "guard_drift_rejected",
            "real_acquisition_not_started",
            "would_run_command_not_printed",
        },
        f"{path}.source_status_summary",
    )
    checks = [require_object(item, f"{path}.checks.item") for item in require_array(data["checks"], f"{path}.checks")]
    passed_checks = sum(1 for check in checks if bool(check.get("passed")))
    failed_checks = len(checks) - passed_checks
    if int(summary["check_count"]) != len(checks):
        raise ContractError(f"{path}.source_status_summary.check_count: must match checks")
    if int(summary["passed_checks"]) != passed_checks:
        raise ContractError(f"{path}.source_status_summary.passed_checks: must match checks")
    if int(summary["failed_checks"]) != failed_checks:
        raise ContractError(f"{path}.source_status_summary.failed_checks: must match checks")
    expected_passed = failed_checks == 0
    if bool(data["passed"]) != expected_passed or bool(summary["passed"]) != expected_passed:
        raise ContractError(f"{path}.passed: must match check results")
    if summary["guard_drift_rejected"] is not True:
        raise ContractError(f"{path}.source_status_summary.guard_drift_rejected: must be true")
    if summary["real_acquisition_not_started"] is not True:
        raise ContractError(f"{path}.source_status_summary.real_acquisition_not_started: must be true")
    if summary["would_run_command_not_printed"] is not True:
        raise ContractError(f"{path}.source_status_summary.would_run_command_not_printed: must be true")


def validate_wave1_guarded_extra_guard_drift_probe(data: dict[str, Any], path: Path) -> None:
    require_keys(data, {"api_version", "kind", "metadata", "probe", "source_status_summary", "passed", "checks"}, str(path))
    if data["api_version"] != WAVE1_GUARDED_EXTRA_GUARD_DRIFT_PROBE_API_VERSION:
        raise ContractError(f"{path}: invalid api_version {data['api_version']!r}")
    if data["kind"] != "MLWave1GuardedExtraGuardDriftProbe":
        raise ContractError(f"{path}: invalid kind {data['kind']!r}")
    metadata = require_object(data["metadata"], f"{path}.metadata")
    require_keys(metadata, {"report_id", "generated_at", "created_by", "claim_boundary"}, f"{path}.metadata")
    boundary = str(metadata["claim_boundary"])
    if "No-execution" not in boundary or "does not invoke" not in boundary:
        raise ContractError(f"{path}.metadata.claim_boundary: must preserve no-execution guarded extra-guard boundary")

    probe = require_object(data["probe"], f"{path}.probe")
    require_keys(
        probe,
        {
            "preflight_script",
            "command",
            "forced_guard_env",
            "returncode",
            "stdout_sha256",
            "stderr_sha256",
            "stdout_preview",
            "stderr_preview",
        },
        f"{path}.probe",
    )
    if not str(probe["preflight_script"]).endswith("ml_wave1_execution_environment_preflight.py"):
        raise ContractError(f"{path}.probe.preflight_script: must invoke environment preflight")
    command = [str(item) for item in require_array(probe["command"], f"{path}.probe.command")]
    if any("wave_1_real_acquisition_launcher.ps1" in item for item in command):
        raise ContractError(f"{path}.probe.command: must not invoke acquisition launcher")
    if "--mode" not in command or "guarded_execution" not in command:
        raise ContractError(f"{path}.probe.command: must run guarded_execution preflight")
    forced_guard_env = require_object(probe["forced_guard_env"], f"{path}.probe.forced_guard_env")
    if forced_guard_env.get("TAMANDUA_ALLOW_ML_REAL_ACQUISITION") != "1":
        raise ContractError(f"{path}.probe.forced_guard_env: must force acquisition guard for guarded mode")
    if forced_guard_env.get("TAMANDUA_ALLOW_ML_TRAINING") != "1":
        raise ContractError(f"{path}.probe.forced_guard_env: must force extra training guard drift")
    if int(probe["returncode"]) == 0:
        raise ContractError(f"{path}.probe.returncode: preflight must reject extra guard drift")
    for field in ["stdout_sha256", "stderr_sha256"]:
        if not SHA256_RE.match(str(probe[field])):
            raise ContractError(f"{path}.probe.{field}: must be sha256")
    combined_preview = f"{probe['stdout_preview']}\n{probe['stderr_preview']}"
    if "Starting real governed ML acquisition" in combined_preview:
        raise ContractError(f"{path}.probe: must not start real acquisition")
    if "ml_wave1_execution_environment_preflight=blocked" not in combined_preview:
        raise ContractError(f"{path}.probe: must show blocked preflight marker")

    summary = require_object(data["source_status_summary"], f"{path}.source_status_summary")
    require_keys(
        summary,
        {
            "passed",
            "check_count",
            "passed_checks",
            "failed_checks",
            "extra_guard_drift_rejected",
            "real_acquisition_not_started",
            "preflight_reported_blocked",
        },
        f"{path}.source_status_summary",
    )
    checks = [require_object(item, f"{path}.checks.item") for item in require_array(data["checks"], f"{path}.checks")]
    passed_checks = sum(1 for check in checks if bool(check.get("passed")))
    failed_checks = len(checks) - passed_checks
    if int(summary["check_count"]) != len(checks):
        raise ContractError(f"{path}.source_status_summary.check_count: must match checks")
    if int(summary["passed_checks"]) != passed_checks:
        raise ContractError(f"{path}.source_status_summary.passed_checks: must match checks")
    if int(summary["failed_checks"]) != failed_checks:
        raise ContractError(f"{path}.source_status_summary.failed_checks: must match checks")
    expected_passed = failed_checks == 0
    if bool(data["passed"]) != expected_passed or bool(summary["passed"]) != expected_passed:
        raise ContractError(f"{path}.passed: must match check results")
    if summary["extra_guard_drift_rejected"] is not True:
        raise ContractError(f"{path}.source_status_summary.extra_guard_drift_rejected: must be true")
    if summary["real_acquisition_not_started"] is not True:
        raise ContractError(f"{path}.source_status_summary.real_acquisition_not_started: must be true")
    if summary["preflight_reported_blocked"] is not True:
        raise ContractError(f"{path}.source_status_summary.preflight_reported_blocked: must be true")


def validate_wave1_operator_go_no_go_summary(data: dict[str, Any], path: Path) -> None:
    require_keys(
        data,
        {
            "api_version",
            "kind",
            "metadata",
            "source",
            "source_artifact_hashes",
            "vx_policy",
            "operator_decision",
            "operator_sequence",
            "source_status_summary",
            "checks",
        },
        str(path),
    )
    if data["api_version"] != WAVE1_OPERATOR_GO_NO_GO_SUMMARY_API_VERSION:
        raise ContractError(f"{path}: invalid api_version {data['api_version']!r}")
    if data["kind"] != "MLWave1OperatorGoNoGoSummary":
        raise ContractError(f"{path}: invalid kind {data['kind']!r}")
    metadata = require_object(data["metadata"], f"{path}.metadata")
    require_keys(metadata, {"report_id", "generated_at", "created_by", "claim_boundary"}, f"{path}.metadata")
    boundary = str(metadata["claim_boundary"])
    if "No-execution" not in boundary or "does not set guards" not in boundary:
        raise ContractError(f"{path}.metadata.claim_boundary: must preserve no-execution operator summary boundary")

    source = require_object(data["source"], f"{path}.source")
    require_keys(
        source,
        {
            "master_handoff",
            "master_handoff_validation",
            "authorization_packet",
            "authorization_packet_validation",
            "pre_execution_checklist",
            "pre_execution_checklist_validation",
            "execution_environment_preflight",
            "execution_environment_preflight_validation",
            "execute_guard_probe",
            "execute_guard_probe_validation",
            "validation_only_guard_drift_probe",
            "validation_only_guard_drift_probe_validation",
            "guarded_extra_guard_drift_probe",
            "guarded_extra_guard_drift_probe_validation",
        },
        f"{path}.source",
    )
    expected_sources = {
        "master_handoff": (
            "20260604T-ml-execution-master-handoff.json",
            "20260621T-ml-execution-master-handoff-post-readiness-refresh.json",
        ),
        "authorization_packet": (
            "20260604T-ml-next-gate-authorization-packet.json",
            "20260621T0310Z-ml-next-gate-authorization-governed-ready.json",
            "20260621T-ml-next-gate-authorization-post-readiness-refresh-governed.json",
        ),
        "pre_execution_checklist": (
            "20260604T-ml-wave1-pre-execution-checklist.json",
            "20260621T-ml-wave1-pre-execution-checklist-post-readiness-refresh.json",
        ),
        "execution_environment_preflight": "20260604T-ml-wave1-execution-environment-preflight.json",
        "execute_guard_probe": "20260604T-ml-wave1-execute-guard-probe.json",
        "validation_only_guard_drift_probe": "20260604T-ml-wave1-validation-only-guard-drift-probe.json",
        "guarded_extra_guard_drift_probe": "20260604T-ml-wave1-guarded-extra-guard-drift-probe.json",
    }
    for field, suffix in expected_sources.items():
        if not str(source[field]).endswith(suffix):
            raise ContractError(f"{path}.source.{field}: must reference canonical {suffix}")
    for field in [
        "master_handoff_validation",
        "authorization_packet_validation",
        "pre_execution_checklist_validation",
        "execution_environment_preflight_validation",
        "execute_guard_probe_validation",
        "validation_only_guard_drift_probe_validation",
        "guarded_extra_guard_drift_probe_validation",
    ]:
        if source[field] not in {"jsonschema+built-in", "built-in"}:
            raise ContractError(f"{path}.source.{field}: invalid validation mode")

    master_path = resolve_report_path(str(source["master_handoff"]), path.parent)
    authorization_path = resolve_report_path(str(source["authorization_packet"]), path.parent)
    checklist_path = resolve_report_path(str(source["pre_execution_checklist"]), path.parent)
    preflight_path = resolve_report_path(str(source["execution_environment_preflight"]), path.parent)
    execute_guard_path = resolve_report_path(str(source["execute_guard_probe"]), path.parent)
    validation_drift_path = resolve_report_path(str(source["validation_only_guard_drift_probe"]), path.parent)
    extra_guard_drift_path = resolve_report_path(str(source["guarded_extra_guard_drift_probe"]), path.parent)
    source_hashes = require_object(data["source_artifact_hashes"], f"{path}.source_artifact_hashes")
    expected_hash_paths = {
        "master_handoff": master_path,
        "authorization_packet": authorization_path,
        "pre_execution_checklist": checklist_path,
        "execution_environment_preflight": preflight_path,
        "execute_guard_probe": execute_guard_path,
        "validation_only_guard_drift_probe": validation_drift_path,
        "guarded_extra_guard_drift_probe": extra_guard_drift_path,
    }
    for name, expected_path in expected_hash_paths.items():
        hash_item = require_object(source_hashes.get(name), f"{path}.source_artifact_hashes.{name}")
        require_keys(hash_item, {"path", "sha256"}, f"{path}.source_artifact_hashes.{name}")
        if not str(hash_item["path"]).endswith(expected_sources[name]):
            raise ContractError(f"{path}.source_artifact_hashes.{name}.path: must match source artifact")
        if str(hash_item["sha256"]) != hashlib.sha256(expected_path.read_bytes()).hexdigest():
            raise ContractError(f"{path}.source_artifact_hashes.{name}.sha256: must match current artifact")
    master = load_json(master_path)
    authorization = load_json(authorization_path)
    checklist = load_json(checklist_path)
    preflight = load_json(preflight_path)
    execute_guard = load_json(execute_guard_path)
    validation_drift = load_json(validation_drift_path)
    extra_guard_drift = load_json(extra_guard_drift_path)
    validate_ml_execution_master_handoff(master, master_path)
    validate_ml_next_gate_authorization_packet(authorization, authorization_path)
    validate_wave1_pre_execution_checklist(checklist, checklist_path)
    validate_wave1_execution_environment_preflight(preflight, preflight_path)
    validate_wave1_execute_guard(execute_guard, execute_guard_path)
    validate_wave1_validation_only_guard_drift_probe(validation_drift, validation_drift_path)
    validate_wave1_guarded_extra_guard_drift_probe(extra_guard_drift, extra_guard_drift_path)
    vx_policy = require_object(data["vx_policy"], f"{path}.vx_policy")
    preflight_vx_policy = require_object(preflight["vx_policy"], f"{preflight_path}.vx_policy")
    if vx_policy != preflight_vx_policy:
        raise ContractError(f"{path}.vx_policy: must match execution environment preflight")
    vx_expectations = {
        "vx_archive_download_guard_env": "TAMANDUA_ALLOW_VX_UNDERGROUND_DOWNLOAD",
        "vx_archive_download_guard_present": False,
        "vx_download_authorized_by_this_packet": False,
        "vx_inventory_metadata_only": True,
        "vx_samples_allowed_in_training_splits": False,
        "vx_guard_must_remain_unset_for_wave1_acquisition": True,
    }
    require_keys(vx_policy, set(vx_expectations), f"{path}.vx_policy")
    for field, expected in vx_expectations.items():
        if vx_policy[field] != expected:
            raise ContractError(f"{path}.vx_policy.{field}: invalid Wave 1 operator go/no-go VX policy")

    decision = require_object(data["operator_decision"], f"{path}.operator_decision")
    require_keys(
        decision,
        {
            "ready_for_operator_go_no_go",
            "decision",
            "next_gate_package_id",
            "validation_command",
            "execute_command",
            "execute_guard_env",
            "operator_sequence_steps",
            "no_execution_claim_boundary",
        },
        f"{path}.operator_decision",
    )
    if decision["next_gate_package_id"] != "ml_data_governed_acquisition":
        raise ContractError(f"{path}.operator_decision.next_gate_package_id: must be governed acquisition")
    master_summary = require_object(master["summary"], f"{master_path}.summary")
    next_gate = require_object(master["next_gate"], f"{master_path}.next_gate")
    next_gate_action_type = str(next_gate["action_type"])
    if next_gate_action_type == "launch_package":
        if "-Execute" in str(decision["validation_command"]):
            raise ContractError(f"{path}.operator_decision.validation_command: must be validation-only")
        if "-Execute" not in str(decision["execute_command"]):
            raise ContractError(f"{path}.operator_decision.execute_command: must include -Execute")
        if decision["execute_guard_env"] != "TAMANDUA_ALLOW_ML_REAL_ACQUISITION":
            raise ContractError(f"{path}.operator_decision.execute_guard_env: must require real acquisition guard")
    elif decision["validation_command"] is not None or decision["execute_command"] is not None or decision["execute_guard_env"] is not None:
        raise ContractError(f"{path}.operator_decision: env remediation must not expose guarded commands")
    if int(decision["operator_sequence_steps"]) != 2:
        raise ContractError(f"{path}.operator_decision.operator_sequence_steps: must be 2")
    if "not execution evidence" not in str(decision["no_execution_claim_boundary"]):
        raise ContractError(f"{path}.operator_decision.no_execution_claim_boundary: must preserve no-execution boundary")

    auth_summary = require_object(authorization["source_status_summary"], f"{authorization_path}.source_status_summary")
    checklist_summary = require_object(checklist["source_status_summary"], f"{checklist_path}.source_status_summary")
    preflight_summary = require_object(preflight["source_status_summary"], f"{preflight_path}.source_status_summary")
    execute_guard_summary = require_object(execute_guard["source_status_summary"], f"{execute_guard_path}.source_status_summary")
    validation_drift_summary = require_object(validation_drift["source_status_summary"], f"{validation_drift_path}.source_status_summary")
    extra_guard_drift_summary = require_object(extra_guard_drift["source_status_summary"], f"{extra_guard_drift_path}.source_status_summary")
    guard_preconditions = require_object(checklist["guard_preconditions"], f"{checklist_path}.guard_preconditions")
    enabled_guards = [str(item) for item in require_array(guard_preconditions["enabled_guard_env"], f"{checklist_path}.guard_preconditions.enabled_guard_env")]
    operator_sequence = [
        require_object(item, f"{path}.operator_sequence.item")
        for item in require_array(data["operator_sequence"], f"{path}.operator_sequence")
    ]
    checklist_operator_sequence = [
        require_object(item, f"{checklist_path}.operator_sequence.item")
        for item in require_array(checklist["operator_sequence"], f"{checklist_path}.operator_sequence")
    ]
    preflight_operator_sequence = [
        require_object(item, f"{preflight_path}.operator_sequence.item")
        for item in require_array(preflight["operator_sequence"], f"{preflight_path}.operator_sequence")
    ]
    if operator_sequence != checklist_operator_sequence or operator_sequence != preflight_operator_sequence:
        raise ContractError(f"{path}.operator_sequence: must match checklist and preflight operator sequence")
    if int(decision["operator_sequence_steps"]) != len(operator_sequence):
        raise ContractError(f"{path}.operator_decision.operator_sequence_steps: must match operator_sequence")
    missing_requirement_ids = [
        str(item) for item in require_array(master_summary["missing_requirement_ids"], f"{master_path}.summary.missing_requirement_ids")
    ]

    for field in ["next_gate_package_id", "validation_command", "execute_command", "execute_guard_env"]:
        source_field = "package_id" if field == "next_gate_package_id" else field
        if decision[field] != next_gate[source_field]:
            raise ContractError(f"{path}.operator_decision.{field}: must match master handoff next gate")
    expected_decision_ready = decision["decision"] == "go_for_guarded_wave1_acquisition"

    summary = require_object(data["source_status_summary"], f"{path}.source_status_summary")
    require_keys(
        summary,
        {
            "ready_for_operator_go_no_go",
            "check_count",
            "passed_checks",
            "failed_checks",
            "next_gate_package_id",
            "validation_command",
            "execute_command",
            "execute_guard_env",
            "operator_sequence_steps",
            "operator_sequence_ready",
            "authorization_ready",
            "benchmark_standalone_detection_surface_covered",
            "benchmark_agent_onnx_detection_surface_covered",
            "benchmark_tamandua_detection_surface_covered",
            "benchmark_detection_surface_contract_ready",
            "ready_to_set_real_acquisition_guard",
            "goal_snapshot_anchor_check_passed",
            "transcript_contract_validation_before_run",
            "transcript_contract_valid_before_run",
            "transcript_contract_missing_before_run",
            "wave1_pre_execution_transcript_contract_validation_before_run",
            "wave1_pre_execution_transcript_contract_valid_before_run",
            "wave1_pre_execution_transcript_contract_missing_before_run",
            "wave1_acceptance_intake_transcript_contract_validation",
            "wave1_acceptance_intake_transcript_contract_valid",
            "wave1_transcript_contract_valid_for_manifest_publish",
            "data_root_configured",
            "data_root_outside_repo",
            "malware_bazaar_auth_key_env",
            "malware_bazaar_auth_key_present",
            "enabled_guards_before_authorization",
            "vx_archive_download_guard_env",
            "vx_archive_download_guard_present",
            "vx_download_authorized_by_operator_go_no_go",
            "vx_inventory_metadata_only",
            "vx_samples_allowed_in_training_splits",
            "vx_guard_must_remain_unset_for_wave1_acquisition",
            "guard_drift_rejected",
            "extra_guard_drift_rejected",
            "execute_guard_launcher_rejected_without_guard",
            "execute_guard_direct_cli_rejected_without_guard",
            "execute_guard_production_manifest_absent_after_rejection",
            "execute_guard_canonical_manifest_absent_after_rejection",
            "real_acquisition_not_started",
            "goal_complete",
            "completion_state",
            "goal_missing_requirements",
            "goal_required_evidence_total",
            "goal_present_required_evidence",
            "goal_usable_required_evidence",
            "goal_missing_required_evidence",
            "goal_unusable_present_required_evidence",
            "next_unproven_requirement_id",
            "next_unproven_requirement_phase",
            "next_unproven_execute_guard_env",
            "missing_requirement_count",
            "missing_requirement_ids",
            "evidence_status_summary",
            "next_unproven_requirement",
        },
        f"{path}.source_status_summary",
    )
    checks = [require_object(item, f"{path}.checks.item") for item in require_array(data["checks"], f"{path}.checks")]
    passed_checks = sum(1 for check in checks if bool(check.get("passed")))
    failed_checks = len(checks) - passed_checks
    expected_ready = failed_checks == 0
    if int(summary["check_count"]) != len(checks):
        raise ContractError(f"{path}.source_status_summary.check_count: must match checks")
    if int(summary["passed_checks"]) != passed_checks:
        raise ContractError(f"{path}.source_status_summary.passed_checks: must match checks")
    if int(summary["failed_checks"]) != failed_checks:
        raise ContractError(f"{path}.source_status_summary.failed_checks: must match checks")
    if bool(decision["ready_for_operator_go_no_go"]) != expected_ready or bool(summary["ready_for_operator_go_no_go"]) != expected_ready:
        raise ContractError(f"{path}.operator_decision.ready_for_operator_go_no_go: must match check results")
    if expected_decision_ready != expected_ready:
        raise ContractError(f"{path}.operator_decision.decision: must match readiness")

    expected_summary = {
        "next_gate_package_id": next_gate["package_id"],
        "validation_command": next_gate["validation_command"],
        "execute_command": next_gate["execute_command"],
        "execute_guard_env": next_gate["execute_guard_env"],
        "operator_sequence_steps": len(operator_sequence),
        "operator_sequence_ready": bool(checklist_summary["operator_sequence_ready"])
        and bool(preflight_summary["operator_sequence_ready"])
        and operator_sequence == preflight_operator_sequence,
        "authorization_ready": bool(auth_summary["authorized_for_guarded_execution"]),
        "benchmark_standalone_detection_surface_covered": bool(
            auth_summary["benchmark_standalone_detection_surface_covered"]
        ),
        "benchmark_agent_onnx_detection_surface_covered": bool(
            auth_summary["benchmark_agent_onnx_detection_surface_covered"]
        ),
        "benchmark_tamandua_detection_surface_covered": bool(auth_summary["benchmark_tamandua_detection_surface_covered"]),
        "benchmark_detection_surface_contract_ready": bool(auth_summary["benchmark_detection_surface_contract_ready"]),
        "ready_to_set_real_acquisition_guard": bool(checklist_summary["ready_to_set_real_acquisition_guard"]),
        "goal_snapshot_anchor_check_passed": bool(checklist_summary["goal_snapshot_anchor_check_passed"])
        and bool(preflight_summary["goal_snapshot_anchor_check_passed"]),
        "transcript_contract_validation_before_run": str(preflight_summary["transcript_contract_validation_before_run"]),
        "transcript_contract_valid_before_run": bool(preflight_summary["transcript_contract_valid_before_run"]),
        "transcript_contract_missing_before_run": bool(preflight_summary["transcript_contract_missing_before_run"]),
        "wave1_pre_execution_transcript_contract_validation_before_run": str(
            preflight_summary["wave1_pre_execution_transcript_contract_validation_before_run"]
        ),
        "wave1_pre_execution_transcript_contract_valid_before_run": bool(
            preflight_summary["wave1_pre_execution_transcript_contract_valid_before_run"]
        ),
        "wave1_pre_execution_transcript_contract_missing_before_run": bool(
            preflight_summary["wave1_pre_execution_transcript_contract_missing_before_run"]
        ),
        "wave1_acceptance_intake_transcript_contract_validation": str(
            preflight_summary["wave1_acceptance_intake_transcript_contract_validation"]
        ),
        "wave1_acceptance_intake_transcript_contract_valid": bool(
            preflight_summary["wave1_acceptance_intake_transcript_contract_valid"]
        ),
        "wave1_transcript_contract_valid_for_manifest_publish": bool(
            preflight_summary["wave1_transcript_contract_valid_for_manifest_publish"]
        ),
        "data_root_configured": bool(preflight_summary["data_root_configured"]),
        "data_root_outside_repo": bool(preflight_summary["data_root_outside_repo"]),
        "malware_bazaar_auth_key_env": str(preflight_summary["malware_bazaar_auth_key_env"]),
        "malware_bazaar_auth_key_present": bool(preflight_summary["malware_bazaar_auth_key_present"]),
        "enabled_guards_before_authorization": len(enabled_guards),
        "vx_archive_download_guard_env": vx_policy["vx_archive_download_guard_env"],
        "vx_archive_download_guard_present": vx_policy["vx_archive_download_guard_present"],
        "vx_download_authorized_by_operator_go_no_go": vx_policy["vx_download_authorized_by_this_packet"],
        "vx_inventory_metadata_only": vx_policy["vx_inventory_metadata_only"],
        "vx_samples_allowed_in_training_splits": vx_policy["vx_samples_allowed_in_training_splits"],
        "vx_guard_must_remain_unset_for_wave1_acquisition": vx_policy[
            "vx_guard_must_remain_unset_for_wave1_acquisition"
        ],
        "guard_drift_rejected": bool(validation_drift_summary["guard_drift_rejected"]),
        "extra_guard_drift_rejected": bool(extra_guard_drift_summary["extra_guard_drift_rejected"]),
        "execute_guard_launcher_rejected_without_guard": bool(execute_guard_summary["execute_rejected_without_guard"]),
        "execute_guard_direct_cli_rejected_without_guard": bool(execute_guard_summary["direct_cli_rejected_without_guard"]),
        "execute_guard_production_manifest_absent_after_rejection": bool(
            execute_guard_summary["production_manifest_absent_after_rejection"]
        ),
        "execute_guard_canonical_manifest_absent_after_rejection": bool(
            execute_guard_summary["canonical_dataset_manifest_absent_after_rejection"]
        ),
        "real_acquisition_not_started": bool(validation_drift_summary["real_acquisition_not_started"])
        and bool(extra_guard_drift_summary["real_acquisition_not_started"]),
        "goal_complete": bool(master_summary["goal_complete"]),
        "completion_state": str(master_summary["completion_state"]),
        "goal_missing_requirements": int(preflight_summary["goal_missing_requirements"]),
        "goal_required_evidence_total": int(preflight_summary["goal_required_evidence_total"]),
        "goal_present_required_evidence": int(preflight_summary["goal_present_required_evidence"]),
        "goal_usable_required_evidence": int(preflight_summary["goal_usable_required_evidence"]),
        "goal_missing_required_evidence": int(preflight_summary["goal_missing_required_evidence"]),
        "goal_unusable_present_required_evidence": int(preflight_summary["goal_unusable_present_required_evidence"]),
        "next_unproven_requirement_id": str(preflight_summary["next_unproven_requirement_id"]),
        "next_unproven_requirement_phase": str(preflight_summary["next_unproven_requirement_phase"]),
        "next_unproven_execute_guard_env": str(preflight_summary["next_unproven_execute_guard_env"]),
        "missing_requirement_count": len(missing_requirement_ids),
        "missing_requirement_ids": missing_requirement_ids,
        "evidence_status_summary": preflight_summary["evidence_status_summary"],
        "next_unproven_requirement": preflight_summary["next_unproven_requirement"],
    }
    for field, expected in expected_summary.items():
        if summary[field] != expected:
            raise ContractError(f"{path}.source_status_summary.{field}: must match current source artifacts")
    required_true_fields = [
        "benchmark_standalone_detection_surface_covered",
        "benchmark_agent_onnx_detection_surface_covered",
        "benchmark_tamandua_detection_surface_covered",
        "benchmark_detection_surface_contract_ready",
        "goal_snapshot_anchor_check_passed",
        "data_root_configured",
        "data_root_outside_repo",
        "guard_drift_rejected",
        "extra_guard_drift_rejected",
        "execute_guard_launcher_rejected_without_guard",
        "execute_guard_direct_cli_rejected_without_guard",
        "execute_guard_production_manifest_absent_after_rejection",
        "execute_guard_canonical_manifest_absent_after_rejection",
        "real_acquisition_not_started",
    ]
    for field in required_true_fields:
        if summary[field] is not True:
            raise ContractError(f"{path}.source_status_summary.{field}: must be true for operator go/no-go")
    if int(summary["enabled_guards_before_authorization"]) != 0:
        raise ContractError(f"{path}.source_status_summary.enabled_guards_before_authorization: must be 0")
    check_by_name = {str(check.get("name")): check for check in checks}
    if check_by_name.get("vx_policy_metadata_only_boundary", {}).get("passed") is not True:
        raise ContractError(f"{path}.checks.vx_policy_metadata_only_boundary: must pass")
    if check_by_name.get("execute_guard_probe_rejects_launcher_and_direct_cli", {}).get("passed") is not True:
        raise ContractError(f"{path}.checks.execute_guard_probe_rejects_launcher_and_direct_cli: must pass")
    auth_check = check_by_name.get("malware_bazaar_auth_key_present")
    if auth_check is None:
        raise ContractError(f"{path}.checks: missing malware_bazaar_auth_key_present")
    if bool(auth_check.get("passed")) != bool(preflight_summary["malware_bazaar_auth_key_present"]):
        raise ContractError(f"{path}.checks.malware_bazaar_auth_key_present: must match preflight")
    goal_snapshot_anchor_check = check_by_name.get("goal_snapshot_anchor_preserved_before_guard")
    if goal_snapshot_anchor_check is None:
        raise ContractError(f"{path}.checks: missing goal_snapshot_anchor_preserved_before_guard")
    if goal_snapshot_anchor_check.get("passed") is not True:
        raise ContractError(f"{path}.checks.goal_snapshot_anchor_preserved_before_guard: must pass")
    if "TAMANDUA_ALLOW_VX_UNDERGROUND_DOWNLOAD" not in str(check_by_name["vx_policy_metadata_only_boundary"].get("detail", "")):
        raise ContractError(f"{path}.checks.vx_policy_metadata_only_boundary: must document VX archive guard")
    if summary["wave1_pre_execution_transcript_contract_validation_before_run"] != "missing":
        raise ContractError(
            f"{path}.source_status_summary.wave1_pre_execution_transcript_contract_validation_before_run: must be missing"
        )
    if summary["wave1_pre_execution_transcript_contract_valid_before_run"] is not False:
        raise ContractError(
            f"{path}.source_status_summary.wave1_pre_execution_transcript_contract_valid_before_run: must be false"
        )
    if summary["wave1_pre_execution_transcript_contract_missing_before_run"] is not True:
        raise ContractError(
            f"{path}.source_status_summary.wave1_pre_execution_transcript_contract_missing_before_run: must be true"
        )
    if check_by_name.get("wave1_transcript_contract_blocks_manifest_publish_before_real_evidence", {}).get("passed") is not True:
        raise ContractError(
            f"{path}.checks.wave1_transcript_contract_blocks_manifest_publish_before_real_evidence: must pass"
        )
    if summary["goal_complete"] is not False or summary["completion_state"] not in {"not_executed", "partial_evidence"}:
        raise ContractError(f"{path}.source_status_summary: must not claim goal completion")
    if int(summary["missing_requirement_count"]) != 9:
        raise ContractError(f"{path}.source_status_summary.missing_requirement_count: must remain 9 before real evidence")
    if int(summary["goal_missing_requirements"]) != len(missing_requirement_ids):
        raise ContractError(f"{path}.source_status_summary.goal_missing_requirements: must match missing requirements")
    if summary["next_unproven_requirement_id"] != "wave1_governed_acquisition":
        raise ContractError(f"{path}.source_status_summary.next_unproven_requirement_id: must remain Wave 1 before real evidence")


def validate_wave1_guarded_run_command_packet(data: dict[str, Any], path: Path) -> None:
    require_keys(
        data,
        {
            "api_version",
            "kind",
            "metadata",
            "source",
            "operator_commands",
            "post_execution_commands",
            "data_root",
            "repo_manifest",
            "vx_policy",
            "transcript_capture_contract",
            "source_artifact_hashes",
            "source_status_summary",
            "ready_for_guarded_wave1_acquisition",
            "execution_blockers",
            "next_unblock_actions",
            "checks",
        },
        str(path),
    )
    if data["api_version"] != WAVE1_GUARDED_RUN_COMMAND_PACKET_API_VERSION:
        raise ContractError(f"{path}: invalid api_version {data['api_version']!r}")
    if data["kind"] != "MLWave1GuardedRunCommandPacket":
        raise ContractError(f"{path}: invalid kind {data['kind']!r}")
    metadata = require_object(data["metadata"], f"{path}.metadata")
    require_keys(metadata, {"report_id", "generated_at", "created_by", "claim_boundary"}, f"{path}.metadata")
    boundary = str(metadata["claim_boundary"])
    if "No-execution" not in boundary or "does not set guards" not in boundary:
        raise ContractError(f"{path}.metadata.claim_boundary: must preserve no-execution guarded-run boundary")

    source = require_object(data["source"], f"{path}.source")
    required_source_keys = {
        "master_handoff",
        "master_handoff_validation",
        "authorization_packet",
        "authorization_packet_validation",
        "pre_execution_checklist",
        "pre_execution_checklist_validation",
        "execution_environment_preflight",
        "execution_environment_preflight_validation",
        "operator_go_no_go_summary",
        "operator_go_no_go_summary_validation",
        "next_action_run",
        "next_action_run_validation",
        "acquisition_readiness",
        "acquisition_readiness_validation",
        "execute_guard_probe",
        "execute_guard_probe_validation",
        "launcher",
    }
    require_keys(source, required_source_keys, f"{path}.source")
    expected_sources = {
        "master_handoff": (
            "20260604T-ml-execution-master-handoff.json",
            "20260621T-ml-execution-master-handoff-post-readiness-refresh.json",
        ),
        "authorization_packet": (
            "20260604T-ml-next-gate-authorization-packet.json",
            "20260621T0310Z-ml-next-gate-authorization-governed-ready.json",
            "20260621T-ml-next-gate-authorization-post-readiness-refresh-governed.json",
        ),
        "pre_execution_checklist": (
            "20260604T-ml-wave1-pre-execution-checklist.json",
            "20260621T-ml-wave1-pre-execution-checklist-post-readiness-refresh.json",
        ),
        "execution_environment_preflight": "20260604T-ml-wave1-execution-environment-preflight.json",
        "operator_go_no_go_summary": (
            "20260604T-ml-wave1-operator-go-no-go-summary.json",
            "20260621T-ml-wave1-operator-go-no-go-summary-post-readiness-refresh.json",
        ),
        "next_action_run": (
            "20260604T-ml-prelab-next-action-validation.run.json",
            "20260621T0300Z-ml-next-action-governed-lab-root.run.json",
            "20260621T-ml-next-action-post-readiness-refresh-governed.run.json",
        ),
        "acquisition_readiness": "20260604T-ml-acquisition-readiness.json",
        "execute_guard_probe": "20260604T-ml-wave1-execute-guard-probe.json",
        "launcher": "wave_1_real_acquisition_launcher.ps1",
    }
    for field, suffix in expected_sources.items():
        if not str(source[field]).endswith(suffix):
            raise ContractError(f"{path}.source.{field}: must reference canonical {suffix}")
    for field in [key for key in required_source_keys if key.endswith("_validation")]:
        if source[field] not in {"jsonschema+built-in", "built-in"}:
            raise ContractError(f"{path}.source.{field}: invalid validation mode")

    master_path = resolve_report_path(str(source["master_handoff"]), path.parent)
    authorization_path = resolve_report_path(str(source["authorization_packet"]), path.parent)
    checklist_path = resolve_report_path(str(source["pre_execution_checklist"]), path.parent)
    preflight_path = resolve_report_path(str(source["execution_environment_preflight"]), path.parent)
    operator_path = resolve_report_path(str(source["operator_go_no_go_summary"]), path.parent)
    next_action_path = resolve_report_path(str(source["next_action_run"]), path.parent)
    acquisition_readiness_path = resolve_report_path(str(source["acquisition_readiness"]), path.parent)
    execute_guard_path = resolve_report_path(str(source["execute_guard_probe"]), path.parent)
    launcher_path = resolve_report_path(str(source["launcher"]), path.parent)

    master = load_json(master_path)
    authorization = load_json(authorization_path)
    checklist = load_json(checklist_path)
    preflight = load_json(preflight_path)
    operator = load_json(operator_path)
    next_action = load_json(next_action_path)
    acquisition_readiness = load_json(acquisition_readiness_path)
    execute_guard = load_json(execute_guard_path)
    validate_ml_execution_master_handoff(master, master_path)
    validate_ml_next_gate_authorization_packet(authorization, authorization_path)
    validate_wave1_pre_execution_checklist(checklist, checklist_path)
    validate_wave1_execution_environment_preflight(preflight, preflight_path)
    validate_wave1_operator_go_no_go_summary(operator, operator_path)
    validate_next_action_run(next_action, next_action_path)
    validate_acquisition_readiness(acquisition_readiness, acquisition_readiness_path)
    validate_wave1_execute_guard(execute_guard, execute_guard_path)
    next_action_safety = require_object(next_action["safety_assertions"], f"{next_action_path}.safety_assertions")
    next_action_ready = (
        next_action["mode"] == "validation_only"
        and next_action["returncode"] == 0
        and next_action_safety["command_validation_only"] is True
        and next_action_safety["execute_guard_absent"] is True
        and next_action_safety["guarded_would_run_command_printed"] is True
        and next_action_safety["no_real_acquisition_evidence"] is True
        and next_action_safety["data_root_outside_repo"] is True
    )

    commands = require_object(data["operator_commands"], f"{path}.operator_commands")
    command_fields = {
        "data_root_set_command",
        "guard_set_command",
        "validation_command",
        "execute_command",
        "guard_cleanup_command",
        "acquisition_command",
        "execute_command_has_execute",
        "validation_command_has_execute",
        "guard_set_separate",
        "execute_command_inlines_guard",
        "command_sha256",
    }
    require_keys(commands, command_fields, f"{path}.operator_commands")
    operator_sequence = [
        require_object(item, f"{operator_path}.operator_sequence.item")
        for item in require_array(operator["operator_sequence"], f"{operator_path}.operator_sequence")
    ]
    validation_step = operator_sequence[0]
    execute_step = operator_sequence[1]
    data_root = require_object(data["data_root"], f"{path}.data_root")
    repo_manifest = require_object(data["repo_manifest"], f"{path}.repo_manifest")
    require_keys(data_root, {"env", "raw", "resolved", "outside_repo", "production_manifest", "production_manifest_present"}, f"{path}.data_root")
    require_keys(repo_manifest, {"path", "present"}, f"{path}.repo_manifest")
    expected_data_root_set_command = f"$env:TAMANDUA_ML_DATA_ROOT = '{data_root['raw']}'"
    if commands["data_root_set_command"] != expected_data_root_set_command:
        raise ContractError(f"{path}.operator_commands.data_root_set_command: must set configured data root explicitly")
    if commands["guard_set_command"] != "$env:TAMANDUA_ALLOW_ML_REAL_ACQUISITION = '1'":
        raise ContractError(f"{path}.operator_commands.guard_set_command: must set the real acquisition guard explicitly")
    if commands["guard_cleanup_command"] != "Remove-Item Env:TAMANDUA_ALLOW_ML_REAL_ACQUISITION -ErrorAction SilentlyContinue":
        raise ContractError(f"{path}.operator_commands.guard_cleanup_command: must clean only the real acquisition guard")
    if commands["validation_command"] != validation_step["command"] or "-Execute" in str(commands["validation_command"]):
        raise ContractError(f"{path}.operator_commands.validation_command: must match validation-only operator step")
    if commands["execute_command"] != execute_step["command"] or "-Execute" not in str(commands["execute_command"]):
        raise ContractError(f"{path}.operator_commands.execute_command: must match guarded execute operator step")
    if commands["execute_command_has_execute"] is not True or commands["validation_command_has_execute"] is not False:
        raise ContractError(f"{path}.operator_commands: execute flags must distinguish validation from execution")
    if commands["guard_set_separate"] is not True or commands["execute_command_inlines_guard"] is not False:
        raise ContractError(f"{path}.operator_commands: guard must remain separate from execute command")
    if (
        "download_production_dataset.py" not in str(commands["acquisition_command"])
        or "--resume" not in str(commands["acquisition_command"])
        or "--yes" not in str(commands["acquisition_command"])
    ):
        raise ContractError(f"{path}.operator_commands.acquisition_command: must reference resumable production acquisition")
    expected_acquisition_command = (
        "python apps\\tamandua_ml\\scripts\\download_production_dataset.py --output "
        "$env:TAMANDUA_ML_DATA_ROOT\\production --samples-per-class 10000 --skip-vt-validation "
        "--vx-inventory docs\\benchmarks\\runs\\ml-vx-inthewild-inventory.json --resume --yes"
    )
    if commands["acquisition_command"] != expected_acquisition_command:
        raise ContractError(f"{path}.operator_commands.acquisition_command: must match canonical Wave 1 launcher command")
    command_hashes = require_object(commands["command_sha256"], f"{path}.operator_commands.command_sha256")
    for field in [
        "data_root_set_command",
        "guard_set_command",
        "validation_command",
        "execute_command",
        "guard_cleanup_command",
        "acquisition_command",
    ]:
        expected_hash = hashlib.sha256(str(commands[field]).encode("utf-8")).hexdigest()
        if command_hashes.get(field) != expected_hash:
            raise ContractError(f"{path}.operator_commands.command_sha256.{field}: must match command")

    auth_post_sequence = [
        require_object(item, f"{authorization_path}.post_execution_sequence.item")
        for item in require_array(authorization["post_execution_sequence"], f"{authorization_path}.post_execution_sequence")
    ]
    if len(auth_post_sequence) != 3:
        raise ContractError(f"{authorization_path}.post_execution_sequence: expected three post-execution steps")
    post_commands = require_object(data["post_execution_commands"], f"{path}.post_execution_commands")
    post_command_fields = {
        "post_acquisition_refresh_command",
        "manifest_publish_guard_set_command",
        "manifest_publish_command",
        "manifest_publish_guard_cleanup_command",
        "post_manifest_refresh_command",
        "manifest_publish_guard_env",
        "manifest_publish_command_has_execute",
        "refresh_commands_have_execute",
        "manifest_publish_guard_set_separate",
        "manifest_publish_command_inlines_guard",
        "command_sha256",
    }
    require_keys(post_commands, post_command_fields, f"{path}.post_execution_commands")
    post_refresh_step, manifest_publish_step, post_manifest_refresh_step = auth_post_sequence
    expected_post_commands = {
        "post_acquisition_refresh_command": str(post_refresh_step["command"]),
        "manifest_publish_guard_set_command": str(manifest_publish_step["guard_set_command"]),
        "manifest_publish_command": str(manifest_publish_step["command"]),
        "manifest_publish_guard_cleanup_command": str(manifest_publish_step["guard_cleanup_command"]),
        "post_manifest_refresh_command": str(post_manifest_refresh_step["command"]),
        "manifest_publish_guard_env": "TAMANDUA_ALLOW_ML_MANIFEST_PUBLISH",
        "manifest_publish_command_has_execute": True,
        "refresh_commands_have_execute": False,
        "manifest_publish_guard_set_separate": True,
        "manifest_publish_command_inlines_guard": False,
    }
    for field, expected in expected_post_commands.items():
        if post_commands[field] != expected:
            raise ContractError(f"{path}.post_execution_commands.{field}: must match authorization packet post-execution sequence")
    if "-Execute" in str(post_commands["post_acquisition_refresh_command"]) or "-Execute" in str(post_commands["post_manifest_refresh_command"]):
        raise ContractError(f"{path}.post_execution_commands: refresh commands must be validation-only")
    if "-Execute" not in str(post_commands["manifest_publish_command"]):
        raise ContractError(f"{path}.post_execution_commands.manifest_publish_command: must include -Execute")
    if "TAMANDUA_ALLOW_ML_MANIFEST_PUBLISH=1" in str(post_commands["manifest_publish_command"]):
        raise ContractError(f"{path}.post_execution_commands.manifest_publish_command: must not inline manifest publish guard")
    post_command_hashes = require_object(post_commands["command_sha256"], f"{path}.post_execution_commands.command_sha256")
    for field in [
        "post_acquisition_refresh_command",
        "manifest_publish_guard_set_command",
        "manifest_publish_command",
        "manifest_publish_guard_cleanup_command",
        "post_manifest_refresh_command",
    ]:
        expected_hash = hashlib.sha256(str(post_commands[field]).encode("utf-8")).hexdigest()
        if post_command_hashes.get(field) != expected_hash:
            raise ContractError(f"{path}.post_execution_commands.command_sha256.{field}: must match command")

    preflight_data_root = require_object(preflight["data_root"], f"{preflight_path}.data_root")
    if data_root["env"] != "TAMANDUA_ML_DATA_ROOT":
        raise ContractError(f"{path}.data_root.env: must be TAMANDUA_ML_DATA_ROOT")
    if data_root["raw"] != preflight_data_root["raw"] or bool(data_root["outside_repo"]) != bool(preflight_data_root["outside_repo"]):
        raise ContractError(f"{path}.data_root: must match execution environment preflight")
    if data_root["outside_repo"] is not True:
        raise ContractError(f"{path}.data_root.outside_repo: must be true")
    if data_root["production_manifest_present"] is not False or repo_manifest["present"] is not False:
        raise ContractError(f"{path}: real manifests must be absent before guarded acquisition")
    if Path(str(data_root["production_manifest"])).exists():
        raise ContractError(f"{path}.data_root.production_manifest: must not exist before guarded acquisition")
    if Path(str(repo_manifest["path"])).exists():
        raise ContractError(f"{path}.repo_manifest.path: must not exist before guarded acquisition")
    vx_policy = require_object(data["vx_policy"], f"{path}.vx_policy")
    preflight_vx_policy = require_object(preflight["vx_policy"], f"{preflight_path}.vx_policy")
    preflight_summary = require_object(preflight["source_status_summary"], f"{preflight_path}.source_status_summary")
    if vx_policy != preflight_vx_policy:
        raise ContractError(f"{path}.vx_policy: must match execution environment preflight")
    vx_guard_env = str(vx_policy.get("vx_archive_download_guard_env", ""))
    if vx_guard_env != "TAMANDUA_ALLOW_VX_UNDERGROUND_DOWNLOAD":
        raise ContractError(f"{path}.vx_policy.vx_archive_download_guard_env: must identify VX archive guard")
    if vx_policy.get("vx_archive_download_guard_present") is not False:
        raise ContractError(f"{path}.vx_policy.vx_archive_download_guard_present: must be false")
    if vx_policy.get("vx_download_authorized_by_this_packet") is not False:
        raise ContractError(f"{path}.vx_policy.vx_download_authorized_by_this_packet: must be false")
    if vx_policy.get("vx_inventory_metadata_only") is not True:
        raise ContractError(f"{path}.vx_policy.vx_inventory_metadata_only: must be true")
    if vx_policy.get("vx_samples_allowed_in_training_splits") is not False:
        raise ContractError(f"{path}.vx_policy.vx_samples_allowed_in_training_splits: must be false")
    transcript_capture = require_object(data["transcript_capture_contract"], f"{path}.transcript_capture_contract")
    authorization_transcript_capture = require_object(
        authorization["transcript_capture_contract"],
        f"{authorization_path}.transcript_capture_contract",
    )
    checklist_transcript_capture = require_object(
        checklist["transcript_capture_contract"],
        f"{checklist_path}.transcript_capture_contract",
    )
    if transcript_capture != authorization_transcript_capture:
        raise ContractError(f"{path}.transcript_capture_contract: must match authorization packet")
    if transcript_capture != checklist_transcript_capture:
        raise ContractError(f"{path}.transcript_capture_contract: must match pre-execution checklist")
    if transcript_capture["capture_helper_shell"] != "powershell":
        raise ContractError(f"{path}.transcript_capture_contract.capture_helper_shell: must be powershell")
    if transcript_capture["capture_helper_mode"] != "operator_copy_paste":
        raise ContractError(f"{path}.transcript_capture_contract.capture_helper_mode: must be operator_copy_paste")
    if int(transcript_capture["capture_helper_command_count"]) < 16:
        raise ContractError(f"{path}.transcript_capture_contract.capture_helper_command_count: must be at least 16")
    if transcript_capture["capture_helper_requires_guard_env"] != "TAMANDUA_ALLOW_ML_REAL_ACQUISITION":
        raise ContractError(f"{path}.transcript_capture_contract.capture_helper_requires_guard_env: must require real acquisition guard")
    if transcript_capture["capture_helper_requires_vx_download_guard_unset"] != "TAMANDUA_ALLOW_VX_UNDERGROUND_DOWNLOAD":
        raise ContractError(
            f"{path}.transcript_capture_contract.capture_helper_requires_vx_download_guard_unset: must keep VX guard unset"
        )

    hashes = require_object(data["source_artifact_hashes"], f"{path}.source_artifact_hashes")
    expected_hash_paths = {
        "master_handoff": master_path,
        "authorization_packet": authorization_path,
        "pre_execution_checklist": checklist_path,
        "execution_environment_preflight": preflight_path,
        "operator_go_no_go_summary": operator_path,
        "next_action_run": next_action_path,
        "acquisition_readiness": acquisition_readiness_path,
        "execute_guard_probe": execute_guard_path,
        "launcher": launcher_path,
    }
    if set(hashes) != set(expected_hash_paths):
        raise ContractError(f"{path}.source_artifact_hashes: must contain exactly the guarded-run source artifacts")
    for name, expected_path in expected_hash_paths.items():
        item = require_object(hashes.get(name), f"{path}.source_artifact_hashes.{name}")
        require_keys(item, {"path", "sha256"}, f"{path}.source_artifact_hashes.{name}")
        if not str(item["path"]).endswith(expected_sources[name]):
            raise ContractError(f"{path}.source_artifact_hashes.{name}.path: must match source artifact")
        if item["sha256"] != hashlib.sha256(expected_path.read_bytes()).hexdigest():
            raise ContractError(f"{path}.source_artifact_hashes.{name}.sha256: must match current artifact")

    summary = require_object(data["source_status_summary"], f"{path}.source_status_summary")
    require_keys(
        summary,
        {
            "ready_for_guarded_wave1_acquisition",
            "check_count",
            "passed_checks",
            "failed_checks",
            "master_ready",
            "authorized_for_guarded_execution",
            "benchmark_standalone_detection_surface_covered",
            "benchmark_agent_onnx_detection_surface_covered",
            "benchmark_tamandua_detection_surface_covered",
            "benchmark_detection_surface_contract_ready",
            "ready_to_set_real_acquisition_guard",
            "goal_snapshot_anchor_check_passed",
            "preflight_ready",
            "operator_decision",
            "next_action_run_ready",
            "acquisition_readiness_passed",
            "execute_guard_probe_passed",
            "data_root_configured",
            "data_root_outside_repo",
            "malware_bazaar_auth_key_env",
            "malware_bazaar_auth_key_present",
            "production_manifest_present",
            "repo_manifest_present",
            "post_execution_sequence_steps",
            "manifest_publish_guard_env",
            "vx_inventory_metadata_only",
            "vx_archive_download_guard_env",
            "vx_archive_download_guard_must_be_unset",
            "vx_download_authorized_by_command_packet",
            "vx_samples_allowed_in_training_splits",
            "transcript_capture_contract_ready",
            "transcript_capture_helper_command_count",
            "transcript_capture_requires_guard_env",
            "transcript_capture_requires_vx_download_guard_unset",
            "transcript_contract_validation_before_run",
            "transcript_contract_valid_before_run",
            "transcript_contract_missing_before_run",
            "wave1_pre_execution_transcript_contract_validation_before_run",
            "wave1_pre_execution_transcript_contract_valid_before_run",
            "wave1_pre_execution_transcript_contract_missing_before_run",
            "wave1_acceptance_intake_transcript_contract_validation",
            "wave1_acceptance_intake_transcript_contract_valid",
            "wave1_transcript_contract_valid_for_manifest_publish",
            "goal_complete",
            "completion_state",
            "goal_missing_requirements",
            "goal_required_evidence_total",
            "goal_present_required_evidence",
            "goal_usable_required_evidence",
            "goal_missing_required_evidence",
            "goal_unusable_present_required_evidence",
            "next_unproven_requirement_id",
            "next_unproven_requirement_phase",
            "next_unproven_execute_guard_env",
            "evidence_status_summary",
            "next_unproven_requirement",
        },
        f"{path}.source_status_summary",
    )
    operator_summary = require_object(operator["source_status_summary"], f"{operator_path}.source_status_summary")
    launcher_text = launcher_path.read_text(encoding="utf-8")
    expected_vx_metadata_only = (
        "--vx-inventory docs\\benchmarks\\runs\\ml-vx-inthewild-inventory.json" in str(commands["acquisition_command"])
        and "TAMANDUA_ALLOW_VX_UNDERGROUND_DOWNLOAD" in launcher_text
        and "Wave 1 acquisition keeps VX metadata-only" in launcher_text
        and preflight_summary["vx_archive_download_guard_absent"] is True
        and preflight_summary["vx_download_authorized_by_preflight"] is False
        and vx_policy["vx_inventory_metadata_only"] is True
        and vx_policy["vx_samples_allowed_in_training_splits"] is False
    )
    checks = [require_object(item, f"{path}.checks.item") for item in require_array(data["checks"], f"{path}.checks")]
    passed_checks = sum(1 for check in checks if bool(check.get("passed")))
    failed_checks = len(checks) - passed_checks
    expected_ready = failed_checks == 0
    blocker_actions = {
        "authorizations_green": (
            "Regenerate and validate the authorization packet, pre-execution checklist, preflight, and operator "
            "go/no-go summary until all pre-run authorization checks are green."
        ),
        "transcript_contract_missing_before_run": (
            "Keep the real acquisition transcript absent before execution; if a stale transcript exists, move it "
            "out of docs/benchmarks/runs before requesting a guarded run packet."
        ),
        "malware_bazaar_auth_key_present": (
            "Set the selected source credential in the isolated lab secret store, then rerun readiness and "
            "preflight without exposing the secret value."
        ),
    }
    expected_blockers = [
        {
            "check": str(check["name"]),
            "detail": str(check["detail"]),
            "operator_action": blocker_actions.get(
                str(check["name"]),
                "Resolve the failed check, regenerate this command packet, and revalidate contracts.",
            ),
        }
        for check in checks
        if check.get("passed") is not True
    ]
    actual_blockers = [
        require_object(item, f"{path}.execution_blockers.item")
        for item in require_array(data["execution_blockers"], f"{path}.execution_blockers")
    ]
    if actual_blockers != expected_blockers:
        raise ContractError(f"{path}.execution_blockers: must match failed checks")
    expected_actions = [
        {"order": index + 1, "check": blocker["check"], "action": blocker["operator_action"]}
        for index, blocker in enumerate(expected_blockers)
    ]
    actual_actions = [
        require_object(item, f"{path}.next_unblock_actions.item")
        for item in require_array(data["next_unblock_actions"], f"{path}.next_unblock_actions")
    ]
    if actual_actions != expected_actions:
        raise ContractError(f"{path}.next_unblock_actions: must match execution blockers")
    expected_summary = {
        "ready_for_guarded_wave1_acquisition": expected_ready,
        "check_count": len(checks),
        "passed_checks": passed_checks,
        "failed_checks": failed_checks,
        "master_ready": bool(master["ready_for_lab_operator"]),
        "authorized_for_guarded_execution": bool(authorization["authorized_for_guarded_execution"]),
        "benchmark_standalone_detection_surface_covered": bool(
            operator_summary["benchmark_standalone_detection_surface_covered"]
        ),
        "benchmark_agent_onnx_detection_surface_covered": bool(
            operator_summary["benchmark_agent_onnx_detection_surface_covered"]
        ),
        "benchmark_tamandua_detection_surface_covered": bool(operator_summary["benchmark_tamandua_detection_surface_covered"]),
        "benchmark_detection_surface_contract_ready": bool(operator_summary["benchmark_detection_surface_contract_ready"]),
        "ready_to_set_real_acquisition_guard": bool(checklist["ready_to_set_real_acquisition_guard"]),
        "goal_snapshot_anchor_check_passed": bool(operator_summary["goal_snapshot_anchor_check_passed"])
        and bool(preflight_summary["goal_snapshot_anchor_check_passed"]),
        "preflight_ready": bool(preflight["ready"]),
        "operator_decision": str(operator["operator_decision"]["decision"]),
        "next_action_run_ready": bool(next_action_ready),
        "acquisition_readiness_passed": bool(acquisition_readiness["passed"]),
        "execute_guard_probe_passed": bool(execute_guard["passed"]),
        "data_root_configured": bool(preflight_data_root["configured"]),
        "data_root_outside_repo": bool(preflight_data_root["outside_repo"]),
        "malware_bazaar_auth_key_env": str(operator_summary["malware_bazaar_auth_key_env"]),
        "malware_bazaar_auth_key_present": bool(operator_summary["malware_bazaar_auth_key_present"])
        and bool(acquisition_readiness["source_status_summary"]["malware_bazaar_auth_key_present"]),
        "production_manifest_present": False,
        "repo_manifest_present": False,
        "post_execution_sequence_steps": 3,
        "manifest_publish_guard_env": "TAMANDUA_ALLOW_ML_MANIFEST_PUBLISH",
        "vx_inventory_metadata_only": expected_vx_metadata_only,
        "vx_archive_download_guard_env": vx_guard_env,
        "vx_archive_download_guard_must_be_unset": expected_vx_metadata_only,
        "vx_download_authorized_by_command_packet": False,
        "vx_samples_allowed_in_training_splits": False,
        "transcript_capture_contract_ready": True,
        "transcript_capture_helper_command_count": int(transcript_capture["capture_helper_command_count"]),
        "transcript_capture_requires_guard_env": "TAMANDUA_ALLOW_ML_REAL_ACQUISITION",
        "transcript_capture_requires_vx_download_guard_unset": "TAMANDUA_ALLOW_VX_UNDERGROUND_DOWNLOAD",
        "transcript_contract_validation_before_run": str(
            preflight_summary["wave1_pre_execution_transcript_contract_validation_before_run"]
        ),
        "transcript_contract_valid_before_run": bool(
            preflight_summary["wave1_pre_execution_transcript_contract_valid_before_run"]
        ),
        "transcript_contract_missing_before_run": bool(
            preflight_summary["wave1_pre_execution_transcript_contract_missing_before_run"]
        ),
        "wave1_pre_execution_transcript_contract_validation_before_run": str(
            preflight_summary["wave1_pre_execution_transcript_contract_validation_before_run"]
        ),
        "wave1_pre_execution_transcript_contract_valid_before_run": bool(
            preflight_summary["wave1_pre_execution_transcript_contract_valid_before_run"]
        ),
        "wave1_pre_execution_transcript_contract_missing_before_run": bool(
            preflight_summary["wave1_pre_execution_transcript_contract_missing_before_run"]
        ),
        "wave1_acceptance_intake_transcript_contract_validation": "missing",
        "wave1_acceptance_intake_transcript_contract_valid": False,
        "wave1_transcript_contract_valid_for_manifest_publish": bool(
            preflight_summary["wave1_transcript_contract_valid_for_manifest_publish"]
        ),
        "goal_complete": bool(operator_summary["goal_complete"]),
        "completion_state": str(operator_summary["completion_state"]),
        "goal_missing_requirements": int(operator_summary["goal_missing_requirements"]),
        "goal_required_evidence_total": int(operator_summary["goal_required_evidence_total"]),
        "goal_present_required_evidence": int(operator_summary["goal_present_required_evidence"]),
        "goal_usable_required_evidence": int(operator_summary["goal_usable_required_evidence"]),
        "goal_missing_required_evidence": int(operator_summary["goal_missing_required_evidence"]),
        "goal_unusable_present_required_evidence": int(operator_summary["goal_unusable_present_required_evidence"]),
        "next_unproven_requirement_id": str(operator_summary["next_unproven_requirement_id"]),
        "next_unproven_requirement_phase": str(operator_summary["next_unproven_requirement_phase"]),
        "next_unproven_execute_guard_env": str(operator_summary["next_unproven_execute_guard_env"]),
        "evidence_status_summary": operator_summary["evidence_status_summary"],
        "next_unproven_requirement": operator_summary["next_unproven_requirement"],
    }
    for field, expected in expected_summary.items():
        if summary[field] != expected:
            raise ContractError(f"{path}.source_status_summary.{field}: must match current source artifacts")
    if bool(data["ready_for_guarded_wave1_acquisition"]) != expected_ready:
        raise ContractError(f"{path}.ready_for_guarded_wave1_acquisition: must match check results")
    guarded_ready_required_true_fields = [
        "master_ready",
        "authorized_for_guarded_execution",
        "benchmark_standalone_detection_surface_covered",
        "benchmark_agent_onnx_detection_surface_covered",
        "benchmark_tamandua_detection_surface_covered",
        "benchmark_detection_surface_contract_ready",
        "ready_to_set_real_acquisition_guard",
        "goal_snapshot_anchor_check_passed",
        "preflight_ready",
        "next_action_run_ready",
        "acquisition_readiness_passed",
        "execute_guard_probe_passed",
        "data_root_configured",
        "data_root_outside_repo",
    ]
    if expected_ready:
        for field in guarded_ready_required_true_fields:
            if summary[field] is not True:
                raise ContractError(f"{path}.source_status_summary.{field}: must be true before guarded acquisition")
        if summary["malware_bazaar_auth_key_present"] is not True:
            raise ContractError(f"{path}.source_status_summary.malware_bazaar_auth_key_present: must be true before guarded acquisition")
    else:
        check_by_name_for_block = {str(check.get("name")): check for check in checks}
        if not any(check.get("passed") is False for check in checks):
            raise ContractError(f"{path}.checks: blocked command packet must include at least one failed check")
        auth_check = check_by_name_for_block.get("malware_bazaar_auth_key_present")
        if summary["malware_bazaar_auth_key_present"] is False and (
            auth_check is None or auth_check.get("passed") is not False
        ):
            raise ContractError(f"{path}.checks.malware_bazaar_auth_key_present: must explain missing Auth-Key")
    if summary["goal_complete"] is not False or summary["completion_state"] not in {"not_executed", "partial_evidence"}:
        raise ContractError(f"{path}.source_status_summary: must not claim goal completion")
    if int(summary["goal_missing_requirements"]) != 9:
        raise ContractError(f"{path}.source_status_summary.goal_missing_requirements: must remain 9 before real evidence")
    if summary["next_unproven_requirement_id"] != "wave1_governed_acquisition":
        raise ContractError(f"{path}.source_status_summary.next_unproven_requirement_id: must remain Wave 1 before real evidence")
    if not expected_vx_metadata_only:
        raise ContractError(f"{path}.source_status_summary.vx_inventory_metadata_only: launcher must reject VX archive downloads")
    if summary["vx_download_authorized_by_command_packet"] is not False:
        raise ContractError(f"{path}.source_status_summary.vx_download_authorized_by_command_packet: must be false")
    if summary["vx_samples_allowed_in_training_splits"] is not False:
        raise ContractError(f"{path}.source_status_summary.vx_samples_allowed_in_training_splits: must be false")
    if summary["transcript_capture_contract_ready"] is not True:
        raise ContractError(f"{path}.source_status_summary.transcript_capture_contract_ready: must be true")
    if summary["wave1_pre_execution_transcript_contract_validation_before_run"] != "missing":
        raise ContractError(
            f"{path}.source_status_summary.wave1_pre_execution_transcript_contract_validation_before_run: must be missing"
        )
    if summary["wave1_pre_execution_transcript_contract_valid_before_run"] is not False:
        raise ContractError(
            f"{path}.source_status_summary.wave1_pre_execution_transcript_contract_valid_before_run: must be false"
        )
    if summary["wave1_pre_execution_transcript_contract_missing_before_run"] is not True:
        raise ContractError(
            f"{path}.source_status_summary.wave1_pre_execution_transcript_contract_missing_before_run: must be true"
        )
    check_by_name = {str(check.get("name")): check for check in checks}
    transcript_check = check_by_name.get("transcript_capture_contract_ready")
    if transcript_check is None:
        raise ContractError(f"{path}.checks: missing transcript_capture_contract_ready")
    if transcript_check.get("passed") is not True:
        raise ContractError(f"{path}.checks.transcript_capture_contract_ready: must pass")
    transcript_contract_check = check_by_name.get("transcript_contract_missing_before_run")
    if transcript_contract_check is None:
        raise ContractError(f"{path}.checks: missing transcript_contract_missing_before_run")
    goal_snapshot_anchor_check = check_by_name.get("goal_snapshot_anchor_preserved_before_guard")
    if goal_snapshot_anchor_check is None:
        raise ContractError(f"{path}.checks: missing goal_snapshot_anchor_preserved_before_guard")
    if goal_snapshot_anchor_check.get("passed") is not True:
        raise ContractError(f"{path}.checks.goal_snapshot_anchor_preserved_before_guard: must pass")
    if check_by_name.get("wave1_transcript_contract_blocks_manifest_publish_before_real_evidence", {}).get("passed") is not True:
        raise ContractError(
            f"{path}.checks.wave1_transcript_contract_blocks_manifest_publish_before_real_evidence: must pass"
        )


def validate_wave1_post_acquisition_go_no_go_summary(data: dict[str, Any], path: Path) -> None:
    require_keys(
        data,
        {
            "api_version",
            "kind",
            "metadata",
            "source",
            "source_artifact_hashes",
            "operator_decision",
            "source_status_summary",
            "operator_sequence",
            "checks",
        },
        str(path),
    )
    if data["api_version"] != WAVE1_POST_ACQUISITION_GO_NO_GO_SUMMARY_API_VERSION:
        raise ContractError(f"{path}: invalid api_version {data['api_version']!r}")
    if data["kind"] != "MLWave1PostAcquisitionGoNoGoSummary":
        raise ContractError(f"{path}: invalid kind {data['kind']!r}")
    metadata = require_object(data["metadata"], f"{path}.metadata")
    require_keys(metadata, {"report_id", "generated_at", "created_by", "claim_boundary"}, f"{path}.metadata")
    boundary = str(metadata["claim_boundary"])
    if "No-execution" not in boundary or "does not set guards" not in boundary:
        raise ContractError(f"{path}.metadata.claim_boundary: must preserve no-execution post-acquisition boundary")

    vx_policy = require_object(data["vx_policy"], f"{path}.vx_policy")
    vx_expectations = {
        "vx_inventory_ref": "docs\\benchmarks\\runs\\ml-vx-inthewild-inventory.json",
        "vx_inventory_metadata_only": True,
        "vx_samples_in_training_splits": False,
        "vx_archive_download_guard_env": "TAMANDUA_ALLOW_VX_UNDERGROUND_DOWNLOAD",
        "vx_archive_download_guard_must_be_unset": True,
    }
    require_keys(vx_policy, set(vx_expectations) | {"operator_note"}, f"{path}.vx_policy")
    for field, expected in vx_expectations.items():
        actual = vx_policy[field]
        if field == "vx_inventory_ref":
            if str(actual).replace("/", "\\") != expected:
                raise ContractError(f"{path}.vx_policy.{field}: must reference canonical VX inventory")
        elif actual != expected:
            raise ContractError(f"{path}.vx_policy.{field}: invalid expected VX policy")
    vx_note = str(vx_policy["operator_note"]).lower()
    for term in ("metadata", "download", "train"):
        if term not in vx_note:
            raise ContractError(f"{path}.vx_policy.operator_note: must document VX metadata-only boundary")

    source = require_object(data["source"], f"{path}.source")
    require_keys(
        source,
        {
            "guarded_run_command_packet",
            "guarded_run_command_packet_validation",
            "lab_run_intake",
            "lab_run_intake_validation",
            "acquisition_receipt",
            "acquisition_receipt_validation",
            "manifest_publish_receipt",
            "manifest_publish_receipt_validation",
        },
        f"{path}.source",
    )
    expected_sources = {
        "guarded_run_command_packet": "20260604T-ml-wave1-guarded-run-command-packet.json",
        "lab_run_intake": "20260604T-ml-wave1-lab-run-intake.json",
        "acquisition_receipt": "20260604T-ml-wave1-acquisition-receipt.json",
        "manifest_publish_receipt": "20260604T-ml-wave1-manifest-publish-receipt.json",
    }
    for field, suffix in expected_sources.items():
        if not str(source[field]).endswith(suffix):
            raise ContractError(f"{path}.source.{field}: must reference canonical {suffix}")
    for field in [
        "guarded_run_command_packet_validation",
        "lab_run_intake_validation",
        "acquisition_receipt_validation",
        "manifest_publish_receipt_validation",
    ]:
        if source[field] not in {"jsonschema+built-in", "built-in"}:
            raise ContractError(f"{path}.source.{field}: invalid validation mode")

    guarded_packet_path = resolve_report_path(str(source["guarded_run_command_packet"]), path.parent)
    intake_path = resolve_report_path(str(source["lab_run_intake"]), path.parent)
    acquisition_path = resolve_report_path(str(source["acquisition_receipt"]), path.parent)
    manifest_path = resolve_report_path(str(source["manifest_publish_receipt"]), path.parent)
    source_hashes = require_object(data["source_artifact_hashes"], f"{path}.source_artifact_hashes")
    expected_source_hash_paths = {
        "guarded_run_command_packet": guarded_packet_path,
        "lab_run_intake": intake_path,
        "acquisition_receipt": acquisition_path,
        "manifest_publish_receipt": manifest_path,
    }
    if set(source_hashes) != set(expected_source_hash_paths):
        raise ContractError(f"{path}.source_artifact_hashes: must contain exactly the Wave 1 post-acquisition source artifacts")
    for name, source_path in expected_source_hash_paths.items():
        hash_item = require_object(source_hashes.get(name), f"{path}.source_artifact_hashes.{name}")
        require_keys(hash_item, {"path", "sha256"}, f"{path}.source_artifact_hashes.{name}")
        if not str(hash_item["path"]).endswith(expected_sources[name]):
            raise ContractError(f"{path}.source_artifact_hashes.{name}.path: must match source artifact")
        if str(hash_item["sha256"]) != hashlib.sha256(source_path.read_bytes()).hexdigest():
            raise ContractError(f"{path}.source_artifact_hashes.{name}.sha256: must match current artifact")
    guarded_packet = load_json(guarded_packet_path)
    intake = load_json(intake_path)
    acquisition = load_json(acquisition_path)
    manifest = load_json(manifest_path)
    validate_wave1_lab_run_intake(intake, intake_path)
    validate_wave1_acquisition_receipt(acquisition, acquisition_path)
    validate_wave1_manifest_publish_receipt(manifest, manifest_path)

    decision = require_object(data["operator_decision"], f"{path}.operator_decision")
    require_keys(
        decision,
        {
            "ready_for_manifest_publish_go_no_go",
            "decision",
            "validation_command",
            "publish_command",
            "publish_guard_env",
            "production_manifest",
            "canonical_dataset_manifest",
            "authorization_inputs_sha256",
            "no_execution_claim_boundary",
        },
        f"{path}.operator_decision",
    )
    if decision["publish_guard_env"] != "TAMANDUA_ALLOW_ML_MANIFEST_PUBLISH":
        raise ContractError(f"{path}.operator_decision.publish_guard_env: must require manifest publish guard")
    if "-Execute" in str(decision["validation_command"]):
        raise ContractError(f"{path}.operator_decision.validation_command: must be validation-only")
    if not str(decision["validation_command"]).endswith("wave_1_manifest_publish_launcher.ps1'"):
        raise ContractError(f"{path}.operator_decision.validation_command: must reference manifest publish launcher")
    if "-Execute" not in str(decision["publish_command"]):
        raise ContractError(f"{path}.operator_decision.publish_command: must include -Execute")
    if "not publication evidence" not in str(decision["no_execution_claim_boundary"]):
        raise ContractError(f"{path}.operator_decision.no_execution_claim_boundary: must preserve no-execution boundary")

    intake_summary = require_object(require_object(intake["source"], f"{intake_path}.source")["source_status_summary"], f"{intake_path}.source.source_status_summary")
    guarded_packet_summary = require_object(guarded_packet["source_status_summary"], f"{guarded_packet_path}.source_status_summary")
    acquisition_summary = require_object(acquisition["source_status_summary"], f"{acquisition_path}.source_status_summary")
    manifest_summary = require_object(manifest["source_status_summary"], f"{manifest_path}.source_status_summary")
    acquisition_config = require_object(acquisition["configuration"], f"{acquisition_path}.configuration")
    manifest_config = require_object(manifest["configuration"], f"{manifest_path}.configuration")
    if decision["publish_command"] != manifest_config["publish_command"]:
        raise ContractError(f"{path}.operator_decision.publish_command: must match manifest publish receipt")
    if decision["validation_command"] != str(manifest_config["publish_command"]).replace(" -Execute", ""):
        raise ContractError(f"{path}.operator_decision.validation_command: must match manifest publish receipt")
    if decision["publish_guard_env"] != manifest_config["publish_guard_env"]:
        raise ContractError(f"{path}.operator_decision.publish_guard_env: must match manifest publish receipt")
    def same_report_path(left: Any, right: Any) -> bool:
        def normalize(value: Any) -> Path:
            candidate = Path(str(value))
            return candidate.resolve() if candidate.is_absolute() else (ROOT / candidate).resolve()

        return normalize(left) == normalize(right)

    if not same_report_path(decision["production_manifest"], acquisition_config["production_manifest"]):
        raise ContractError(f"{path}.operator_decision.production_manifest: must match acquisition receipt")
    if not same_report_path(decision["canonical_dataset_manifest"], acquisition_config["canonical_dataset_manifest"]):
        raise ContractError(f"{path}.operator_decision.canonical_dataset_manifest: must match acquisition receipt")
    if not same_report_path(acquisition_config["production_manifest"], manifest_config["production_manifest"]):
        raise ContractError(f"{path}: production manifest path must match between receipts")
    if not same_report_path(acquisition_config["canonical_dataset_manifest"], manifest_config["canonical_dataset_manifest"]):
        raise ContractError(f"{path}: canonical manifest path must match between receipts")
    authorization_inputs = {
        "lab_run_intake": str(source["lab_run_intake"]),
        "acquisition_receipt": str(source["acquisition_receipt"]),
        "manifest_publish_receipt": str(source["manifest_publish_receipt"]),
        "validation_command": str(decision["validation_command"]),
        "publish_command": str(decision["publish_command"]),
        "publish_guard_env": str(decision["publish_guard_env"]),
        "data_root": str(Path(str(decision["production_manifest"])).parent.parent),
        "production_manifest": str(decision["production_manifest"]),
        "canonical_dataset_manifest": str(decision["canonical_dataset_manifest"]),
    }
    expected_authorization_inputs_sha256 = hashlib.sha256(
        json.dumps(authorization_inputs, separators=(",", ":"), sort_keys=True, ensure_ascii=True).encode("utf-8")
    ).hexdigest()
    if str(decision["authorization_inputs_sha256"]) != expected_authorization_inputs_sha256:
        raise ContractError(f"{path}.operator_decision.authorization_inputs_sha256: must match authorization inputs")

    summary = require_object(data["source_status_summary"], f"{path}.source_status_summary")
    require_keys(
        summary,
        {
            "ready_for_manifest_publish_go_no_go",
            "check_count",
            "passed_checks",
            "failed_checks",
            "ready_for_post_acquisition_refresh",
            "transcript_present",
            "transcript_valid",
            "pre_execution_transcript_contract_validation_before_run",
            "pre_execution_transcript_contract_valid_before_run",
            "pre_execution_transcript_contract_missing_before_run",
            "intake_transcript_contract_validation",
            "intake_transcript_contract_valid",
            "transcript_contract_valid_for_manifest_publish",
            "wave1_pre_execution_transcript_contract_validation_before_run",
            "wave1_pre_execution_transcript_contract_valid_before_run",
            "wave1_pre_execution_transcript_contract_missing_before_run",
            "wave1_acceptance_intake_transcript_contract_validation",
            "wave1_acceptance_intake_transcript_contract_valid",
            "wave1_transcript_contract_valid_for_manifest_publish",
            "execute_succeeded",
            "production_manifest_present",
            "ready_for_manifest_publish",
            "acquisition_transcript_guarded_run_command_packet_sha256",
            "acquisition_transcript_stdout_sha256",
            "acquisition_transcript_stderr_sha256",
            "manifest_transcript_guarded_run_command_packet_sha256",
            "manifest_transcript_stdout_sha256",
            "manifest_transcript_stderr_sha256",
            "transcript_hashes_match_between_receipts",
            "vx_policy_ready_for_manifest_publish",
            "acquisition_receipt_vx_policy_valid",
            "manifest_receipt_vx_policy_valid",
            "acquisition_receipt_expected_vx_policy_valid",
            "manifest_receipt_expected_vx_policy_valid",
            "expected_vx_inventory_ref",
            "expected_vx_inventory_metadata_only",
            "expected_vx_samples_in_training_splits",
            "expected_vx_archive_download_guard_env",
            "expected_vx_archive_download_guard_must_be_unset",
            "vx_samples_in_training_splits",
            "production_manifest_exists",
            "production_manifest_shape_valid",
            "canonical_dataset_manifest_absent_before_publish",
            "manifest_publish_complete",
            "validation_command_no_execute",
            "publish_command_has_execute",
            "publish_guard_env",
            "operator_sequence_steps",
            "blocker_count",
            "blockers",
            "goal_complete",
            "completion_state",
            "goal_missing_requirements",
            "goal_required_evidence_total",
            "goal_present_required_evidence",
            "goal_usable_required_evidence",
            "goal_missing_required_evidence",
            "goal_unusable_present_required_evidence",
            "next_unproven_requirement_id",
            "next_unproven_requirement_phase",
            "next_unproven_execute_guard_env",
            "evidence_status_summary",
            "next_unproven_requirement",
        },
        f"{path}.source_status_summary",
    )
    sequence = [require_object(item, f"{path}.operator_sequence.item") for item in require_array(data["operator_sequence"], f"{path}.operator_sequence")]
    if len(sequence) != 2:
        raise ContractError(f"{path}.operator_sequence: must contain validation and guarded execute steps")
    if int(summary["operator_sequence_steps"]) != len(sequence):
        raise ContractError(f"{path}.source_status_summary.operator_sequence_steps: must match operator sequence")
    validation_step = sequence[0]
    execute_step = sequence[1]
    require_keys(validation_step, {"step", "mode", "command", "required_env", "claim_boundary"}, f"{path}.operator_sequence[0]")
    require_keys(
        execute_step,
        {
            "step",
            "mode",
            "data_root_set_command",
            "guard_set_command",
            "command",
            "required_env",
            "guard_cleanup_command",
            "claim_boundary",
        },
        f"{path}.operator_sequence[1]",
    )
    if int(validation_step["step"]) != 1 or validation_step["mode"] != "validation_only":
        raise ContractError(f"{path}.operator_sequence[0]: first step must be validation_only")
    if str(validation_step["command"]) != str(decision["validation_command"]):
        raise ContractError(f"{path}.operator_sequence[0].command: must match validation command")
    if "-Execute" in str(validation_step["command"]):
        raise ContractError(f"{path}.operator_sequence[0].command: validation step must not execute")
    if require_object(validation_step["required_env"], f"{path}.operator_sequence[0].required_env"):
        raise ContractError(f"{path}.operator_sequence[0].required_env: validation step must not require guards")
    if int(execute_step["step"]) != 2 or execute_step["mode"] != "guarded_execute":
        raise ContractError(f"{path}.operator_sequence[1]: second step must be guarded_execute")
    if str(execute_step["command"]) != str(decision["publish_command"]):
        raise ContractError(f"{path}.operator_sequence[1].command: must match publish command")
    expected_data_root = str(Path(str(decision["production_manifest"])).parent.parent)
    if str(execute_step["data_root_set_command"]) != f"$env:TAMANDUA_ML_DATA_ROOT = '{expected_data_root}'":
        raise ContractError(f"{path}.operator_sequence[1].data_root_set_command: must set manifest data root")
    if str(execute_step["guard_set_command"]) != "$env:TAMANDUA_ALLOW_ML_MANIFEST_PUBLISH = '1'":
        raise ContractError(f"{path}.operator_sequence[1].guard_set_command: must set manifest publish guard separately")
    execute_required_env = require_object(execute_step["required_env"], f"{path}.operator_sequence[1].required_env")
    if execute_required_env.get("TAMANDUA_ML_DATA_ROOT") != expected_data_root:
        raise ContractError(f"{path}.operator_sequence[1].required_env: must require manifest data root")
    if execute_required_env.get("TAMANDUA_ALLOW_ML_MANIFEST_PUBLISH") != "1":
        raise ContractError(f"{path}.operator_sequence[1].required_env: must require manifest publish guard")
    if str(execute_step["guard_cleanup_command"]) != "Remove-Item Env:TAMANDUA_ALLOW_ML_MANIFEST_PUBLISH -ErrorAction SilentlyContinue":
        raise ContractError(f"{path}.operator_sequence[1].guard_cleanup_command: must remove manifest publish guard")
    checks = [require_object(item, f"{path}.checks.item") for item in require_array(data["checks"], f"{path}.checks")]
    check_by_name = {str(check.get("name")): check for check in checks}
    if "vx_policy_ready_for_manifest_publish" not in check_by_name:
        raise ContractError(f"{path}.checks: missing vx_policy_ready_for_manifest_publish")
    if "expected_vx_policy_metadata_only_boundary" not in check_by_name:
        raise ContractError(f"{path}.checks: missing expected_vx_policy_metadata_only_boundary")
    if "transcript_contract_valid_for_manifest_publish" not in check_by_name:
        raise ContractError(f"{path}.checks: missing transcript_contract_valid_for_manifest_publish")
    if "transcript_hashes_match_between_receipts" not in check_by_name:
        raise ContractError(f"{path}.checks: missing transcript_hashes_match_between_receipts")
    passed_checks = sum(1 for check in checks if bool(check.get("passed")))
    failed_checks = len(checks) - passed_checks
    expected_ready = failed_checks == 0
    if int(summary["check_count"]) != len(checks):
        raise ContractError(f"{path}.source_status_summary.check_count: must match checks")
    if int(summary["passed_checks"]) != passed_checks:
        raise ContractError(f"{path}.source_status_summary.passed_checks: must match checks")
    if int(summary["failed_checks"]) != failed_checks:
        raise ContractError(f"{path}.source_status_summary.failed_checks: must match checks")
    if bool(decision["ready_for_manifest_publish_go_no_go"]) != expected_ready or bool(summary["ready_for_manifest_publish_go_no_go"]) != expected_ready:
        raise ContractError(f"{path}.operator_decision.ready_for_manifest_publish_go_no_go: must match check results")
    if (decision["decision"] == "go_for_guarded_manifest_publish") != expected_ready:
        raise ContractError(f"{path}.operator_decision.decision: must match readiness")

    expected_blockers = sorted(set(str(item) for item in acquisition.get("blockers", []) + manifest.get("blockers", [])))
    expected_summary = {
        "ready_for_post_acquisition_refresh": bool(intake["ready_for_post_acquisition_refresh"]),
        "transcript_present": bool(intake_summary["transcript_present"]),
        "transcript_valid": bool(intake_summary["transcript_valid"]),
        "pre_execution_transcript_contract_validation_before_run": str(
            guarded_packet_summary["transcript_contract_validation_before_run"]
        ),
        "pre_execution_transcript_contract_valid_before_run": bool(
            guarded_packet_summary["transcript_contract_valid_before_run"]
        ),
        "pre_execution_transcript_contract_missing_before_run": bool(
            guarded_packet_summary["transcript_contract_missing_before_run"]
        ),
        "intake_transcript_contract_validation": str(intake_summary["transcript_contract_validation"]),
        "intake_transcript_contract_valid": bool(intake_summary["transcript_contract_valid"]),
        "transcript_contract_valid_for_manifest_publish": (
            guarded_packet_summary["transcript_contract_missing_before_run"] is True
            and guarded_packet_summary["transcript_contract_validation_before_run"] == "missing"
            and guarded_packet_summary["transcript_contract_valid_before_run"] is False
            and intake_summary["transcript_contract_valid"] is True
            and intake_summary["transcript_contract_validation"] in {"jsonschema+built-in", "built-in"}
        ),
        "wave1_pre_execution_transcript_contract_validation_before_run": str(
            guarded_packet_summary.get(
                "wave1_pre_execution_transcript_contract_validation_before_run",
                guarded_packet_summary["transcript_contract_validation_before_run"],
            )
        ),
        "wave1_pre_execution_transcript_contract_valid_before_run": bool(
            guarded_packet_summary.get(
                "wave1_pre_execution_transcript_contract_valid_before_run",
                guarded_packet_summary["transcript_contract_valid_before_run"],
            )
        ),
        "wave1_pre_execution_transcript_contract_missing_before_run": bool(
            guarded_packet_summary.get(
                "wave1_pre_execution_transcript_contract_missing_before_run",
                guarded_packet_summary["transcript_contract_missing_before_run"],
            )
        ),
        "wave1_acceptance_intake_transcript_contract_validation": str(intake_summary["transcript_contract_validation"]),
        "wave1_acceptance_intake_transcript_contract_valid": bool(intake_summary["transcript_contract_valid"]),
        "wave1_transcript_contract_valid_for_manifest_publish": (
            guarded_packet_summary["transcript_contract_missing_before_run"] is True
            and guarded_packet_summary["transcript_contract_validation_before_run"] == "missing"
            and guarded_packet_summary["transcript_contract_valid_before_run"] is False
            and intake_summary["transcript_contract_valid"] is True
            and intake_summary["transcript_contract_validation"] in {"jsonschema+built-in", "built-in"}
        ),
        "execute_succeeded": bool(intake_summary["execute_succeeded"]),
        "production_manifest_present": bool(intake_summary["production_manifest_present"]),
        "ready_for_manifest_publish": bool(acquisition["ready_for_manifest_publish"]),
        "acquisition_transcript_guarded_run_command_packet_sha256": str(
            acquisition_summary.get("acquisition_transcript_guarded_run_command_packet_sha256", "")
        ),
        "acquisition_transcript_stdout_sha256": str(acquisition_summary.get("acquisition_transcript_stdout_sha256", "")),
        "acquisition_transcript_stderr_sha256": str(acquisition_summary.get("acquisition_transcript_stderr_sha256", "")),
        "manifest_transcript_guarded_run_command_packet_sha256": str(
            manifest_summary.get("acquisition_transcript_guarded_run_command_packet_sha256", "")
        ),
        "manifest_transcript_stdout_sha256": str(manifest_summary.get("acquisition_transcript_stdout_sha256", "")),
        "manifest_transcript_stderr_sha256": str(manifest_summary.get("acquisition_transcript_stderr_sha256", "")),
        "transcript_hashes_match_between_receipts": all(
            str(acquisition_summary.get(field, "")) == str(manifest_summary.get(field, ""))
            for field in [
                "acquisition_transcript_guarded_run_command_packet_sha256",
                "acquisition_transcript_stdout_sha256",
                "acquisition_transcript_stderr_sha256",
            ]
        ),
        "vx_policy_ready_for_manifest_publish": (
            acquisition_summary.get("acquisition_transcript_vx_policy_valid") is True
            and acquisition_summary.get("acquisition_transcript_vx_samples_in_training_splits") is False
            and manifest_summary.get("acquisition_transcript_vx_policy_valid") is True
            and manifest_summary.get("acquisition_transcript_vx_samples_in_training_splits") is False
        ),
        "acquisition_receipt_vx_policy_valid": bool(acquisition_summary.get("acquisition_transcript_vx_policy_valid")),
        "manifest_receipt_vx_policy_valid": bool(manifest_summary.get("acquisition_transcript_vx_policy_valid")),
        "acquisition_receipt_expected_vx_policy_valid": acquisition.get("vx_policy") == dict(vx_policy),
        "manifest_receipt_expected_vx_policy_valid": manifest.get("vx_policy") == dict(vx_policy),
        "expected_vx_inventory_ref": str(vx_policy["vx_inventory_ref"]),
        "expected_vx_inventory_metadata_only": vx_policy["vx_inventory_metadata_only"],
        "expected_vx_samples_in_training_splits": vx_policy["vx_samples_in_training_splits"],
        "expected_vx_archive_download_guard_env": str(vx_policy["vx_archive_download_guard_env"]),
        "expected_vx_archive_download_guard_must_be_unset": vx_policy["vx_archive_download_guard_must_be_unset"],
        "vx_samples_in_training_splits": manifest_summary.get("acquisition_transcript_vx_samples_in_training_splits"),
        "production_manifest_exists": bool(acquisition_summary["production_manifest_exists"]),
        "production_manifest_shape_valid": bool(acquisition_summary["production_manifest_shape_valid"]),
        "canonical_dataset_manifest_absent_before_publish": bool(acquisition_summary["canonical_dataset_manifest_absent_before_publish"]),
        "manifest_publish_complete": bool(manifest["manifest_publish_complete"]),
        "validation_command_no_execute": "-Execute" not in str(decision["validation_command"]),
        "publish_command_has_execute": "-Execute" in str(decision["publish_command"]),
        "publish_guard_env": str(manifest_config["publish_guard_env"]),
        "operator_sequence_steps": len(sequence),
        "blocker_count": len(expected_blockers),
        "blockers": expected_blockers,
        "goal_complete": bool(guarded_packet_summary["goal_complete"]),
        "completion_state": str(guarded_packet_summary["completion_state"]),
        "goal_missing_requirements": int(guarded_packet_summary["goal_missing_requirements"]),
        "goal_required_evidence_total": int(guarded_packet_summary["goal_required_evidence_total"]),
        "goal_present_required_evidence": int(guarded_packet_summary["goal_present_required_evidence"]),
        "goal_usable_required_evidence": int(guarded_packet_summary["goal_usable_required_evidence"]),
        "goal_missing_required_evidence": int(guarded_packet_summary["goal_missing_required_evidence"]),
        "goal_unusable_present_required_evidence": int(guarded_packet_summary["goal_unusable_present_required_evidence"]),
        "next_unproven_requirement_id": str(guarded_packet_summary["next_unproven_requirement_id"]),
        "next_unproven_requirement_phase": str(guarded_packet_summary["next_unproven_requirement_phase"]),
        "next_unproven_execute_guard_env": str(guarded_packet_summary["next_unproven_execute_guard_env"]),
        "evidence_status_summary": guarded_packet_summary["evidence_status_summary"],
        "next_unproven_requirement": guarded_packet_summary["next_unproven_requirement"],
    }
    for field, expected in expected_summary.items():
        if summary[field] != expected:
            raise ContractError(f"{path}.source_status_summary.{field}: must match current source artifacts")
    if bool(summary["vx_policy_ready_for_manifest_publish"]) != (check_by_name["vx_policy_ready_for_manifest_publish"].get("passed") is True):
        raise ContractError(f"{path}.source_status_summary.vx_policy_ready_for_manifest_publish: must match VX policy check")
    if bool(summary["transcript_contract_valid_for_manifest_publish"]) != (
        check_by_name["transcript_contract_valid_for_manifest_publish"].get("passed") is True
    ):
        raise ContractError(
            f"{path}.source_status_summary.transcript_contract_valid_for_manifest_publish: must match transcript contract check"
        )
    if bool(summary["transcript_hashes_match_between_receipts"]) != (
        check_by_name["transcript_hashes_match_between_receipts"].get("passed") is True
    ):
        raise ContractError(
            f"{path}.source_status_summary.transcript_hashes_match_between_receipts: must match transcript hash check"
        )
    if bool(summary["ready_for_manifest_publish_go_no_go"]) and summary["transcript_hashes_match_between_receipts"] is not True:
        raise ContractError(f"{path}.source_status_summary.transcript_hashes_match_between_receipts: required for go")
    if summary["pre_execution_transcript_contract_validation_before_run"] not in {"missing", "failed"}:
        raise ContractError(
            f"{path}.source_status_summary.pre_execution_transcript_contract_validation_before_run: must be missing or failed"
        )
    if summary["pre_execution_transcript_contract_valid_before_run"] is not False:
        raise ContractError(
            f"{path}.source_status_summary.pre_execution_transcript_contract_valid_before_run: must be false"
        )
    if summary["pre_execution_transcript_contract_missing_before_run"] is not (
        summary["pre_execution_transcript_contract_validation_before_run"] == "missing"
    ):
        raise ContractError(
            f"{path}.source_status_summary.pre_execution_transcript_contract_missing_before_run: must match validation state"
        )
    transcript_aliases = {
        "wave1_acceptance_intake_transcript_contract_validation": "intake_transcript_contract_validation",
        "wave1_acceptance_intake_transcript_contract_valid": "intake_transcript_contract_valid",
        "wave1_transcript_contract_valid_for_manifest_publish": "transcript_contract_valid_for_manifest_publish",
    }
    for alias, legacy in transcript_aliases.items():
        if summary[alias] != summary[legacy]:
            raise ContractError(f"{path}.source_status_summary.{alias}: must match {legacy}")
    if summary["wave1_pre_execution_transcript_contract_validation_before_run"] != "missing":
        raise ContractError(
            f"{path}.source_status_summary.wave1_pre_execution_transcript_contract_validation_before_run: must be missing"
        )
    if summary["wave1_pre_execution_transcript_contract_valid_before_run"] is not False:
        raise ContractError(
            f"{path}.source_status_summary.wave1_pre_execution_transcript_contract_valid_before_run: must be false"
        )
    if summary["wave1_pre_execution_transcript_contract_missing_before_run"] is not True:
        raise ContractError(
            f"{path}.source_status_summary.wave1_pre_execution_transcript_contract_missing_before_run: must be true"
        )
    expected_vx_check_passed = (
        summary["acquisition_receipt_expected_vx_policy_valid"] is True
        and summary["manifest_receipt_expected_vx_policy_valid"] is True
    )
    if bool(check_by_name["expected_vx_policy_metadata_only_boundary"].get("passed")) != expected_vx_check_passed:
        raise ContractError(f"{path}.checks.expected_vx_policy_metadata_only_boundary: must match expected VX policy receipts")
    if "TAMANDUA_ALLOW_VX_UNDERGROUND_DOWNLOAD" not in str(check_by_name["expected_vx_policy_metadata_only_boundary"].get("detail", "")):
        raise ContractError(f"{path}.checks.expected_vx_policy_metadata_only_boundary: must document VX archive guard")
    for summary_field, policy_field in {
        "expected_vx_inventory_ref": "vx_inventory_ref",
        "expected_vx_inventory_metadata_only": "vx_inventory_metadata_only",
        "expected_vx_samples_in_training_splits": "vx_samples_in_training_splits",
        "expected_vx_archive_download_guard_env": "vx_archive_download_guard_env",
        "expected_vx_archive_download_guard_must_be_unset": "vx_archive_download_guard_must_be_unset",
    }.items():
        if summary_field == "expected_vx_inventory_ref":
            if str(summary[summary_field]).replace("/", "\\") != str(vx_policy[policy_field]).replace("/", "\\"):
                raise ContractError(f"{path}.source_status_summary.{summary_field}: must match vx_policy")
        elif summary[summary_field] != vx_policy[policy_field]:
            raise ContractError(f"{path}.source_status_summary.{summary_field}: must match vx_policy")
    if summary["vx_policy_ready_for_manifest_publish"] is True and summary["vx_samples_in_training_splits"] is not False:
        raise ContractError(f"{path}.source_status_summary.vx_samples_in_training_splits: must be false when VX policy is ready")
    manifest_not_already_published = bool(summary["manifest_publish_complete"]) is False
    if not manifest_not_already_published and bool(summary["ready_for_manifest_publish_go_no_go"]) is True:
        raise ContractError(f"{path}.source_status_summary.manifest_not_already_published: must not request publish after manifest is already complete")
    if summary["goal_complete"] is not False or summary["completion_state"] not in {"not_executed", "partial_evidence"}:
        raise ContractError(f"{path}.source_status_summary: must not claim goal completion")
    if int(summary["goal_missing_requirements"]) != 9:
        raise ContractError(f"{path}.source_status_summary.goal_missing_requirements: must remain 9 before real evidence")


def validate_contract(instance_path: Path, schema_path: Path, fallback_validator: Any) -> str:
    data = load_json(instance_path)
    used_jsonschema = run_jsonschema(data, schema_path, instance_path)
    fallback_validator(data, instance_path)
    return "jsonschema+built-in" if used_jsonschema else "built-in"


def validate_ml_next_operator_packet(data: dict[str, Any], path: Path) -> None:
    require_keys(
        data,
        {
            "api_version",
            "kind",
            "metadata",
            "source_authorization_packet",
            "operator_decision",
            "source_auth",
            "pre_run_transcript_state",
            "commands",
            "safety_invariants",
            "expected_evidence",
            "downstream_benchmark_surfaces",
            "checks",
            "source_status_summary",
        },
        str(path),
    )
    if data["api_version"] != ML_NEXT_OPERATOR_PACKET_API_VERSION:
        raise ContractError(f"{path}: invalid api_version {data['api_version']!r}")
    if data["kind"] != "MLNextOperatorPacket":
        raise ContractError(f"{path}: invalid kind {data['kind']!r}")
    metadata = require_object(data["metadata"], f"{path}.metadata")
    require_keys(metadata, {"report_id", "generated_at", "created_by", "claim_boundary"}, f"{path}.metadata")
    boundary = str(metadata["claim_boundary"])
    if "No-execution" not in boundary or "does not set guards" not in boundary or "push mirrors" not in boundary:
        raise ContractError(f"{path}.metadata.claim_boundary: must describe no-execution/no-push boundary")

    authorization_path = Path(str(data["source_authorization_packet"]))
    if not authorization_path.is_absolute():
        authorization_path = ROOT / authorization_path
    validate_contract(authorization_path, ML_NEXT_GATE_AUTHORIZATION_PACKET_SCHEMA, validate_ml_next_gate_authorization_packet)
    authorization_packet = load_json(authorization_path)
    authorization = require_object(authorization_packet["authorization"], f"{authorization_path}.authorization")
    authorization_summary = require_object(authorization_packet["source_status_summary"], f"{authorization_path}.source_status_summary")

    decision = require_object(data["operator_decision"], f"{path}.operator_decision")
    require_keys(
        decision,
        {
            "package_id",
            "ready_for_guarded_execution",
            "authorized_for_guarded_execution",
            "publication_decision",
            "publication_reason",
            "blockers",
            "failed_authorization_checks",
        },
        f"{path}.operator_decision",
    )
    blockers = [str(item) for item in require_array(decision["blockers"], f"{path}.operator_decision.blockers")]
    failed_authorization_checks = [
        str(item)
        for item in require_array(decision["failed_authorization_checks"], f"{path}.operator_decision.failed_authorization_checks")
    ]
    if decision["package_id"] != authorization["package_id"]:
        raise ContractError(f"{path}.operator_decision.package_id: must match authorization packet")
    if decision["authorized_for_guarded_execution"] != authorization_packet["authorized_for_guarded_execution"]:
        raise ContractError(f"{path}.operator_decision.authorized_for_guarded_execution: must match authorization packet")
    env_remediation_selected = authorization.get("action_type") in {"set_required_env", "fix_required_env"}
    expected_blockers = [str(item) for item in authorization_summary.get("virusshare_fallback_blockers", [])]
    if env_remediation_selected:
        expected_blockers.extend(["missing_env:TAMANDUA_ML_DATA_ROOT", "missing_env:VIRUSSHARE_API_KEY"])
    if blockers != expected_blockers:
        raise ContractError(f"{path}.operator_decision.blockers: must match VirusShare fallback blockers")
    ready = (
        not env_remediation_selected
        and
        authorization_packet["authorized_for_guarded_execution"] is True
        and authorization_summary.get("virusshare_fallback_readiness_ready") is True
        and not blockers
        and not failed_authorization_checks
    )
    if bool(decision["ready_for_guarded_execution"]) != ready:
        raise ContractError(f"{path}.operator_decision.ready_for_guarded_execution: must match source readiness")
    expected_publication_decision = "eligible_after_operator_approval" if ready else "hold_do_not_push"
    if decision["publication_decision"] != expected_publication_decision:
        raise ContractError(f"{path}.operator_decision.publication_decision: must match guarded readiness")
    if decision["publication_decision"] == "hold_do_not_push" and "blocked" not in str(decision["publication_reason"]).lower():
        raise ContractError(f"{path}.operator_decision.publication_reason: hold decision must explain blocker")

    source_auth = require_object(data["source_auth"], f"{path}.source_auth")
    require_keys(
        source_auth,
        {"selected_route", "env", "required_for_selected_route", "present", "value_redacted", "operator_note"},
        f"{path}.source_auth",
    )
    expected_selected_route = str(authorization_summary.get("source_decision_selected_route", "virusshare_fallback"))
    expected_source_auth_present = "virusshare_api_key_present" not in blockers
    if source_auth["selected_route"] != expected_selected_route:
        raise ContractError(f"{path}.source_auth.selected_route: must match authorization source decision")
    if source_auth["env"] != "VIRUSSHARE_API_KEY":
        raise ContractError(f"{path}.source_auth.env: must be VIRUSSHARE_API_KEY")
    if source_auth["required_for_selected_route"] is not (expected_selected_route == "virusshare_fallback"):
        raise ContractError(f"{path}.source_auth.required_for_selected_route: must match selected route")
    if source_auth["present"] is not expected_source_auth_present:
        raise ContractError(f"{path}.source_auth.present: must match VirusShare blockers")
    if source_auth["value_redacted"] != ("present" if expected_source_auth_present else "absent"):
        raise ContractError(f"{path}.source_auth.value_redacted: must expose only redacted presence")
    if "secret store" not in str(source_auth["operator_note"]):
        raise ContractError(f"{path}.source_auth.operator_note: must direct operator to isolated secret store")

    transcript_state = require_object(data["pre_run_transcript_state"], f"{path}.pre_run_transcript_state")
    require_keys(
        transcript_state,
        {
            "pre_execution_contract_validation",
            "pre_execution_contract_valid",
            "pre_execution_contract_missing",
            "acceptance_intake_contract_validation",
            "acceptance_intake_contract_valid",
            "valid_for_manifest_publish",
            "operator_note",
        },
        f"{path}.pre_run_transcript_state",
    )
    transcript_expectations = {
        "pre_execution_contract_validation": str(
            authorization_summary.get("wave1_pre_execution_transcript_contract_validation_before_run", "missing")
        ),
        "pre_execution_contract_valid": bool(
            authorization_summary.get("wave1_pre_execution_transcript_contract_valid_before_run", False)
        ),
        "pre_execution_contract_missing": bool(
            authorization_summary.get("wave1_pre_execution_transcript_contract_missing_before_run", True)
        ),
        "acceptance_intake_contract_validation": str(
            authorization_summary.get("wave1_acceptance_intake_transcript_contract_validation", "missing")
        ),
        "acceptance_intake_contract_valid": bool(
            authorization_summary.get("wave1_acceptance_intake_transcript_contract_valid", False)
        ),
        "valid_for_manifest_publish": False,
    }
    for field, expected in transcript_expectations.items():
        if transcript_state[field] != expected:
            raise ContractError(f"{path}.pre_run_transcript_state.{field}: must match authorization transcript state")
    if "fresh guarded acquisition transcript" not in str(transcript_state["operator_note"]):
        raise ContractError(f"{path}.pre_run_transcript_state.operator_note: must require fresh guarded transcript")

    commands = require_object(data["commands"], f"{path}.commands")
    uses_virusshare_fallback = False
    if env_remediation_selected:
        if set(commands) != {"env_remediation"}:
            raise ContractError(f"{path}.commands: env remediation packet must not expose guarded commands")
        remediation = require_object(commands["env_remediation"], f"{path}.commands.env_remediation")
        required_env = require_object(remediation["required_env"], f"{path}.commands.env_remediation.required_env")
        if required_env.get("TAMANDUA_ML_DATA_ROOT") != "<external isolated lab data root>":
            raise ContractError(f"{path}.commands.env_remediation.required_env.TAMANDUA_ML_DATA_ROOT: must be placeholder")
        if required_env.get("VIRUSSHARE_API_KEY") != "<redacted: isolated lab secret store>":
            raise ContractError(f"{path}.commands.env_remediation.required_env.VIRUSSHARE_API_KEY: must be redacted")
        if "ml_execution_status.py" not in str(remediation["rerun_status_command"]):
            raise ContractError(f"{path}.commands.env_remediation.rerun_status_command: must rerun execution status")
        if "ml_virusshare_fallback_readiness_probe.py" not in str(remediation["rerun_readiness_command"]):
            raise ContractError(f"{path}.commands.env_remediation.rerun_readiness_command: must rerun readiness")
        if "ml_next_gate_authorization_packet.py" not in str(remediation["rerun_authorization_command"]):
            raise ContractError(f"{path}.commands.env_remediation.rerun_authorization_command: must rerun authorization")
        serialized = json.dumps(data, sort_keys=True, ensure_ascii=True)
        if "-Execute" in serialized or "TAMANDUA_ALLOW_ML_REAL_ACQUISITION = '1'" in serialized:
            raise ContractError(f"{path}.commands.env_remediation: must not expose guarded execution")
    else:
        validation = require_object(commands["validation"], f"{path}.commands.validation")
        guarded_execute = require_object(commands["guarded_execute"], f"{path}.commands.guarded_execute")
        post_acquisition = require_object(commands["post_acquisition"], f"{path}.commands.post_acquisition")
        if str(validation["command"]) != str(authorization["validation_command"]):
            raise ContractError(f"{path}.commands.validation.command: must match authorization validation command")
        if "-Execute" in str(validation["command"]):
            raise ContractError(f"{path}.commands.validation.command: must be validation-only")
        if require_object(validation["required_env"], f"{path}.commands.validation.required_env"):
            raise ContractError(f"{path}.commands.validation.required_env: validation must not require env")
        if str(guarded_execute["command"]) != str(authorization["execute_command"]):
            raise ContractError(f"{path}.commands.guarded_execute.command: must match authorization execute command")
        if "-Execute" not in str(guarded_execute["command"]):
            raise ContractError(f"{path}.commands.guarded_execute.command: must be guarded execute")
        if str(guarded_execute["guard_set_command"]) != "$env:TAMANDUA_ALLOW_ML_REAL_ACQUISITION = '1'":
            raise ContractError(f"{path}.commands.guarded_execute.guard_set_command: must set real acquisition guard separately")
        required_env = require_object(guarded_execute["required_env"], f"{path}.commands.guarded_execute.required_env")
        if required_env.get("TAMANDUA_ALLOW_ML_REAL_ACQUISITION") != "1":
            raise ContractError(f"{path}.commands.guarded_execute.required_env: must require real acquisition guard")
        uses_virusshare_fallback = "wave_1_virusshare_fallback_acquisition_launcher.ps1" in str(guarded_execute["command"])
        if uses_virusshare_fallback and required_env.get("VIRUSSHARE_API_KEY") != "<redacted: isolated lab secret store>":
            raise ContractError(f"{path}.commands.guarded_execute.required_env.VIRUSSHARE_API_KEY: must be redacted")
        serialized = json.dumps(data, sort_keys=True, ensure_ascii=True)
        if "VIRUSSHARE_API_KEY=" in serialized or "VIRUSSHARE_API_KEY = '" in serialized:
            raise ContractError(f"{path}: must not embed a VirusShare secret value")
        if uses_virusshare_fallback and "VIRUSSHARE_API_KEY" not in str(guarded_execute["guard_cleanup_command"]):
            raise ContractError(f"{path}.commands.guarded_execute.guard_cleanup_command: must remove VirusShare secret")
        if post_acquisition["manifest_guard_set_command"] != "$env:TAMANDUA_ALLOW_ML_MANIFEST_PUBLISH = '1'":
            raise ContractError(f"{path}.commands.post_acquisition.manifest_guard_set_command: invalid manifest guard")
        if "-Execute" not in str(post_acquisition["manifest_publish_command"]):
            raise ContractError(f"{path}.commands.post_acquisition.manifest_publish_command: must be guarded execute")

    safety = require_object(data["safety_invariants"], f"{path}.safety_invariants")
    safety_expectations = {
        "vx_archive_download_guard_env": "TAMANDUA_ALLOW_VX_UNDERGROUND_DOWNLOAD",
        "vx_archive_download_guard_must_remain_unset": True,
        "vx_download_authorized_by_this_packet": False,
        "vx_inventory_metadata_only": True,
        "vx_samples_allowed_in_training_splits": False,
        "raw_samples_allowed_in_git": False,
        "data_root_must_be_outside_repo": True,
        "source_mirror_code_and_metadata_only": True,
        "trained_weights_release_artifact_only_after_ml_gates": True,
    }
    for field, expected in safety_expectations.items():
        if safety.get(field) != expected:
            raise ContractError(f"{path}.safety_invariants.{field}: must be {expected!r}")
    expected_evidence = require_array(data["expected_evidence"], f"{path}.expected_evidence")
    for suffix in [
        "20260604T-ml-wave1-real-acquisition-transcript.json",
        "20260604T-ml-wave1-manifest-publish-receipt.json",
        "20260604T-ml-wave1-acceptance-checklist.json",
        "20260604T-ml-dataset-manifest.json",
    ]:
        if not any(str(item).endswith(suffix) for item in expected_evidence):
            raise ContractError(f"{path}.expected_evidence: missing {suffix}")
    downstream = require_object(data["downstream_benchmark_surfaces"], f"{path}.downstream_benchmark_surfaces")
    if downstream.get("next_unproven_requirement") != "wave1_governed_acquisition":
        raise ContractError(f"{path}.downstream_benchmark_surfaces.next_unproven_requirement: must remain Wave 1")
    if downstream.get("detection_surface_contract_ready") is not True:
        raise ContractError(f"{path}.downstream_benchmark_surfaces.detection_surface_contract_ready: must be true")

    checks = [require_object(item, f"{path}.checks.item") for item in require_array(data["checks"], f"{path}.checks")]
    check_by_name = {str(check["name"]): check for check in checks}
    for required_check in {
        "source_authorization_packet_loaded",
        "validation_command_remains_validation_only",
        "execute_command_remains_guarded",
        "vx_archives_not_authorized",
        "ml_mirror_publication_hold_preserved",
    }:
        if required_check not in check_by_name:
            raise ContractError(f"{path}.checks: missing {required_check}")
        if check_by_name[required_check].get("passed") is not True:
            raise ContractError(f"{path}.checks.{required_check}.passed: must be true")
    if "virusshare_secret_required_but_not_embedded" not in check_by_name:
        raise ContractError(f"{path}.checks: missing virusshare_secret_required_but_not_embedded")
    if uses_virusshare_fallback and check_by_name["virusshare_secret_required_but_not_embedded"].get("passed") is not True:
        raise ContractError(f"{path}.checks.virusshare_secret_required_but_not_embedded.passed: must be true for fallback route")

    summary = require_object(data["source_status_summary"], f"{path}.source_status_summary")
    if summary["ready_for_guarded_execution"] != ready:
        raise ContractError(f"{path}.source_status_summary.ready_for_guarded_execution: must match source readiness")
    if summary["publication_decision"] != expected_publication_decision:
        raise ContractError(f"{path}.source_status_summary.publication_decision: must match decision")
    if int(summary["blocker_count"]) != len(blockers):
        raise ContractError(f"{path}.source_status_summary.blocker_count: must match blockers")
    if int(summary["failed_authorization_check_count"]) != len(failed_authorization_checks):
        raise ContractError(f"{path}.source_status_summary.failed_authorization_check_count: must match failed checks")
    if int(summary["passed_checks"]) != sum(1 for check in checks if check.get("passed") is True):
        raise ContractError(f"{path}.source_status_summary.passed_checks: must match checks")
    if int(summary["failed_checks"]) != sum(1 for check in checks if check.get("passed") is not True):
        raise ContractError(f"{path}.source_status_summary.failed_checks: must match checks")


